    private static void drawRoundedRectImgui(double x, double y, double width, double height, double edgeRadius,
                                             int color) {
        float[] c = { (color >> 16 & 255) / 255.0F, (color >> 8 & 255) / 255.0F, (color & 255) / 255.0F,
                (color >> 24 & 255) / 255.0F };
        GL11.glPushAttrib(GL11.GL_ALL_ATTRIB_BITS);
        GL11.glEnable(GL11.GL_BLEND);
        GL11.glDisable(GL11.GL_TEXTURE_2D);
        GL11.glBlendFunc(GL11.GL_SRC_ALPHA, GL11.GL_ONE_MINUS_SRC_ALPHA);
        GL11.glColor4f(c[0], c[1], c[2], c[3]);
        GL11.glBegin(GL11.GL_POLYGON);
        for (int i = 0; i <= 90; i += 3)
            GL11.glVertex2f((float) (x + edgeRadius + Math.sin(i * Math.PI / 180.0) * edgeRadius * -1.0),
                    (float) (y + edgeRadius + Math.cos(i * Math.PI / 180.0) * edgeRadius * -1.0));
        for (int i = 90; i <= 180; i += 3)
            GL11.glVertex2f((float) (x + edgeRadius + Math.sin(i * Math.PI / 180.0) * edgeRadius * -1.0),
                    (float) (y + height - edgeRadius + Math.cos(i * Math.PI / 180.0) * edgeRadius * -1.0));
        for (int i = 0; i <= 90; i += 3)
            GL11.glVertex2f((float) (x + width - edgeRadius + Math.sin(i * Math.PI / 180.0) * edgeRadius),
                    (float) (y + height - edgeRadius + Math.cos(i * Math.PI / 180.0) * edgeRadius));
        for (int i = 90; i <= 180; i += 3)
            GL11.glVertex2f((float) (x + width - edgeRadius + Math.sin(i * Math.PI / 180.0) * edgeRadius),
                    (float) (y + edgeRadius + Math.cos(i * Math.PI / 180.0) * edgeRadius));
        GL11.glEnd();
        GL11.glColor4f(1.0f, 1.0f, 1.0f, 1.0f);
        GL11.glPopAttrib();
    }

