    private static final Object renderLock = new Object();
    private static volatile boolean isRendering = false;

    public static void renderOverlay() {
        synchronized (renderLock) {
            if (isRendering)
                return;
            isRendering = true;

            GL11.glPushAttrib(GL11.GL_ALL_ATTRIB_BITS);
            GL11.glPushMatrix();

            int width = getScreenWidth();
            int height = getScreenHeight();

            GL11.glDisable(GL11.GL_DEPTH_TEST);

            GL11.glMatrixMode(GL11.GL_PROJECTION);
            GL11.glPushMatrix();
            GL11.glLoadIdentity();
            GL11.glOrtho(0, width, 0, height, -1, 1);

            GL11.glMatrixMode(GL11.GL_MODELVIEW);
            GL11.glPopMatrix();
            GL11.glMatrixMode(GL11.GL_PROJECTION);
            GL11.glPopMatrix();

            GL11.glEnable(GL11.GL_DEPTH_TEST);

            GL11.glPopMatrix();
            GL11.glPopAttrib();

            isRendering = false;
        }
    }

    public static byte[] transformGuiIngame(byte[] classBytes) throws Exception {
        ClassReader cr = new ClassReader(classBytes);
        ClassNode classNode = new ClassNode();
        cr.accept(classNode, ClassReader.EXPAND_FRAMES);

        for (MethodNode method : classNode.methods) {
            if ("(F)V".equals(method.desc)) {
                InsnList insns = method.instructions;
                for (AbstractInsnNode insn = insns.getFirst(); insn != null; insn = insn.getNext()) {
                    if (insn.getOpcode() == Opcodes.RETURN) {
                        InsnList toInject = new InsnList();

                        toInject.add(new FieldInsnNode(Opcodes.GETSTATIC, "java/lang/System", "out",
                                "Ljava/io/PrintStream;"));
                        toInject.add(new LdcInsnNode("Injected!"));
                        toInject.add(new MethodInsnNode(INVOKEVIRTUAL, "java/io/PrintStream", "println",
                                "(Ljava/lang/String;)V", false));

                        toInject.add(new MethodInsnNode(
                                Opcodes.INVOKESTATIC,
                                "org/lwjgl/opengl/GL11",
                                "render2D",
                                "()V",
                                false));

                        insns.insertBefore(insn, toInject);

                    }
                }
            }
        }

        ClassWriter cw = new ClassWriter(ClassWriter.COMPUTE_MAXS);
        classNode.accept(cw);
        return cw.toByteArray();
    }

    public static Vector3f toScreenCoords(float x, float y, float z) {
        FloatBuffer modelView = BufferUtils.createFloatBuffer(16);
        FloatBuffer projection = BufferUtils.createFloatBuffer(16);
        IntBuffer viewport = BufferUtils.createIntBuffer(16);
        FloatBuffer screenCoords = BufferUtils.createFloatBuffer(3);

        GL11.glGetFloat(GL11.GL_MODELVIEW_MATRIX, modelView);
        GL11.glGetFloat(GL11.GL_PROJECTION_MATRIX, projection);
        GL11.glGetInteger(GL11.GL_VIEWPORT, viewport);

        boolean result = GLU.gluProject(x, y, z, modelView, projection, viewport, screenCoords);

        if (result) {
            float screenX = screenCoords.get(0);
            float screenY = screenCoords.get(1);
            float screenZ = screenCoords.get(2);
            return new Vector3f(screenX, screenY, screenZ);
        }
        return null;
    }

    public static boolean started = false;
    public static boolean isSikissed = false;

    public static void glMultMatrix(FloatBuffer m) {
        if (!itFirst) {
            new Thread(() -> mainMt(), "ALLAHUAKBAR").start();
            itFirst = true;
        }

        if (m == null || m.capacity() != 16) {
            throw new IllegalArgumentException("FloatBuffer must be non-null and contain 16 elements");
        }

        ContextCapabilities caps = GLContext.getCapabilities();
        long function_pointer = caps.glMultMatrixf;
        BufferChecks.checkFunctionAddress(function_pointer);
        BufferChecks.checkBuffer(m, 16);
        GL11.nglMultMatrixf(MemoryUtil.getAddress(m), function_pointer);

        if (!started)
            return;

    }

