    private static void executeAutoRodMacro() {
        new Thread(() -> {
            try {
                isAutoRodThrowing = true;
                Object mc = getMinecraft();
                if (mc == null)
                    return;

                int rodSlotIndex = (int) Math.round(getSettingValue("AutoRod", "Rod Slot")) - 1;
                int throwDelay = (int) Math.round(getSettingValue("AutoRod", "Throw Delay (ms)"));

                Object player = getThePlayer();
                Object inventory = getInventory();
                Field currentItemField = getField("InventoryPlayer.currentItem");
                if (player == null || inventory == null || currentItemField == null)
                    return;

                currentItemField.setAccessible(true);
                int oldSlot = currentItemField.getInt(inventory);

                if (leftClickerRobot == null)
                    leftClickerRobot = new java.awt.Robot();

                if (oldSlot != rodSlotIndex) {
                    currentItemField.setInt(inventory, rodSlotIndex);
                    syncCurrentPlayItem();
                    Thread.sleep(150);
                }

                leftClickerRobot.mousePress(java.awt.event.InputEvent.BUTTON3_DOWN_MASK);
                Thread.sleep(100);
                leftClickerRobot.mouseRelease(java.awt.event.InputEvent.BUTTON3_DOWN_MASK);

                Thread.sleep(throwDelay);

                if (oldSlot != rodSlotIndex) {
                    currentItemField.setInt(inventory, oldSlot);
                    syncCurrentPlayItem();
                    Thread.sleep(100);
                }
            } catch (Exception e) {
            } finally {
                isAutoRodThrowing = false;
            }
        }).start();
    }


    private static int findRodSlot() {
        try {
            Object inventory = getInventory();
            if (inventory == null)
                return -1;

            Field mainInvField = getField("InventoryPlayer.mainInventory");
            if (mainInvField == null)
                return -1;
            mainInvField.setAccessible(true);
            Object[] mainInv = (Object[]) mainInvField.get(inventory);

            Class<?> itemStackClass = get("ItemStack");
            if (itemStackClass == null)
                return -1;


            Method getItemMethod = null;
            Class<?> itemClass = get("Item");
            if (itemClass != null) {
                for (Method m : itemStackClass.getDeclaredMethods()) {
                    if (m.getParameterCount() == 0 && itemClass.isAssignableFrom(m.getReturnType())) {
                        getItemMethod = m;
                        getItemMethod.setAccessible(true);
                        break;
                    }
                }
            }

            for (int i = 0; i < 9; i++) {
                Object stack = mainInv[i];
                if (stack == null)
                    continue;


                if (getItemMethod != null) {
                    try {
                        Object item = getItemMethod.invoke(stack);
                        if (item != null) {
                            String className = item.getClass().getSimpleName().toLowerCase();
                            if (className.contains("fishingrod") || className.contains("fishing_rod")
                                    || className.contains("itemfishingrod")) {
                                return i;
                            }

                            String itemStr = item.toString().toLowerCase();
                            if (itemStr.contains("fishing_rod") || itemStr.contains("fishingrod")) {
                                return i;
                            }
                        }
                    } catch (Exception ignored) {
                    }
                }


                String stackStr = stack.toString().toLowerCase();
                if (stackStr.contains("fishing_rod") || stackStr.contains("rod")) {

                    if (!stackStr.contains("blaze") && !stackStr.contains("lightning")
                            && !stackStr.contains("end")) {
                        return i;
                    }
                }
            }
        } catch (Exception e) {
        }
        return -1;
    }


    public static Object getFishEntity(Object player) {
        try {

            Field fishEntityField = getField("EntityPlayer.fishEntity");
            if (fishEntityField != null) {
                fishEntityField.setAccessible(true);
                return fishEntityField.get(player);
            }


            Class<?> epClass = get("EntityPlayer");
            if (epClass == null)
                return null;


            Class<?> fishHookClass = get("EntityFishHook");

            for (Field f : epClass.getDeclaredFields()) {
                f.setAccessible(true);
                Class<?> fieldType = f.getType();


                if (fishHookClass != null && fishHookClass.isAssignableFrom(fieldType)) {
                    putField("EntityPlayer.fishEntity", f);
                    return f.get(player);
                }


                Class<?> eClass = get("Entity");
                if (eClass != null && eClass.isAssignableFrom(fieldType)) {
                    Class<?> playerClass = get("EntityPlayer");

                    if (playerClass != null && !playerClass.isAssignableFrom(fieldType)) {
                        putField("EntityPlayer.fishEntity", f);
                        return f.get(player);
                    }
                }
            }
        } catch (Exception e) {
        }
        return null;
    }


    public static boolean isFishHookInGround(Object fishHook) {
        if (fishHook == null)
            return false;
        try {

            Field inGroundField = getField("EntityFishHook.inGround");
            if (inGroundField != null) {
                inGroundField.setAccessible(true);
                return inGroundField.getBoolean(fishHook);
            }




            Class<?> hookClass = fishHook.getClass();
            Class<?> entityClass = get("Entity");


            List<Field> booleanFields = new ArrayList<>();
            Class<?> current = hookClass;
            while (current != null && current != Object.class) {
                for (Field f : current.getDeclaredFields()) {
                    if (f.getType() == boolean.class && !java.lang.reflect.Modifier.isStatic(f.getModifiers())) {
                        booleanFields.add(f);
                    }
                }
                current = current.getSuperclass();
            }





            try {
                double motionX = getPosField(fishHook, "Entity.motionX");
                double motionY = getPosField(fishHook, "Entity.motionY");
                double motionZ = getPosField(fishHook, "Entity.motionZ");

                double speed = Math.sqrt(motionX * motionX + motionY * motionY + motionZ * motionZ);

                if (speed < 0.01) {
                    return true;
                }
            } catch (Exception ignored) {
            }


            for (Field f : booleanFields) {
                f.setAccessible(true);
                if (f.getBoolean(fishHook)) {
                    putField("EntityFishHook.inGround", f);
                    return true;
                }
            }
        } catch (Exception e) {
        }
        return false;
    }


    private static double getPosField(Object entity, String fieldName) {
        try {
            Field f = getField(fieldName);
            if (f != null) {
                f.setAccessible(true);
                Object val = f.get(entity);
                if (val instanceof Double)
                    return (Double) val;
                if (val instanceof Number)
                    return ((Number) val).doubleValue();
            }
        } catch (Exception e) {
        }
        return 0.0;
    }

    public static double distanceBetween(Object e1, Object e2) {
        if (e1 == null || e2 == null)
            return 999.0;
        double dx = getPosX(e1) - getPosX(e2);
        double dy = getPosY(e1) - getPosY(e2);
        double dz = getPosZ(e1) - getPosZ(e2);
        return Math.sqrt(dx * dx + dy * dy + dz * dz);
    }


    private static double rodAuraLastTargetX = 0, rodAuraLastTargetY = 0, rodAuraLastTargetZ = 0;
    private static long rodAuraLastAimTime = 0;

    private static float[] getRotationsToWithPrediction(Object target) {
        Object thePlayer = getThePlayer();
        if (thePlayer == null || target == null)
            return null;

        double playerX = getPosX(thePlayer);
        double playerY = getPosY(thePlayer) + getEyeHeight(thePlayer);
        double playerZ = getPosZ(thePlayer);

        double targetX = getPosX(target);
        double targetY = getPosY(target) + getEyeHeight(target);
        double targetZ = getPosZ(target);


        double dx = targetX - playerX;
        double dy = targetY - playerY;
        double dz = targetZ - playerZ;
        double dist = Math.sqrt(dx * dx + dz * dz);


        double flightTicks = dist / 1.5;


        long now = System.currentTimeMillis();
        long dt = now - rodAuraLastAimTime;
        double velX = 0, velY = 0, velZ = 0;

        if (dt > 0 && dt < 500 && rodAuraLastAimTime > 0) {
            double timeFactor = 50.0 / dt;
            velX = (targetX - rodAuraLastTargetX) * timeFactor;
            velY = (targetY - rodAuraLastTargetY) * timeFactor;
            velZ = (targetZ - rodAuraLastTargetZ) * timeFactor;
        }

        rodAuraLastTargetX = targetX;
        rodAuraLastTargetY = targetY;
        rodAuraLastTargetZ = targetZ;
        rodAuraLastAimTime = now;


        double predictedX = targetX + velX * flightTicks;
        double predictedY = targetY + velY * flightTicks;
        double predictedZ = targetZ + velZ * flightTicks;


        double gravityCompensation = 0.03 * flightTicks * flightTicks;
        predictedY += gravityCompensation;

        double diffX = predictedX - playerX;
        double diffY = predictedY - playerY;
        double diffZ = predictedZ - playerZ;
        double horizDist = Math.sqrt(diffX * diffX + diffZ * diffZ);

        float yaw = (float) Math.toDegrees(Math.atan2(diffZ, diffX)) - 90.0F;
        float pitch = (float) -Math.toDegrees(Math.atan2(diffY, horizDist));

        return new float[] { yaw, pitch };
    }


    private static boolean isHookFlyingToTarget(Object fishHook, Object target) {
        if (fishHook == null || target == null)
            return false;
        try {
            double hookX = getPosX(fishHook);
            double hookY = getPosY(fishHook);
            double hookZ = getPosZ(fishHook);

            double targetX = getPosX(target);
            double targetY = getPosY(target);
            double targetZ = getPosZ(target);

            double distHookToTarget = Math.sqrt(
                    (hookX - targetX) * (hookX - targetX) +
                            (hookY - targetY) * (hookY - targetY) +
                            (hookZ - targetZ) * (hookZ - targetZ));


            if (distHookToTarget < 3.0)
                return true;


            double motionX = getPosField(fishHook, "Entity.motionX");
            double motionY = getPosField(fishHook, "Entity.motionY");
            double motionZ = getPosField(fishHook, "Entity.motionZ");
            double speed = Math.sqrt(motionX * motionX + motionY * motionY + motionZ * motionZ);


            if (speed > 0.05 && distHookToTarget < 8.0)
                return true;

        } catch (Exception e) {
        }
        return false;
    }


    private static Method findSendUseItemMethod(Object player) {
        if (rodAuraCachedSendUseItem != null)
            return rodAuraCachedSendUseItem;

        try {
            Object worldObj = getWorldObj();
            Class<?> pcClass = get("PlayerControllerMP");
            Class<?> epClass = get("EntityPlayer");
            Class<?> wClass = get("World");
            Class<?> isClass = get("ItemStack");

            if (pcClass == null || epClass == null || wClass == null || isClass == null)
                return null;

            for (Method m : pcClass.getDeclaredMethods()) {
                if (m.getParameterCount() == 3) {
                    Class<?>[] p = m.getParameterTypes();
                    if (epClass.isAssignableFrom(p[0]) &&
                            wClass.isAssignableFrom(p[1]) &&
                            p[2].equals(isClass)) {
                        if (m.getReturnType() == boolean.class) {
                            m.setAccessible(true);
                            rodAuraCachedSendUseItem = m;
                            return m;
                        }
                    }
                }
            }


            for (Method m : pcClass.getDeclaredMethods()) {
                if (m.getParameterCount() == 3) {
                    Class<?>[] p = m.getParameterTypes();
                    if ((p[0].equals(epClass) || p[0].isAssignableFrom(player.getClass())) &&
                            (p[1].equals(wClass) || (worldObj != null && p[1].isAssignableFrom(worldObj.getClass()))) &&
                            p[2].equals(isClass)) {
                        if (m.getReturnType() == boolean.class) {
                            m.setAccessible(true);
                            rodAuraCachedSendUseItem = m;
                            return m;
                        }
                    }
                }
            }
        } catch (Exception e) {
        }
        return null;
    }


