    private static final String[] POSITIVE_POTION_KEYWORDS = {
            "heal", "health", "regen", "speed", "swiftness", "strength", "fire_resist", "fire_resistance",
            "absorption", "resistance"
    };
    private static final String[] NEGATIVE_POTION_KEYWORDS = {
            "harm", "damage", "instant_damage", "poison", "slowness", "weakness", "wither"
    };

    private static int findSplashPotionSlot(boolean positive) {
        try {
            Object inventory = getInventory();
            if (inventory == null)
                return -1;

            Field mainInvField = getField("InventoryPlayer.mainInventory");
            if (mainInvField == null)
                return -1;
            mainInvField.setAccessible(true);
            Object[] mainInv = (Object[]) mainInvField.get(inventory);

            Class<?> itemStackClass = get("ItemStack");
            if (itemStackClass == null)
                return -1;


            Method getItemMethod = null;
            Class<?> itemClass = get("Item");
            if (itemClass != null) {
                for (Method m : itemStackClass.getDeclaredMethods()) {
                    if (m.getParameterCount() == 0 && itemClass.isAssignableFrom(m.getReturnType())) {
                        getItemMethod = m;
                        getItemMethod.setAccessible(true);
                        break;
                    }
                }
            }


            Method getMetadataMethod = null;
            for (Method m : itemStackClass.getDeclaredMethods()) {
                if (m.getParameterCount() == 0 && (m.getReturnType() == int.class)) {
                    String mName = m.getName().toLowerCase();
                    if (mName.contains("metadata") || mName.contains("damage") || mName.contains("durability")) {
                        getMetadataMethod = m;
                        getMetadataMethod.setAccessible(true);
                        break;
                    }
                }
            }

            if (getMetadataMethod == null) {
                for (Method m : itemStackClass.getDeclaredMethods()) {
                    if (m.getParameterCount() == 0 && m.getReturnType() == int.class) {

                        getMetadataMethod = m;
                        getMetadataMethod.setAccessible(true);
                        break;
                    }
                }
            }

            String[] keywords = positive ? POSITIVE_POTION_KEYWORDS : NEGATIVE_POTION_KEYWORDS;


            for (int i = 0; i < 9; i++) {
                if (isSplashPotionMatch(mainInv[i], getItemMethod, getMetadataMethod, keywords)) {
                    return i;
                }
            }
        } catch (Exception e) {
        }
        return -1;
    }

    private static boolean isSplashPotionMatch(Object stack, Method getItemMethod, Method getMetadataMethod,
                                               String[] keywords) {
        if (stack == null)
            return false;
        try {

            String stackStr = stack.toString().toLowerCase();

            if (!stackStr.contains("potion"))
                return false;

            int meta = -1;
            if (stackStr.contains("@")) {
                String metaStr = stackStr.substring(stackStr.lastIndexOf("@") + 1);
                try {
                    meta = Integer.parseInt(metaStr);
                } catch (Exception ignored) {
                }
            }
            if (meta == -1 && getMetadataMethod != null) {
                try {
                    meta = (int) getMetadataMethod.invoke(stack);
                } catch (Exception ignored) {
                }
            }

            if (meta != -1) {

                if ((meta & 16384) == 0 && meta < 16384) {
                    return false;
                }

                int potionId = meta & 0xF;



                boolean isPositiveById = (potionId == 1 || potionId == 2 || potionId == 3 ||
                        potionId == 5 || potionId == 6 || potionId == 9 ||
                        potionId == 11 || potionId == 13 || potionId == 14);


                boolean isNegativeById = (potionId == 4 || potionId == 8 || potionId == 10 || potionId == 12);

                boolean lookingForPositive = (keywords == POSITIVE_POTION_KEYWORDS);

                if (lookingForPositive && isPositiveById)
                    return true;
                if (!lookingForPositive && isNegativeById)
                    return true;
                return false;
            }


            Method getDisplayName = getMethod("ItemStack.getDisplayName");
            String dispName = "";
            if (getDisplayName != null) {
                dispName = ((String) getDisplayName.invoke(stack)).toLowerCase();
            }

            String fullCheck = stackStr + " " + dispName;
            if (fullCheck.contains("splash") || fullCheck.contains("patlayıcı")) {
                for (String kw : keywords) {
                    if (fullCheck.contains(kw))
                        return true;
                }
            }

        } catch (Exception ignored) {
        }
        return false;
    }

