    public static void setSneakState(boolean sneak) {
        try {

            Object mc = getMinecraft();
            if (mc == null)
                return;

            Class<?> gsClass = (Class<?>) get("GameSettings");
            if (gsClass == null)
                return;


            Object gsInstance = null;
            for (Field f : mc.getClass().getDeclaredFields()) {
                if (f.getType().equals(gsClass)) {
                    f.setAccessible(true);
                    gsInstance = f.get(mc);
                    break;
                }
            }
            if (gsInstance == null)
                return;


            Field keyBindSneakField = getField("GameSettings.keyBindSneak");
            if (keyBindSneakField == null)
                return;
            keyBindSneakField.setAccessible(true);
            Object keyBindSneak = keyBindSneakField.get(gsInstance);
            if (keyBindSneak == null)
                return;


            Field pressedField = getField("KeyBinding.pressed");
            if (pressedField == null)
                return;
            pressedField.setAccessible(true);

            if (sneak) {
                pressedField.setBoolean(keyBindSneak, true);
            } else {

                Field keyCodeField = getField("KeyBinding.keyCode");
                if (keyCodeField != null) {
                    keyCodeField.setAccessible(true);
                    int keyCode = keyCodeField.getInt(keyBindSneak);
                    boolean physicallyHeld = false;
                    if (keyCode >= 0) {
                        physicallyHeld = org.lwjgl.input.Keyboard.isKeyDown(keyCode);
                    } else {
                        physicallyHeld = org.lwjgl.input.Mouse.isButtonDown(keyCode + 100);
                    }
                    pressedField.setBoolean(keyBindSneak, physicallyHeld);
                } else {
                    pressedField.setBoolean(keyBindSneak, false);
                }
            }
        } catch (Exception e) {
        }
    }

