    private static int findSoupSlot() {
        try {
            Object inventory = getInventory();
            if (inventory == null)
                return -1;

            Field mainInvField = getField("InventoryPlayer.mainInventory");
            if (mainInvField == null)
                return -1;
            mainInvField.setAccessible(true);

            Object[] mainInv = (Object[]) mainInvField.get(inventory);
            if (mainInv == null)
                return -1;

            Class<?> itemClass = get("Item");
            Method getIdMethod = null;
            if (itemClass != null) {
                for (Method m : itemClass.getDeclaredMethods()) {
                    if (Modifier.isStatic(m.getModifiers()) && m.getReturnType() == int.class
                            && m.getParameterCount() == 1 && m.getParameterTypes()[0] == itemClass) {
                        getIdMethod = m;
                        getIdMethod.setAccessible(true);
                        break;
                    }
                }
            }

            for (int i = 0; i < 9; i++) {
                Object stack = mainInv[i];
                if (stack == null)
                    continue;

                Method getItemMethod = getMethod("ItemStack.getItem");
                if (getItemMethod == null)
                    continue;

                Object item = getItemMethod.invoke(stack);
                if (item == null)
                    continue;


                if (getIdMethod != null) {
                    try {
                        int id = (Integer) getIdMethod.invoke(null, item);
                        if (id == 282)
                            return i;
                    } catch (Exception ex) {}
                }

                String dn = "";
                try {
                    Method getDn = getMethod("ItemStack.getDisplayName");
                    if (getDn != null) dn = ((String) getDn.invoke(stack)).toLowerCase();
                } catch (Exception ex) {}

                String itemName = item.getClass().getSimpleName().toLowerCase();
                String checkStr = item.toString().toLowerCase() + " " + itemName + " " + dn;

                if (checkStr.contains("soup") || checkStr.contains("stew") || checkStr.contains("corba")
                        || checkStr.contains("çorba") || checkStr.contains("itemsoup") || checkStr.contains("güveç") || checkStr.contains("mantar")) {
                    return i;
                }
            }
        } catch (Exception e) {
        }
        return -1;
    }

    private static void ghostEatSoup(int soupSlot) {
        if (isAutoSoupEating)
            return;
        isAutoSoupEating = true;

        try {
            Object player = getThePlayer();
            Object inventory = getInventory();
            Object playerController = getPlayerController();
            Object worldObj = getWorldObj();
            if (player == null || inventory == null || playerController == null || worldObj == null) {
                isAutoSoupEating = false;
                return;
            }

            Field currentItemField = getField("InventoryPlayer.currentItem");
            if (currentItemField == null) {
                isAutoSoupEating = false;
                return;
            }
            currentItemField.setAccessible(true);
            int clientSlot = currentItemField.getInt(inventory);

            Field mainInvField = getField("InventoryPlayer.mainInventory");
            mainInvField.setAccessible(true);
            Object[] mainInv = (Object[]) mainInvField.get(inventory);
            Object soupStack = mainInv[soupSlot];
            if (soupStack == null) {
                isAutoSoupEating = false;
                return;
            }

            Method sendUseItem = findSendUseItemMethod(player);
            if (sendUseItem == null) {
                isAutoSoupEating = false;
                return;
            }


            if (clientSlot != soupSlot) {
                currentItemField.setInt(inventory, soupSlot);
                syncCurrentPlayItem();
            }

            sendUseItem.invoke(playerController, player, worldObj, soupStack);

            if (clientSlot != soupSlot) {
                currentItemField.setInt(inventory, clientSlot);
                syncCurrentPlayItem();
            }
        } catch (Exception e) {
        }
        isAutoSoupEating = false;
    }

