    public static int getBlockIdAt(int x, int y, int z) {
        try {
            Object world = getWorldObj();
            if (world == null)
                return 0;

            Method getChunk = getMethod("World.getChunkFromChunkCoords");
            if (getChunk == null)
                return 0;
            Object chunk = getChunk.invoke(world, x >> 4, z >> 4);
            if (chunk == null)
                return 0;

            Method getBlock = getMethod("Chunk.getBlock");
            if (getBlock == null)
                return 0;
            Object block = getBlock.invoke(chunk, x & 15, y, z & 15);
            if (block == null)
                return 0;

            Method getId = getMethod("Block.getIdFromBlock");
            if (getId == null)
                return 0;
            return (int) getId.invoke(null, block);
        } catch (Exception e) {
        }
        return 0;
    }

    private static volatile Method _cachedMetaMethod = null;
    private static volatile boolean _metaMethodSearchDone = false;

    public static int getBlockMetadataAt(int x, int y, int z) {
        try {
            Object world = getWorldObj();
            if (world == null) return 0;
            Method getChunk = getMethod("World.getChunkFromChunkCoords");
            if (getChunk == null) return 0;
            Object chunk = getChunk.invoke(world, x >> 4, z >> 4);
            if (chunk == null) return 0;

            if (!_metaMethodSearchDone) {
                _metaMethodSearchDone = true;
                Method mapped = getMethod("Chunk.getBlockMetadata");
                if (mapped != null) {
                    _cachedMetaMethod = mapped;
                } else {
                    Method getBlockM = getMethod("Chunk.getBlock");
                    for (Method m : chunk.getClass().getDeclaredMethods()) {
                        Class<?>[] p = m.getParameterTypes();
                        if (m.getReturnType() == int.class && p.length == 3 &&
                                p[0] == int.class && p[1] == int.class && p[2] == int.class) {
                            m.setAccessible(true);
                            try {
                                int test = (int) m.invoke(chunk, 0, 64, 0);
                                if (test >= 0 && test <= 15) {
                                    _cachedMetaMethod = m;
                                    break;
                                }
                            } catch (Exception ignored) {}
                        }
                    }
                }
            }
            if (_cachedMetaMethod != null) {
                return (int) _cachedMetaMethod.invoke(chunk, x & 15, y, z & 15);
            }
        } catch (Exception e) {}
        return 0;
    }

    public static String getBlockNameAt(int x, int y, int z) {
        try {
            Object world = getWorldObj();
            if (world == null) return "minecraft:air";

            Method getChunk = getMethod("World.getChunkFromChunkCoords");
            if (getChunk == null) return "minecraft:air";
            Object chunk = getChunk.invoke(world, x >> 4, z >> 4);
            if (chunk == null) return "minecraft:air";

            Method getBlock = getMethod("Chunk.getBlock");
            if (getBlock == null) return "minecraft:air";
            Object block = getBlock.invoke(chunk, x & 15, y, z & 15);
            if (block == null) return "minecraft:air";


            try {

                Field registryField = null;
                Class<?> blockClass = get("Block");
                if (blockClass != null) {
                    for (Field f : blockClass.getDeclaredFields()) {
                        f.setAccessible(true);
                        if (f.getType().getSimpleName().contains("Registry") ||
                                f.getType().getSimpleName().contains("RegistryNamespaced")) {
                            registryField = f;
                            break;
                        }
                    }
                    if (registryField != null) {
                        registryField.setAccessible(true);
                        Object registry = registryField.get(null);
                        if (registry != null) {

                            for (Method m : registry.getClass().getMethods()) {
                                if (m.getParameterTypes().length == 1 &&
                                        m.getName().contains("getNameForObject")) {
                                    Object resLoc = m.invoke(registry, block);
                                    if (resLoc != null) {
                                        return resLoc.toString();
                                    }
                                }
                            }

                            for (Method m : registry.getClass().getMethods()) {
                                if (m.getParameterTypes().length == 1 &&
                                        m.getReturnType() == Object.class &&
                                        !m.getName().equals("getClass")) {
                                    try {
                                        Object resLoc = m.invoke(registry, block);
                                        if (resLoc != null && resLoc.toString().contains(":")) {
                                            return resLoc.toString();
                                        }
                                    } catch (Exception ignored) {}
                                }
                            }
                        }
                    }
                }
            } catch (Exception ignored) {}


            Method getId = getMethod("Block.getIdFromBlock");
            if (getId != null) {
                int id = (int) getId.invoke(null, block);
                return "minecraft:block_" + id;
            }
        } catch (Exception e) {}
        return "minecraft:air";
    }

