    public static void renderImageESP(Object en, Vector4f pos, String imagePath) {
        float x = pos.getX(), y = pos.getY(), right = pos.getZ(), bottom = pos.getW();
        float width = right - x;
        float height = bottom - y;

        if (getSettingBoolean("ESP", "2D Box")) {
            int espRgb = new Color(255, 255, 255, 255).getRGB();
            float outlineThickness = 0.5f;
            drawRect2(x, y, width, 1, espRgb);
            drawRect2(x, y, 1, height, espRgb);
            drawRect2(x, bottom, width, 1, espRgb);
            drawRect2(right, y, 1, height + 1, espRgb);
        }

        if (getSettingBoolean("ESP", "Image ESP")) {
            try {

                int textureId = loadTextureFromFile(imagePath);
                if (textureId <= 0)
                    return;

                GL11.glEnable(GL11.GL_TEXTURE_2D);
                GL11.glEnable(GL11.GL_BLEND);
                GL11.glBlendFunc(GL11.GL_SRC_ALPHA, GL11.GL_ONE_MINUS_SRC_ALPHA);
                GL11.glDisable(GL11.GL_DEPTH_TEST);

                GL11.glBindTexture(GL11.GL_TEXTURE_2D, textureId);

                GL11.glColor4f(1.0f, 1.0f, 1.0f, 0.8f);

                float imgWidth = width + 10;
                float imgHeight = height + 10;
                float imgX = x - 5;
                float imgY = y - 5;

                GL11.glBegin(GL11.GL_QUADS);
                GL11.glTexCoord2f(0, 0);
                GL11.glVertex2f(imgX, imgY);
                GL11.glTexCoord2f(1, 0);
                GL11.glVertex2f(imgX + imgWidth, imgY);
                GL11.glTexCoord2f(1, 1);
                GL11.glVertex2f(imgX + imgWidth, imgY + imgHeight);
                GL11.glTexCoord2f(0, 1);
                GL11.glVertex2f(imgX, imgY + imgHeight);
                GL11.glEnd();

                GL11.glDisable(GL11.GL_TEXTURE_2D);
                GL11.glDisable(GL11.GL_BLEND);
                GL11.glEnable(GL11.GL_DEPTH_TEST);
                GL11.glColor4f(1.0f, 1.0f, 1.0f, 1.0f);

            } catch (Exception e) {
                e.printStackTrace();
            }
        }
    }

    public static double interp(final double newPos, final double oldPos) {
        return oldPos + (newPos - oldPos) * getRenderPartialTicks();
    }

    public static void render3DImageESP(Object entity, String imagePath, double scale) {
        if (entity == null)
            return;

        int textureId = loadTextureFromFile(imagePath);
        if (textureId <= 0)
            return;

        double x = interp(getPosX(), getLastTickPosX(getThePlayer())) - getRenderPosX();
        double y = interp(getPosY(), getLastTickPosY(getThePlayer())) - getRenderPosY();
        double z = interp(getPosZ(), getLastTickPosZ(getThePlayer())) - getRenderPosZ();

        GL11.glPushMatrix();

        GL11.glTranslated(x, y + getEntityHeight(), z);

        GL11.glRotatef(0, 0.0f, 1.0f, 0.0f);
        GL11.glRotatef(8, 1.0f, 0.0f, 0.0f);

        GL11.glScaled(-scale, -scale, scale);

        GL11.glRotatef(180.0f, 0.0f, 1.0f, 0.0f);

        GL11.glEnable(GL11.GL_BLEND);
        GL11.glBlendFunc(GL11.GL_SRC_ALPHA, GL11.GL_ONE_MINUS_SRC_ALPHA);
        GL11.glDisable(GL11.GL_DEPTH_TEST);
        GL11.glDisable(GL11.GL_LIGHTING);

        GL11.glEnable(GL11.GL_TEXTURE_2D);
        GL11.glBindTexture(GL11.GL_TEXTURE_2D, textureId);

        GL11.glColor4f(1.0f, 1.0f, 1.0f, 0.9f);

        float width = 1.0f;
        float height = 2.0f;

        GL11.glBegin(GL11.GL_QUADS);
        {
            GL11.glTexCoord2f(0.0f, 0.0f);
            GL11.glVertex3f(-width / 2, -height / 2, 0.0f);

            GL11.glTexCoord2f(1.0f, 0.0f);
            GL11.glVertex3f(width / 2, -height / 2, 0.0f);

            GL11.glTexCoord2f(1.0f, 1.0f);
            GL11.glVertex3f(width / 2, height / 2, 0.0f);

            GL11.glTexCoord2f(0.0f, 1.0f);
            GL11.glVertex3f(-width / 2, height / 2, 0.0f);
        }
        GL11.glEnd();

        GL11.glDisable(GL11.GL_TEXTURE_2D);
        GL11.glEnable(GL11.GL_DEPTH_TEST);
        GL11.glDisable(GL11.GL_BLEND);
        GL11.glEnable(GL11.GL_LIGHTING);
        GL11.glColor4f(1.0f, 1.0f, 1.0f, 1.0f);

        GL11.glPopMatrix();
    }

    public static int loadTextureFromFile(String filePath) {
        try {
            File file = new File(filePath);
            if (!file.exists()) {
                System.err.println("File not found: " + filePath);
                return -1;
            }

            BufferedImage image = ImageIO.read(file);
            int width = image.getWidth();
            int height = image.getHeight();

            int[] pixels = new int[width * height];
            image.getRGB(0, 0, width, height, pixels, 0, width);

            ByteBuffer buffer = ByteBuffer.allocateDirect(width * height * 4);

            for (int y = 0; y < height; y++) {
                for (int x = 0; x < width; x++) {
                    int pixel = pixels[y * width + x];
                    buffer.put((byte) ((pixel >> 16) & 0xFF));
                    buffer.put((byte) ((pixel >> 8) & 0xFF));
                    buffer.put((byte) (pixel & 0xFF));
                    buffer.put((byte) ((pixel >> 24) & 0xFF));
                }
            }
            buffer.flip();

            int textureId = GL11.glGenTextures();
            GL11.glBindTexture(GL11.GL_TEXTURE_2D, textureId);

            GL11.glTexParameteri(GL11.GL_TEXTURE_2D, GL11.GL_TEXTURE_MIN_FILTER, GL11.GL_LINEAR);
            GL11.glTexParameteri(GL11.GL_TEXTURE_2D, GL11.GL_TEXTURE_MAG_FILTER, GL11.GL_LINEAR);
            GL11.glTexParameteri(GL11.GL_TEXTURE_2D, GL11.GL_TEXTURE_WRAP_S, GL11.GL_CLAMP);
            GL11.glTexParameteri(GL11.GL_TEXTURE_2D, GL11.GL_TEXTURE_WRAP_T, GL11.GL_CLAMP);

            GL11.glTexImage2D(GL11.GL_TEXTURE_2D, 0, GL11.GL_RGBA, width, height,
                    0, GL11.GL_RGBA, GL11.GL_UNSIGNED_BYTE, buffer);

            return textureId;

        } catch (Exception e) {
            e.printStackTrace();
            return -1;
        }
    }

