    public static void drawBlockBox(float x, float y, float z, Color color) {
        double rx = x - getRenderPosX();
        double ry = y - getRenderPosY();
        double rz = z - getRenderPosZ();

        float minX = (float) rx;
        float maxX = minX + 1;
        float minY = (float) ry;
        float maxY = minY + 1;
        float minZ = (float) rz;
        float maxZ = minZ + 1;

        Vector3f[] c = {
                new Vector3f(minX, minY, minZ),
                new Vector3f(minX, maxY, minZ),
                new Vector3f(maxX, maxY, minZ),
                new Vector3f(maxX, minY, minZ),
                new Vector3f(minX, minY, maxZ),
                new Vector3f(minX, maxY, maxZ),
                new Vector3f(maxX, maxY, maxZ),
                new Vector3f(maxX, minY, maxZ)
        };

        GL11.glPushMatrix();
        GL11.glDisable(GL11.GL_TEXTURE_2D);
        GL11.glEnable(GL11.GL_BLEND);
        GL11.glDisable(GL11.GL_DEPTH_TEST);
        GL11.glBlendFunc(GL11.GL_SRC_ALPHA, GL11.GL_ONE_MINUS_SRC_ALPHA);
        GL11.glLineWidth(1.3f);
        GL11.glColor4f(color.getRed() / 255f, color.getGreen() / 255f, color.getBlue() / 255f, color.getAlpha() / 255f);
        GL11.glBegin(GL11.GL_LINES);

        drawLine(c[0], c[1]);
        drawLine(c[1], c[2]);
        drawLine(c[2], c[3]);
        drawLine(c[3], c[0]);

        drawLine(c[4], c[5]);
        drawLine(c[5], c[6]);
        drawLine(c[6], c[7]);
        drawLine(c[7], c[4]);

        drawLine(c[0], c[4]);
        drawLine(c[1], c[5]);
        drawLine(c[2], c[6]);
        drawLine(c[3], c[7]);

        GL11.glEnd();
        GL11.glEnable(GL11.GL_DEPTH_TEST);
        GL11.glEnable(GL11.GL_TEXTURE_2D);
        GL11.glDisable(GL11.GL_BLEND);
        GL11.glPopMatrix();
    }

    private static void drawLine(Vector3f from, Vector3f to) {
        GL11.glVertex3f(from.x, from.y, from.z);
        GL11.glVertex3f(to.x, to.y, to.z);
    }

    public static Vector4f getEntityPositionsOn2D(Object entity) {
        double[] pos = getEntityPos(entity);
        float yOffset = -0.2f;

        float minX = (float) (pos[0] - 0.5);
        float maxX = (float) (pos[0] + 0.5);
        float minZ = (float) (pos[2] - 0.5);
        float maxZ = (float) (pos[2] + 0.5);
        float minY = (float) (pos[1]);
        float maxY = (float) (pos[1] + 2.5 + yOffset);

        List<Vector3f> corners = Arrays.asList(
                new Vector3f(minX, minY, minZ),
                new Vector3f(minX, maxY, minZ),
                new Vector3f(maxX, minY, minZ),
                new Vector3f(maxX, maxY, minZ),
                new Vector3f(minX, minY, maxZ),
                new Vector3f(minX, maxY, maxZ),
                new Vector3f(maxX, minY, maxZ),
                new Vector3f(maxX, maxY, maxZ));

        Vector4f projectedBox = new Vector4f(Float.MAX_VALUE, Float.MAX_VALUE, -1.0f, -1.0f);
        int scaleFactor = 2;

        for (Vector3f vec : corners) {
            Vector3f projected = projectOn2D(vec.x, vec.y, vec.z, scaleFactor);
            if (projected != null && projected.z >= 0.0f && projected.z < 1.0f) {
                projectedBox.x = Math.min(projected.x, projectedBox.x);
                projectedBox.y = Math.min(projected.y, projectedBox.y);
                projectedBox.z = Math.max(projected.x, projectedBox.z);
                projectedBox.w = Math.max(projected.y, projectedBox.w);
            }
        }

        return projectedBox;
    }

