    public static Vector3f projectOn2D(float x, float y, float z, int scaleFactor) {
        GL11.glGetFloat(GL11.GL_MODELVIEW_MATRIX, floatBuffer1);
        GL11.glGetFloat(GL11.GL_PROJECTION_MATRIX, floatBuffer2);
        GL11.glGetInteger(GL11.GL_VIEWPORT, intBuffer);

        windPos.clear();
        if (GLU.gluProject(x, y, z, floatBuffer1, floatBuffer2, intBuffer, windPos)) {
            windPos.rewind();
            float screenX = windPos.get(0) / scaleFactor;
            float screenY = (Display.getHeight() - windPos.get(1)) / scaleFactor;
            float screenZ = windPos.get(2);
            return new Vector3f(screenX, screenY, screenZ);
        }

        return null;
    }

