    public static void esprenderer(Object en, Vector4f pos) {
        float x = pos.getX(), y = pos.getY(), right = pos.getZ(), bottom = pos.getW();
        float width = right - x;
        float height = bottom - y;

        float health = getHealth(en);
        float healthValueNormalized = health / 20f;
        String name = getName(en);
        String text = "§f" + name + String.format(" §7[§r%.1f HP§7]", health);

        Color healthColor = healthValueNormalized > 0.75f ? new Color(66, 246, 123)
                : healthValueNormalized > 0.5f ? new Color(228, 255, 105)
                : healthValueNormalized > 0.35f ? new Color(236, 100, 64)
                : new Color(255, 65, 68);
        if (getSettingBoolean("ESP", "2D HealthBar")) {
            float healthBarWidth = 3f;
            float barHeight = height + 1;
            float filledHeight = barHeight * healthValueNormalized;
            Color emptyColor = new Color(0, 0, 0, 180);

            roundedRect(x - 3.5f, y - 0.5f, healthBarWidth - 1.5f, barHeight, 2, emptyColor);
            drawRect2(x - 3f, y + (barHeight - filledHeight) - 0.5f, 1f, filledHeight, healthColor.getRGB());
            if (healthValueNormalized < 0.8f) {
                String healthText = (int) (healthValueNormalized * 100) + "%";
                double fontScalePercent = 0.5;

                GL11.glPushMatrix();
                GL11.glTranslated(x - 6f, y + (barHeight - filledHeight) - 4f, 0);
                GL11.glScaled(fontScalePercent, fontScalePercent, 1);

                GL11.glEnable(GL11.GL_BLEND);
                drawString(healthText, 0, 0, Color.WHITE.getRGB());

                GL11.glPopMatrix();
            }
        }
        if (getSettingBoolean("ESP", "2D Box")) {
            int espRgb = new Color(255, 255, 255, 255).getRGB();
            float outlineThickness = 0.5f;
            drawRect2(x, y, width, 1, espRgb);
            drawRect2(x, y, 1, height, espRgb);
            drawRect2(x, bottom, width, 1, espRgb);
            drawRect2(right, y, 1, height + 1, espRgb);
            int black = Color.BLACK.getRGB();
            drawRect2(x - outlineThickness, y - outlineThickness, width + outlineThickness * 2, outlineThickness,
                    black);
            drawRect2(x - outlineThickness, y, outlineThickness, height, black);
            drawRect2(x - outlineThickness, bottom, width + outlineThickness * 2, outlineThickness, black);
            drawRect2(right, y, outlineThickness, height, black);
        }
    }

