    public static Vector4f worldToScreen1(double x, double y, double z, float height) {
        FloatBuffer screenCoords = BufferUtils.createFloatBuffer(3);
        FloatBuffer modelView = BufferUtils.createFloatBuffer(16);
        FloatBuffer projection = BufferUtils.createFloatBuffer(16);
        IntBuffer viewport = BufferUtils.createIntBuffer(16);

        GL11.glGetFloat(GL11.GL_MODELVIEW_MATRIX, modelView);
        GL11.glGetFloat(GL11.GL_PROJECTION_MATRIX, projection);
        GL11.glGetInteger(GL11.GL_VIEWPORT, viewport);

        boolean result = GLU.gluProject((float) x, (float) y, (float) z,
                modelView, projection, viewport, screenCoords);
        if (!result)
            return null;

        float screenX = screenCoords.get(0);
        float screenY = viewport.get(3) - screenCoords.get(1);

        return new Vector4f(screenX, screenY, screenX, screenY - height);
    }

    public static Vector4f getInterpolatedScreenPos(Object entity) {
        float partialTicks = getRenderPartialTicks();

        double px = getPrevPosX(entity) + (getPosX(entity) - getPrevPosX(entity)) * partialTicks;
        double py = getPrevPosY(entity) + (getPosY(entity) - getPrevPosY(entity)) * partialTicks + getEyeHeight(entity);
        double pz = getPrevPosZ(entity) + (getPosZ(entity) - getPrevPosZ(entity)) * partialTicks;

        double[] screen = worldToScreen(px, py, pz);
        if (screen == null)
            return null;

        float x = (float) screen[0];
        float y = (float) screen[1];
        float width = 20;
        float height = 50;

        return new Vector4f(x, y, x + width, y + height);
    }

    public static double[] worldToScreen(double x, double y, double z) {
        FloatBuffer screenCoords = BufferUtils.createFloatBuffer(3);
        FloatBuffer modelView = BufferUtils.createFloatBuffer(16);
        FloatBuffer projection = BufferUtils.createFloatBuffer(16);
        IntBuffer viewport = BufferUtils.createIntBuffer(16);

        GL11.glGetFloat(GL11.GL_MODELVIEW_MATRIX, modelView);
        GL11.glGetFloat(GL11.GL_PROJECTION_MATRIX, projection);
        GL11.glGetInteger(GL11.GL_VIEWPORT, viewport);

        boolean result = GLU.gluProject((float) x, (float) y, (float) z, modelView, projection, viewport, screenCoords);
        if (result) {
            double screenX = screenCoords.get(0);
            double screenY = GL11.getScreenHeight() - screenCoords.get(1);
            double screenZ = screenCoords.get(2);
            if (screenZ >= 0 && screenZ < 1.0)
                return new double[] { screenX, screenY, screenZ };
        }
        return null;
    }

