    public static void toggleModuleInSelected() {
        String selectedCat = new ArrayList<>(new LinkedHashSet<>(moduleCategories)).get(tabSelectedCategory);
        List<String> modules = new ArrayList<>();
        for (int i = 0; i < moduleNames.size(); i++) {
            if (moduleCategories.get(i).equals(selectedCat) && !isModuleHidden(moduleNames.get(i)))
                modules.add(moduleNames.get(i));
        }

        if (tabSelectedModule < modules.size()) {
            int index = moduleNames.indexOf(modules.get(tabSelectedModule));
            boolean current = moduleEnabled.get(index);
            moduleEnabled.set(index, !current);

            if (!current)
                moduleOnEnable.get(index).run();
            else
                moduleOnDisable.get(index).run();
        }
    }

