    public static void hideVanillaScoreboard() {
        try {


            Object mc = getMinecraft();
            if (mc == null) return;
            Field guiIngameField = getField("Minecraft.ingameGUI");
            if (guiIngameField == null) return;
            guiIngameField.setAccessible(true);
            Object guiIngame = guiIngameField.get(mc);
            if (guiIngame == null) return;


            for (Field f : guiIngame.getClass().getDeclaredFields()) {
                f.setAccessible(true);
                Object val = f.get(guiIngame);
                if (val != null && val.getClass().getSimpleName().toLowerCase().contains("scoreboard")) {
                    f.set(guiIngame, null);
                    break;
                }
            }
        } catch (Exception ignored) {}
    }

