    private static void renderColoredText(String text, float x, float y) {
        int currentColor = 0xFFFFFFFF;
        float offsetX = 0;

        for (int i = 0; i < text.length(); i++) {
            char c = text.charAt(i);

            if (c == '§' && i + 1 < text.length()) {
                char code = text.charAt(i + 1);
                currentColor = getColorFromCode(code);
                i++;
                continue;
            }

            String toDraw = String.valueOf(c);
            GL11.drawString(toDraw, x + offsetX, y, currentColor);
            offsetX += GL11.getStringWidthCustomFont(toDraw);
        }
    }

    private static int getColorFromCode(char code) {
        switch (code) {
            case '0':
                return 0xFF000000;
            case '1':
                return 0xFF0000AA;
            case '2':
                return 0xFF00AA00;
            case '3':
                return 0xFF00AAAA;
            case '4':
                return 0xFFAA0000;
            case '5':
                return 0xFFAA00AA;
            case '6':
                return 0xFFFFAA00;
            case '7':
                return 0xFFAAAAAA;
            case '8':
                return 0xFF555555;
            case '9':
                return 0xFF5555FF;
            case 'a':
                return 0xFF55FF55;
            case 'b':
                return 0xFF55FFFF;
            case 'c':
                return 0xFFFF5555;
            case 'd':
                return 0xFFFF55FF;
            case 'e':
                return 0xFFFFFF55;
            case 'f':
                return 0xFFFFFFFF;
            default:
                return 0xFFFFFFFF;
        }
    }

