    static int glideTicks = 0;



    static int glideGroundSpoofTick = 0;
    static double glideLastGroundY = -1.0;
    static boolean glideWasInAir = false;

    public static void glideOnUpdate() {
        if (!isModuleEnabled("Glide"))
            return;

        try {
            Object player = getThePlayer();
            if (player == null)
                return;

            boolean workInMenus = getSettingBoolean("Glide", "Work In Menus");
            if (!workInMenus && getCurrentScreen() != null) {
                return;
            }

            boolean spacePressed = Keyboard.isKeyDown(Keyboard.KEY_SPACE);

            boolean moving = Keyboard.isKeyDown(Keyboard.KEY_W) ||
                    Keyboard.isKeyDown(Keyboard.KEY_S) ||
                    Keyboard.isKeyDown(Keyboard.KEY_A) ||
                    Keyboard.isKeyDown(Keyboard.KEY_D);


            setTimerSpeed(1.0);

            double rawMotionSpeed = getSettingValue("Glide", "Motion Speed");
            double glideMotion = getSettingValue("Glide", "Glide Motion");
            int tickAmount = (int) Math.round(getSettingValue("Glide", "Tick Amount"));
            boolean flyUpwards = getSettingBoolean("Glide", "Fly Upwards");
            double jumpHeight = getSettingValue("Glide", "Jump Height");


            boolean onGround = isOnGround();
            double posX = getPosX();
            double posY = getPosY();
            double posZ = getPosZ();











            if (!onGround && moving) {
                glideGroundSpoofTick++;
                glideWasInAir = true;







                if (glideGroundSpoofTick >= tickAmount) {
                    glideGroundSpoofTick = 0;


                    setOnGround(true);
                    setFallDistance(0);




                    double groundY = posY - (Math.random() * 0.001);
                    Object groundPacket = createC04(posX, groundY, posZ, true);
                    if (groundPacket != null) {
                        sendPacket(groundPacket);
                    }



                    Object airPacket = createC04(posX, posY + 0.001 + Math.random() * 0.001, posZ, false);
                    if (airPacket != null) {
                        sendPacket(airPacket);
                    }


                    setOnGround(false);
                }
            } else if (onGround) {

                if (glideWasInAir) {
                    glideGroundSpoofTick = 0;
                    glideWasInAir = false;
                    setFallDistance(0);
                }
                glideLastGroundY = posY;
            }


            if (moving) {
                if (onGround) {



                    if (glideTicks > 0) {
                        glideTicks = 0;
                    }
                    if (!spacePressed && jumpHeight > 0 && glideTicks == 0) {


                        setMotionY(jumpHeight + (Math.random() - 0.5) * 0.0001);
                        glideTicks = -1;
                    }
                } else {

                    if (glideTicks < 0) glideTicks = 0;
                    glideTicks++;

                    if (flyUpwards) {

                        if (!spacePressed) {

                            double climbSpeed = Math.min(0.08 + (jumpHeight * 0.12), 0.20);
                            setMotionY(climbSpeed);
                        }
                    } else {



                        if (!spacePressed && jumpHeight > 0.42 && glideTicks == tickAmount) {
                            double currentY = getMotionY();
                            if (currentY < -0.1 && currentY > -0.5) {
                                double extraBoost = Math.min((jumpHeight - 0.42) * 0.05, 0.05) + (Math.random() - 0.5) * 0.005;
                                setMotionY(currentY + extraBoost);
                            }
                        }


                        if (!spacePressed && glideMotion > 0) {
                            double currentY = getMotionY();

                            double glideLimit = -(0.15 + glideMotion * 0.06);
                            if (currentY < glideLimit) {
                                setMotionY(glideLimit + (Math.random() - 0.5) * 0.001);
                            }
                        }
                    }
                }




                double jitter = (Math.random() - 0.5) * 0.001;
                double acSafeSpeedLimit = 0.27 + (rawMotionSpeed * 0.095) + jitter;

                float yaw = getRotationYaw();

                boolean w = Keyboard.isKeyDown(Keyboard.KEY_W);
                boolean s = Keyboard.isKeyDown(Keyboard.KEY_S);
                boolean a = Keyboard.isKeyDown(Keyboard.KEY_A);
                boolean d = Keyboard.isKeyDown(Keyboard.KEY_D);

                float forward = 0;
                if (w) forward += 1;
                if (s) forward -= 1;

                float strafe = 0;
                if (a) strafe += 1;
                if (d) strafe -= 1;



                if (forward != 0 && strafe != 0) {
                    forward *= 0.707106781F;
                    strafe *= 0.707106781F;
                }

                if (forward != 0.0F) {
                    if (strafe > 0.0F) {
                        yaw += (float)(forward > 0.0F ? -45 : 45);
                    } else if (strafe < 0.0F) {
                        yaw += (float)(forward > 0.0F ? 45 : -45);
                    }
                    strafe = 0.0F;
                    if (forward > 0.0F) {
                        forward = 1.0F;
                    } else if (forward < 0.0F) {
                        forward = -1.0F;
                    }
                }

                double rad = Math.toRadians((double)yaw + 90.0D);
                double mx = (double)forward * acSafeSpeedLimit * Math.cos(rad) + (double)strafe * acSafeSpeedLimit * Math.sin(rad);
                double mz = (double)forward * acSafeSpeedLimit * Math.sin(rad) - (double)strafe * acSafeSpeedLimit * Math.cos(rad);



                double prevMx = getMotionX();
                double prevMz = getMotionZ();
                double lerpFactor = Math.min(1.0, 0.35 + rawMotionSpeed * 0.02);
                setMotionX(prevMx + (mx - prevMx) * lerpFactor);
                setMotionZ(prevMz + (mz - prevMz) * lerpFactor);
            }
        } catch (Exception e) {
            e.printStackTrace();
        }
    }

