    public static void dumpAllFields() {
        try {
            Class<?> clazz = get("teiste");
            if (clazz == null) {
                System.out.println("Class not found: teiste");
                return;
            }

            Object instance = null;

            try {
                Constructor<?> c = clazz.getDeclaredConstructor();
                c.setAccessible(true);
                instance = c.newInstance();
            } catch (Throwable ignored) {
            }

            System.out.println("==== FIELD DUMP :: " + clazz.getName() + " ====");

            for (Field f : clazz.getDeclaredFields()) {
                try {
                    f.setAccessible(true);

                    boolean isStatic = Modifier.isStatic(f.getModifiers());
                    Object value = isStatic
                            ? f.get(null)
                            : (instance != null ? f.get(instance) : null);

                    String valueStr;

                    if (value == null) {
                        valueStr = "null";
                    } else if (value.getClass().isArray()) {

                        if (value instanceof Object[]) {
                            valueStr = Arrays.deepToString((Object[]) value);
                        } else if (value instanceof int[]) {
                            valueStr = Arrays.toString((int[]) value);
                        } else if (value instanceof long[]) {
                            valueStr = Arrays.toString((long[]) value);
                        } else if (value instanceof byte[]) {
                            valueStr = Arrays.toString((byte[]) value);
                        } else if (value instanceof boolean[]) {
                            valueStr = Arrays.toString((boolean[]) value);
                        } else if (value instanceof char[]) {
                            valueStr = Arrays.toString((char[]) value);
                        } else if (value instanceof float[]) {
                            valueStr = Arrays.toString((float[]) value);
                        } else if (value instanceof double[]) {
                            valueStr = Arrays.toString((double[]) value);
                        } else {
                            valueStr = "[unknown array type]";
                        }
                    } else {
                        valueStr = value.toString();
                    }

                    System.out.println(
                            (isStatic ? "[STATIC] " : "[FIELD] ") +
                                    f.getType().getSimpleName() + " " +
                                    f.getName() + " = " +
                                    valueStr);

                } catch (Throwable t) {
                    System.out.println("[ERROR] " + f.getName());
                }
            }

            System.out.println("==== END DUMP ====");

        } catch (Throwable t) {
            t.printStackTrace();
        }
    }

    static Runnable createLookTPModule(String name, int key, double distance) {
        return () -> {
            if (getThePlayer() == null) {
                addChatMessage("§cLookTP: Player is null!", false);
                return;
            }


            String mode = getMode("LookTP", "Mode");
            double range = getSettingValue("LookTP", "Range");


            double[] targetPos = calculateTargetPosition(range);
            double targetX = targetPos[0];
            double targetY = targetPos[1];
            double targetZ = targetPos[2];

            addChatMessage("§bLookTP: §fTeleporting to " +
                    String.format("§bX: %.1f §fY: §b%.1f §fZ: §b%.1f", targetX, targetY, targetZ), false);

            if (mode.equals("Normal")) {

                setPosition(targetX, targetY, targetZ);
                addChatMessage("§bNormal teleport completed!", false);

            } else if (mode.equals("Infinite")) {

                sendLookTPPackets(targetX, targetY, targetZ);
            }


            int moduleIndex = moduleNames.indexOf(name);
            if (moduleIndex != -1) {
                moduleEnabled.set(moduleIndex, false);
                if (moduleOnDisable.size() > moduleIndex) {
                    moduleOnDisable.get(moduleIndex).run();
                }
            }
        };
    }

    private static void sendLookTPPackets(double targetX, double targetY, double targetZ) {
        new Thread(() -> {
            try {
                float yaw = getRotationYaw();
                float pitch = getRotationPitch();


                int packets = 35 + new Random().nextInt(15);

                for (int i = 0; i < packets; i++) {

                    Object c04 = createC04(targetX, targetY, targetZ, false);
                    Object c06 = createC06(targetX, targetY, targetZ, yaw, pitch, false);

                    if (c04 != null)
                        sendPacket(c04);
                    if (c06 != null)
                        sendPacket(c06);


                    Thread.sleep(17 + new Random().nextInt(12));
                }


                Object finalC04 = createC04(targetX, targetY, targetZ, true);
                if (finalC04 != null)
                    sendPacket(finalC04);


                setMotionX(0.08);
                setMotionZ(0.08);

                addChatMessage("§bInfinite teleport completed! (" + packets + " packets)", false);

            } catch (Exception e) {
                addChatMessage("§cLookTP failed: " + e.getMessage(), false);
                e.printStackTrace();
            }
        }).start();
    }


    private static double[] calculateTargetPosition(double range) {
        double yaw = Math.toRadians(getRotationYaw());
        double pitch = Math.toRadians(getRotationPitch());

        double xComp = -Math.sin(yaw) * Math.cos(pitch);
        double yComp = -Math.sin(pitch);
        double zComp = Math.cos(yaw) * Math.cos(pitch);

        double targetX = getPosX() + xComp * range;
        double targetY = getPosY() + yComp * range + getEyeHeight(getThePlayer());
        double targetZ = getPosZ() + zComp * range;

        return new double[] { targetX, targetY, targetZ };
    }

    private static Object createC06(double x, double y, double z, float yaw, float pitch, boolean onGround) {
        try {
            Class<?> c06Class = get("C06PacketPlayerPosLook");
            if (c06Class == null)
                return null;

            Constructor<?> constructor = c06Class.getConstructor(
                    double.class, double.class, double.class,
                    float.class, float.class, boolean.class);

            return constructor.newInstance(x, y, z, yaw, pitch, onGround);

        } catch (Exception e) {
            e.printStackTrace();
            return null;
        }
    }

