    public static void loadConfig(String configName) {
        if (configName == null || configName.isEmpty()) {
            configName = DEFAULT_CONFIG;
        }

        if (!configName.endsWith(".cfg")) {
            configName += ".cfg";
        }

        Path configPath = Paths.get(CONFIG_DIR + configName);

        if (!Files.exists(configPath)) {
            addChatMessage("§cConfig bulunamadı: §e" + configName, false);
            return;
        }

        try (BufferedReader reader = new BufferedReader(new FileReader(configPath.toFile()))) {
            String line;
            String section = "";

            List<Boolean> newModuleStates = new ArrayList<>(Collections.nCopies(moduleEnabled.size(), false));
            List<Integer> newModuleBinds = new ArrayList<>(moduleBindKeys);

            friends.clear();

            while ((line = reader.readLine()) != null) {
                line = line.trim();
                if (line.isEmpty())
                    continue;

                if (line.startsWith("[") && line.endsWith("]")) {
                    section = line.substring(1, line.length() - 1);
                    continue;
                }

                if (section.equals("FRIENDS")) {
                    friends.add(line.toLowerCase());
                    continue;
                }

                if (section.equals("SCHEMATIC_TOGGLE_BINDS")) {
                    String[] kv = line.split(":", 2);
                    if (kv.length == 2) {
                        try {
                            schematicToggleBindKeys.put(kv[0].trim(), Integer.parseInt(kv[1].trim()));
                        } catch (NumberFormatException ignored) {}
                    }
                    continue;
                }

                String[] parts = line.split(":");
                if (parts.length < 3)
                    continue;

                String moduleName = parts[0];
                String settingName = parts[1];
                String value = parts[2];

                switch (section) {
                    case "CLIPBOARD":
                        String[] cb = line.split(":");
                        if (cb.length == 5) {
                            clipboardKeyPos1 = Integer.parseInt(cb[0]);
                            clipboardKeyPos2 = Integer.parseInt(cb[1]);
                            clipboardKeyCopy = Integer.parseInt(cb[2]);
                            clipboardKeyPaste = Integer.parseInt(cb[3]);
                            clipboardKeyClear = Integer.parseInt(cb[4]);
                        } else if (cb.length == 4) {

                            clipboardKeyPos1 = Integer.parseInt(cb[0]);
                            clipboardKeyPos2 = Integer.parseInt(cb[1]);
                            clipboardKeyPaste = Integer.parseInt(cb[2]);
                            clipboardKeyClear = Integer.parseInt(cb[3]);
                        }
                        break;
                    case "MODULES":
                        int moduleIndex = getModuleIndexIgnoreCase(moduleName);
                        if (moduleIndex != -1) {
                            boolean enabled = Boolean.parseBoolean(parts[1]);
                            int bindKey = Integer.parseInt(parts[2]);
                            newModuleStates.set(moduleIndex, enabled);
                            newModuleBinds.set(moduleIndex, bindKey);

                            addChatMessage("§7Config: " + moduleName + " -> " + enabled + " (key: " + bindKey + ")",
                                    false);
                        }
                        break;
                    case "TELEPORT":
                        String[] v = line.split(":");
                        if (v.length == 4) {
                            tpX = Double.parseDouble(v[0]);
                            tpY = Double.parseDouble(v[1]);
                            tpZ = Double.parseDouble(v[2]);
                            tpSet = Boolean.parseBoolean(v[3]);
                        }
                        break;

                    case "NUMBERSETTINGS":
                        if (moduleSettingsValues.containsKey(moduleName)) {
                            List<String> names = moduleSettingsNames.get(moduleName);
                            int settingIndex = names.indexOf(settingName);
                            if (settingIndex != -1) {
                                moduleSettingsValues.get(moduleName).set(settingIndex, Double.parseDouble(value));
                            }
                        }
                        break;

                    case "BOOLEANSETTINGS":
                        if (moduleSettingsBooleans.containsKey(moduleName)) {
                            List<String> names = moduleBooleanSettingNames.get(moduleName);
                            int settingIndex = names.indexOf(settingName);
                            if (settingIndex != -1) {
                                moduleSettingsBooleans.get(moduleName).set(settingIndex, Boolean.parseBoolean(value));
                            }
                        }
                        break;

                    case "MODESETTINGS":
                        if (moduleModeSettingValues.containsKey(moduleName)) {
                            List<String> names = moduleModeSettingNames.get(moduleName);
                            int settingIndex = names.indexOf(settingName);
                            if (settingIndex != -1) {
                                moduleModeSettingValues.get(moduleName).set(settingIndex, value);
                            }
                        }
                        break;

                    case "STRINGSETTINGS":
                        if (moduleStringSettingValues.containsKey(moduleName)) {
                            List<String> names = moduleStringSettingNames.get(moduleName);
                            int settingIndex = names.indexOf(settingName);
                            if (settingIndex != -1) {
                                moduleStringSettingValues.get(moduleName).set(settingIndex, value);
                            }
                        }
                        break;
                    case "MEDIAWIDGET":
                        String[] mw = line.split(":");
                        if (mw.length == 4) {
                            mediaWidgetX = Float.parseFloat(mw[0]);
                            mediaWidgetY = Float.parseFloat(mw[1]);
                            mediaWidgetTargetW = Float.parseFloat(mw[2]);
                            mediaWidgetTargetH = Float.parseFloat(mw[3]);
                            mediaWidgetW = mediaWidgetTargetW;
                            mediaWidgetH = mediaWidgetTargetH;
                        }
                        break;
                    case "HUDPOSITIONS":
                        String[] hp = line.split(":");
                        if (hp.length == 5) {
                            String elem = hp[0];
                            float px = Float.parseFloat(hp[1]);
                            float py = Float.parseFloat(hp[2]);
                            float pw = Float.parseFloat(hp[3]);
                            float ph = Float.parseFloat(hp[4]);
                            if (elem.equals("Notifications")) hudNotifPos = new float[]{px, py, pw, ph};
                            else if (elem.equals("ArrayList")) hudArrayListPos = new float[]{px, py, pw, ph};
                            else if (elem.equals("Watermark")) hudWatermarkPos = new float[]{px, py, pw, ph};
                            else if (elem.equals("ScoreBoard")) hudScoreboardPos = new float[]{px, py, pw, ph};
                            hudEditorInitialized = true;
                        }
                        break;
                }
            }

            for (int i = 0; i < moduleEnabled.size(); i++) {
                boolean oldState = moduleEnabled.get(i);
                boolean newState = newModuleStates.get(i);
                int newBind = newModuleBinds.get(i);

                moduleBindKeys.set(i, newBind);

                if (oldState != newState) {
                    moduleEnabled.set(i, newState);

                    if (newState) {
                        moduleOnEnable.get(i).run();
                        addChatMessage("§aAçıldı: §e" + moduleNames.get(i), false);
                    } else {
                        moduleOnDisable.get(i).run();
                        addChatMessage("§cKapandı: §e" + moduleNames.get(i), false);
                    }
                }
            }

            currentConfig = configName;
            addChatMessage("§aConfig başarıyla yüklendi: §e" + configName, false);

        } catch (IOException e) {
            addChatMessage("§cConfig yüklenemedi: " + e.getMessage(), false);
        } catch (Exception e) {
            addChatMessage("§cConfig yüklenirken hata: " + e.getMessage(), false);
            e.printStackTrace();
        }
    }

