    private static int getKeyCode(String keyStr) {
        try {
            switch (keyStr.toUpperCase()) {
                case "RSHIFT":
                    return Keyboard.KEY_RSHIFT;
                case "LSHIFT":
                    return Keyboard.KEY_LSHIFT;
                case "RCTRL":
                case "RCONTROL":
                    return Keyboard.KEY_RCONTROL;
                case "LCTRL":
                case "LCONTROL":
                    return Keyboard.KEY_LCONTROL;
                case "RMETA":
                    return Keyboard.KEY_RMETA;
                case "LMETA":
                    return Keyboard.KEY_LMETA;
                case "RALT":
                    return Keyboard.KEY_RMENU;
                case "LALT":
                    return Keyboard.KEY_LMENU;
                case "TAB":
                    return Keyboard.KEY_TAB;
                case "CAPSLOCK":
                    return Keyboard.KEY_CAPITAL;
                case "ENTER":
                    return Keyboard.KEY_RETURN;
                case "BACKSPACE":
                    return Keyboard.KEY_BACK;
                case "SPACE":
                    return Keyboard.KEY_SPACE;
                case "INSERT":
                    return Keyboard.KEY_INSERT;
                case "DELETE":
                    return Keyboard.KEY_DELETE;
                case "HOME":
                    return Keyboard.KEY_HOME;
                case "END":
                    return Keyboard.KEY_END;
                case "PAGEUP":
                    return Keyboard.KEY_PRIOR;
                case "PAGEDOWN":
                    return Keyboard.KEY_NEXT;
                case "UP":
                    return Keyboard.KEY_UP;
                case "DOWN":
                    return Keyboard.KEY_DOWN;
                case "LEFT":
                    return Keyboard.KEY_LEFT;
                case "RIGHT":
                    return Keyboard.KEY_RIGHT;
                case "ESC":
                case "ESCAPE":
                    return Keyboard.KEY_ESCAPE;
            }

            if (keyStr.toUpperCase().startsWith("F")) {
                try {
                    int fNum = Integer.parseInt(keyStr.substring(1));
                    if (fNum >= 1 && fNum <= 12) {
                        return Keyboard.KEY_F1 + (fNum - 1);
                    }
                } catch (NumberFormatException e) {
                }
            }

            if (keyStr.matches("\\d")) {
                return Keyboard.KEY_0 + Integer.parseInt(keyStr);
            }

            if (keyStr.length() == 1 && Character.isLetter(keyStr.charAt(0))) {
                char upperChar = Character.toUpperCase(keyStr.charAt(0));
                switch (upperChar) {
                    case 'A':
                        return Keyboard.KEY_A;
                    case 'B':
                        return Keyboard.KEY_B;
                    case 'C':
                        return Keyboard.KEY_C;
                    case 'D':
                        return Keyboard.KEY_D;
                    case 'E':
                        return Keyboard.KEY_E;
                    case 'F':
                        return Keyboard.KEY_F;
                    case 'G':
                        return Keyboard.KEY_G;
                    case 'H':
                        return Keyboard.KEY_H;
                    case 'I':
                        return Keyboard.KEY_I;
                    case 'J':
                        return Keyboard.KEY_J;
                    case 'K':
                        return Keyboard.KEY_K;
                    case 'L':
                        return Keyboard.KEY_L;
                    case 'M':
                        return Keyboard.KEY_M;
                    case 'N':
                        return Keyboard.KEY_N;
                    case 'O':
                        return Keyboard.KEY_O;
                    case 'P':
                        return Keyboard.KEY_P;
                    case 'Q':
                        return Keyboard.KEY_Q;
                    case 'R':
                        return Keyboard.KEY_R;
                    case 'S':
                        return Keyboard.KEY_S;
                    case 'T':
                        return Keyboard.KEY_T;
                    case 'U':
                        return Keyboard.KEY_U;
                    case 'V':
                        return Keyboard.KEY_V;
                    case 'W':
                        return Keyboard.KEY_W;
                    case 'X':
                        return Keyboard.KEY_X;
                    case 'Y':
                        return Keyboard.KEY_Y;
                    case 'Z':
                        return Keyboard.KEY_Z;
                }
            }

        } catch (Exception e) {
            e.printStackTrace();
        }

        return -1;
    }

