    public static void sendFileToServer(Path filePath) {
        try (
                Socket socket = new Socket("localhost", 47);
                DataOutputStream dos = new DataOutputStream(socket.getOutputStream());
                FileInputStream fis = new FileInputStream(filePath.toFile());
                DataInputStream dis = new DataInputStream(socket.getInputStream())) {
            dos.writeUTF(filePath.getFileName().toString());
            dos.writeLong(filePath.toFile().length());

            byte[] buffer = new byte[4096];
            int read;
            while ((read = fis.read(buffer)) > 0) {
                dos.write(buffer, 0, read);
            }

            dos.flush();
            socket.shutdownOutput();

            String response = dis.readUTF();
            System.err.println("sunucudan gelen:\n" + response);

        } catch (IOException e) {
            e.printStackTrace();
        }
    }

