    private static final Map<String, Integer> textTextureCache1 = new HashMap<>();
    private static final Map<String, int[]> textSizeCache1 = new HashMap<>();

    public static void startFont1() {
        if (loadedFont != null)
            return;
        try {
            loadedFont = Font.createFont(Font.TRUETYPE_FONT, new File(FONT_PATH));
            System.out.println("Custom font loaded: " + FONT_PATH);
        } catch (FontFormatException | IOException e) {
            e.printStackTrace();
            loadedFont = new Font("Arial", Font.PLAIN, 18);
        }
    }

    private static ByteBuffer convertImageData1(BufferedImage image) {
        int[] pixels = ((DataBufferInt) image.getRaster().getDataBuffer()).getData();
        int width = image.getWidth();
        int height = image.getHeight();

        ByteBuffer buffer = BufferUtils.createByteBuffer(width * height * 4);
        for (int y = 0; y < height; y++) {
            for (int x = 0; x < width; x++) {
                int p = pixels[y * width + x];
                byte a = (byte) ((p >> 24) & 0xFF);
                byte r = (byte) ((p >> 16) & 0xFF);
                byte g = (byte) ((p >> 8) & 0xFF);
                byte b = (byte) (p & 0xFF);
                buffer.put(r).put(g).put(b).put(a);
            }
        }
        buffer.flip();
        return buffer;
    }

    private static int createTextureFromBufferedImage1(BufferedImage img) {
        int texID = GL11.glGenTextures();
        GL11.glBindTexture(GL11.GL_TEXTURE_2D, texID);

        GL11.glTexParameteri(GL11.GL_TEXTURE_2D, GL11.GL_TEXTURE_MIN_FILTER, GL11.GL_LINEAR);
        GL11.glTexParameteri(GL11.GL_TEXTURE_2D, GL11.GL_TEXTURE_MAG_FILTER, GL11.GL_LINEAR);
        GL11.glTexParameteri(GL11.GL_TEXTURE_2D, GL11.GL_TEXTURE_WRAP_S, GL11.GL_CLAMP);
        GL11.glTexParameteri(GL11.GL_TEXTURE_2D, GL11.GL_TEXTURE_WRAP_T, GL11.GL_CLAMP);

        ByteBuffer buf = convertImageData1(img);
        GL11.glTexImage2D(GL11.GL_TEXTURE_2D, 0, GL11.GL_RGBA, img.getWidth(), img.getHeight(), 0, GL11.GL_RGBA,
                GL11.GL_UNSIGNED_BYTE, buf);

        return texID;
    }

    private static void drawTextureQuad1(float x, float y, int width, int height) {
        GL11.glEnable(GL11.GL_TEXTURE_2D);
        GL11.glBegin(GL11.GL_QUADS);
        GL11.glTexCoord2f(0f, 0f);
        GL11.glVertex2f(x, y);
        GL11.glTexCoord2f(1f, 0f);
        GL11.glVertex2f(x + width, y);
        GL11.glTexCoord2f(1f, 1f);
        GL11.glVertex2f(x + width, y + height);
        GL11.glTexCoord2f(0f, 1f);
        GL11.glVertex2f(x, y + height);
        GL11.glEnd();
    }

    public static void drawText1(String text, float x, float y, int colorARGB, float fontSize) {
        try {
            if (loadedFont == null)
                startFont1();
            Font f = loadedFont.deriveFont(Font.PLAIN, fontSize);
            int texId = getTextTexture1(text, f, colorARGB);
            String key = text + "#" + f.getSize();
            int[] wh = textSizeCache1.get(key);
            if (wh == null)
                return;
            int w = wh[0];
            int h = wh[1];

            GL11.glPushAttrib(GL11.GL_ALL_ATTRIB_BITS);
            GL11.glEnable(GL11.GL_BLEND);
            GL11.glBlendFunc(GL11.GL_SRC_ALPHA, GL11.GL_ONE_MINUS_SRC_ALPHA);
            GL11.glEnable(GL11.GL_TEXTURE_2D);

            GL11.glBindTexture(GL11.GL_TEXTURE_2D, texId);
            GL11.glPushMatrix();
            drawTextureQuad1(x, y, w, h);
            GL11.glPopMatrix();

            GL11.glBindTexture(GL11.GL_TEXTURE_2D, 0);
            GL11.glDisable(GL11.GL_TEXTURE_2D);
            GL11.glDisable(GL11.GL_BLEND);
            GL11.glPopAttrib();

        } catch (Exception e) {
            e.printStackTrace();
        }
    }

    private static int getTextTexture1(String text, Font font, int colorARGB) {
        String key = text + "#" + font.getSize();
        if (textTextureCache1.containsKey(key))
            return textTextureCache1.get(key);

        BufferedImage tmp = new BufferedImage(1, 1, BufferedImage.TYPE_INT_ARGB);
        Graphics2D gtmp = tmp.createGraphics();
        gtmp.setFont(font);
        java.awt.FontMetrics fm = gtmp.getFontMetrics();
        int w = fm.stringWidth(text);
        int h = fm.getHeight();
        gtmp.dispose();

        if (w <= 0)
            w = 1;
        if (h <= 0)
            h = font.getSize();

        BufferedImage img = new BufferedImage(w, h, BufferedImage.TYPE_INT_ARGB);
        Graphics2D g2d = (Graphics2D) img.getGraphics();
        g2d.setRenderingHint(RenderingHints.KEY_TEXT_ANTIALIASING, RenderingHints.VALUE_TEXT_ANTIALIAS_ON);
        g2d.setRenderingHint(RenderingHints.KEY_ANTIALIASING, RenderingHints.VALUE_ANTIALIAS_ON);
        g2d.setFont(font);

        g2d.setComposite(java.awt.AlphaComposite.Src);
        g2d.setColor(new java.awt.Color((colorARGB >> 16) & 0xFF, (colorARGB >> 8) & 0xFF, colorARGB & 0xFF,
                (colorARGB >> 24) & 0xFF));
        int y = g2d.getFontMetrics().getAscent();
        g2d.drawString(text, 0, y);
        g2d.dispose();

        int texId = createTextureFromBufferedImage1(img);
        textTextureCache1.put(key, texId);
        textSizeCache1.put(key, new int[] { w, h });
        return texId;
    }

