    public static int getScaleFactor() {
        try {
            Object mc = getMinecraft();
            if (mc != null) {

                Class<?> srClass = (Class<?>) get("ScaledResolution");
                if (srClass != null) {
                    java.lang.reflect.Constructor<?> ctor = srClass.getConstructor(get("Minecraft"));
                    Object sr = ctor.newInstance(mc);
                    java.lang.reflect.Method m = srClass.getDeclaredMethod("getScaleFactor");
                    m.setAccessible(true);
                    return (Integer) m.invoke(sr);
                }


                Object gs = null;
                Class<?> gsClass = (Class<?>) get("GameSettings");
                if (gsClass != null) {
                    for (java.lang.reflect.Field f : mc.getClass().getDeclaredFields()) {
                        if (f.getType().equals(gsClass)) {
                            f.setAccessible(true);
                            gs = f.get(mc);
                            break;
                        }
                    }
                }

                if (gs != null) {
                    for (java.lang.reflect.Field f : gs.getClass().getDeclaredFields()) {
                        if (f.getType() == int.class
                                && (f.getName().equals("guiScale") || f.getName().equals("field_74335_Z"))) {
                            f.setAccessible(true);
                            int scale = f.getInt(gs);
                            if (scale != 0)
                                return scale;
                            break;
                        }
                    }
                }
            }
        } catch (Throwable ignored) {
        }

        return 2;
    }

