    private static int getRiceColor(float offset) {
        float time = (System.currentTimeMillis() % 750) / 750f;
        float t = (time + offset) % 1.0f;



        float brightness;
        if (t < 0.5f) {
            brightness = 1.0f - (t / 0.5f) * 0.85f;
        } else {
            brightness = 0.15f + ((t - 0.5f) / 0.5f) * 0.85f;
        }

        int c = (int) (brightness * 255);
        return (0xFF << 24) | (c << 16) | (c << 8) | c;
    }

    private static int getRiceColor(int index) {
        return getRiceColor(index * 0.15f);
    }

