    public static int mapMouseToGuiX(int mouseX) {
        try {
            int displayW = Display.getWidth();
            int guiW = getScreenWidth();
            return (int) ((long) mouseX * guiW / Math.max(displayW, 1));
        } catch (Throwable t) {
            return mouseX;
        }
    }

    public static int mapMouseToGuiY(int mouseY) {
        try {
            int displayH = Display.getHeight();
            int guiH = getScreenHeight();
            int mapped = (int) ((long) mouseY * guiH / Math.max(displayH, 1));
            return guiH - mapped - 1;
        } catch (Throwable t) {
            return mouseY;
        }
    }

    public static float wrapAngleTo180_float(float angle) {
        angle %= 360.0F;
        if (angle >= 180.0F)
            angle -= 360.0F;
        if (angle < -180.0F)
            angle += 360.0F;
        return angle;
    }

