    public static int getModernColor(int index, float offset) {
        long time = System.currentTimeMillis();
        double wave = Math.sin(time * 0.003D + (index + offset) * 0.15D) * 0.5D + 0.5D;
        double wave2 = Math.sin(time * 0.005D + (index + offset) * 0.1D) * 0.5D + 0.5D;
        int r = (int) (100 + wave * 155);
        int g = (int) (50 + wave2 * 180);
        int b = (int) (200 + wave * 55);
        return new Color(Math.min(255, r), Math.min(255, g), Math.min(255, b), 255).getRGB();
    }


    public static int getNeonColor(int index, float offset) {
        long time = System.currentTimeMillis();
        float hue = (float) ((time * 0.001D + (index + offset) * 0.06D) % 1.0D);
        int rgb = Color.HSBtoRGB(hue, 1.0f, 1.0f);
        return rgb | 0xFF000000;
    }


    public static int getGalaxyColor(int index, float offset) {
        long time = System.currentTimeMillis();
        double t = time * 0.004D + (index + offset) * 0.12D;
        double phase1 = Math.sin(t) * 0.5D + 0.5D;
        double phase2 = Math.sin(t + 2.094D) * 0.5D + 0.5D;
        double phase3 = Math.sin(t + 4.189D) * 0.5D + 0.5D;

        int r = (int) (80 + phase1 * 175);
        int g = (int) (20 + phase3 * 100);
        int b = (int) (150 + phase2 * 105);
        return new Color(Math.min(255, r), Math.min(255, g), Math.min(255, b), 255).getRGB();
    }


    public static int getFadeColor(int index, float offset) {
        long time = System.currentTimeMillis();
        double t = time * 0.004D + (index + offset) * 0.08D;

        double r = Math.sin(t) * 127 + 128;
        double g = Math.sin(t + 2.0D) * 127 + 128;
        double b = Math.sin(t + 4.0D) * 127 + 128;

        r = Math.min(255, r * 1.2);
        g = Math.min(255, g * 1.1);
        b = Math.min(255, b * 1.3);
        return new Color((int) r, (int) g, (int) b, 255).getRGB();
    }


    public static int getGlassColor(int index, float offset) {
        long time = System.currentTimeMillis();
        double wave = Math.sin(time / 1200.0D - index * 0.5D - offset * 0.003D) * 0.5D + 0.5D;
        int val = (int) (130 + wave * 125);
        return new Color(val, val, val, 255).getRGB();
    }


    public static int getShadowColor(int index, float offset) {
        long time = System.currentTimeMillis();
        double wave = Math.sin(time * 0.005D + (index + offset) * 0.1D) * 0.5D + 0.5D;
        double flicker = Math.sin(time * 0.015D + index * 0.3D) * 0.15D + 0.85D;
        int r = (int) (180 + wave * 75);
        int g = (int) (40 + wave * 120);
        int b = (int) (10 + wave * 30);
        r = (int) Math.min(255, r * flicker);
        g = (int) Math.min(255, g * flicker);
        b = (int) Math.min(255, b * flicker);
        return new Color(r, g, b, 255).getRGB();
    }

    public static int getOceanColor(int index, float offset) {
        long time = System.currentTimeMillis();
        double wave = Math.sin(time * 0.005D + (index + offset) * 0.1D) * 0.5D + 0.5D;
        double flicker = Math.sin(time * 0.015D + index * 0.3D) * 0.15D + 0.85D;
        int r = (int) (10 + wave * 60);
        int g = (int) (140 + wave * 80);
        int b = (int) (200 + wave * 55);
        r = (int) Math.min(255, r * flicker);
        g = (int) Math.min(255, g * flicker);
        b = (int) Math.min(255, b * flicker);
        return new Color(r, g, b, 255).getRGB();
    }

