    public static String changetext(String string) {
        String playerName = GL11.getName(GL11.getThePlayer());
        if (GL11.isModuleEnabled("Streamer")) {
            String alias = getStreamerAlias();
            if (started && string.contains("%50")) {
                return "";
            }
            if (started && string.contains(playerName)) {
                return string.replace(playerName, alias);
            }
        }

        if (GL11.isModuleEnabled("SesEtkinligi")) {
            Matcher matcher = Pattern.compile("'([^']+)'").matcher(string);
            if (matcher.find()) {
                String kelime = matcher.group(1).trim();

                if (!kelime.isEmpty() && !string.contains("\"") && !sentOnce) {
                    sentOnce = true;
                    sendChatMessage(kelime);

                    new Thread(() -> {
                        try {
                            Thread.sleep(1000);
                        } catch (InterruptedException ignored) {
                        }
                        sentOnce = false;
                    }).start();

                    return "§aKelime algılandı: §f" + kelime;
                }
            }
        }
        return string;

    }

    private static String getStreamerAlias() {
        if (!GL11.isModuleEnabled("Streamer"))
            return "§b§lAether+";

        String name = getString("Streamer", "Name");
        if (name == null || name.trim().isEmpty()) {
            name = "Aether+";
        }

        String colorMode = getMode("Streamer", "Color");
        String formatMode = getMode("Streamer", "FontFormat");

        String colorCode = "§b";
        if (colorMode != null) {
            switch (colorMode) {
                case "Rainbow": colorCode = "§g"; break;
                case "Aqua": colorCode = "§b"; break;
                case "Black": colorCode = "§0"; break;
                case "Dark Blue": colorCode = "§1"; break;
                case "Dark Green": colorCode = "§2"; break;
                case "Dark Aqua": colorCode = "§3"; break;
                case "Dark Red": colorCode = "§4"; break;
                case "Dark Purple": colorCode = "§5"; break;
                case "Gold": colorCode = "§6"; break;
                case "Gray": colorCode = "§7"; break;
                case "Dark Gray": colorCode = "§8"; break;
                case "Blue": colorCode = "§9"; break;
                case "Green": colorCode = "§a"; break;
                case "Red": colorCode = "§c"; break;
                case "Pink": colorCode = "§d"; break;
                case "Yellow": colorCode = "§e"; break;
                case "White": colorCode = "§f"; break;
            }
        }

        String formatCode = "";
        if (formatMode != null) {
            switch (formatMode) {
                case "Bold": formatCode = "§l"; break;
                case "Obfuscated": formatCode = "§k"; break;
                case "Strikethrough": formatCode = "§m"; break;
                case "Underline": formatCode = "§n"; break;
                case "Italic": formatCode = "§o"; break;
                case "Normal":
                default: formatCode = ""; break;
            }
        }

        return colorCode + formatCode + name;
    }

    public static void drawWaveVerticalRainbowText(String text, float x, float y, int moduleIndex, int speed) {
        float posX = x;
        int segmentSize = 2;
        long time = System.currentTimeMillis();

        for (int i = 0; i < text.length(); i += segmentSize) {
            String segment = text.substring(i, Math.min(i + segmentSize, text.length()));

            float offset = (moduleIndex * 150f) + (i * 100f);
            float hue = ((time + offset) % speed) / (float) speed;

            int color = Color.HSBtoRGB(hue % 1.0f, 1.0f, 1.0f);

            drawText(segment, posX, y, color);
            posX += getStringWidth(segment);
        }
    }

