    public static Vector3f projectToScreen(float x, float y, float z) {
        FloatBuffer modelView = BufferUtils.createFloatBuffer(16);
        FloatBuffer projection = BufferUtils.createFloatBuffer(16);
        IntBuffer viewport = BufferUtils.createIntBuffer(16);
        FloatBuffer screenCoords = BufferUtils.createFloatBuffer(3);

        GL11.glGetFloat(GL11.GL_MODELVIEW_MATRIX, modelView);
        GL11.glGetFloat(GL11.GL_PROJECTION_MATRIX, projection);
        GL11.glGetInteger(GL11.GL_VIEWPORT, viewport);

        boolean result = GLU.gluProject(x, y, z, modelView, projection, viewport, screenCoords);

        if (result) {
            float sx = screenCoords.get(0);
            float sy = viewport.get(3) - screenCoords.get(1);
            return new Vector3f(sx, sy, screenCoords.get(2));
        }
        return null;
    }

    public static Vector3f screenToWorld(float screenX, float screenY) {
        IntBuffer viewport = BufferUtils.createIntBuffer(16);
        FloatBuffer modelview = BufferUtils.createFloatBuffer(16);
        FloatBuffer projection = BufferUtils.createFloatBuffer(16);
        FloatBuffer position = BufferUtils.createFloatBuffer(3);

        GL11.glGetInteger(GL11.GL_VIEWPORT, viewport);
        GL11.glGetFloat(GL11.GL_MODELVIEW_MATRIX, modelview);
        GL11.glGetFloat(GL11.GL_PROJECTION_MATRIX, projection);

        float realY = viewport.get(3) - screenY;

        boolean success = GLU.gluUnProject(screenX, realY, 0.0f, modelview, projection, viewport, position);
        if (success) {
            return new Vector3f(position.get(0), position.get(1), position.get(2));
        }
        return null;
    }

