    static Runnable createClipModule(String name, int key, double yOffset) {
        return () -> {
            String clipMode = getMode(name, "Mode");
            boolean isHold = "Hold".equals(clipMode);

            if (isHold) {

                new Thread(() -> {
                    int idx = moduleNames.indexOf(name);
                    int boundKey = (idx != -1 && idx < moduleBindKeys.size()) ? moduleBindKeys.get(idx) : 0;
                    while (isModuleEnabled(name)) {
                        if (boundKey == 0 || !Keyboard.isKeyDown(boundKey)) {

                            if (idx != -1) {
                                moduleEnabled.set(idx, false);
                                moduleOnDisable.get(idx).run();
                            }
                            break;
                        }
                        double px = getPosX();
                        double py = getPosY();
                        double pz = getPosZ();
                        double originalMotionY = getMotionY();
                        setMotionY(0);
                        setPosition(px, py + yOffset, pz);
                        setMotionY(originalMotionY);
                        try { Thread.sleep(50); } catch (InterruptedException ignored) {}
                    }
                }, name + "-HoldThread").start();
            } else {

                double x = getPosX();
                double y = getPosY();
                double z = getPosZ();

                double originalMotionY = getMotionY();
                setMotionY(0);
                setPosition(x, y + yOffset, z);

                try {
                    Thread.sleep(50);
                } catch (InterruptedException ignored) {
                }

                setMotionY(originalMotionY);

                int i = moduleNames.indexOf(name);
                if (i != -1) {
                    moduleEnabled.set(i, false);
                    moduleOnDisable.get(i).run();
                }
            }
        };
    }

    static Runnable createForwardClipModule(String name, int key, double distance) {
        return () -> {
            String clipMode = getMode(name, "Mode");
            boolean isHold = "Hold".equals(clipMode);

            if (isHold) {

                new Thread(() -> {
                    int idx = moduleNames.indexOf(name);
                    int boundKey = (idx != -1 && idx < moduleBindKeys.size()) ? moduleBindKeys.get(idx) : 0;
                    while (isModuleEnabled(name)) {
                        if (boundKey == 0 || !Keyboard.isKeyDown(boundKey)) {

                            if (idx != -1) {
                                moduleEnabled.set(idx, false);
                                if (moduleOnDisable.size() > idx) moduleOnDisable.get(idx).run();
                            }
                            break;
                        }
                        Random rand = new Random();
                        int blockCount = 4 + rand.nextInt(2);
                        double variedDistance = blockCount * (0.9 + (rand.nextDouble() * 0.2));

                        double px = getPosX();
                        double py = getPosY();
                        double pz = getPosZ();

                        double yaw = Math.toRadians(getRotationYaw());
                        double dx = -Math.sin(yaw) * variedDistance;
                        double dz = Math.cos(yaw) * variedDistance;
                        double dy = (rand.nextDouble() - 0.5) * 0.1;

                        setMotionX(0);
                        setMotionY(0);
                        setMotionZ(0);
                        setPosition(px + dx, py + dy, pz + dz);

                        double smallDx = -Math.sin(yaw) * 0.2;
                        double smallDz = Math.cos(yaw) * 0.2;
                        setPosition(getPosX() + smallDx, getPosY(), getPosZ() + smallDz);

                        try { Thread.sleep(50); } catch (InterruptedException ignored) {}
                    }
                }, name + "-HoldThread").start();
            } else {

                Random rand = new Random();
                int blockCount = 4 + rand.nextInt(2);
                double variedDistance = blockCount * (0.9 + (rand.nextDouble() * 0.2));

                double x = getPosX();
                double y = getPosY();
                double z = getPosZ();

                double yaw = Math.toRadians(getRotationYaw());
                double dx = -Math.sin(yaw) * variedDistance;
                double dz = Math.cos(yaw) * variedDistance;

                double dy = (rand.nextDouble() - 0.5) * 0.1;

                setMotionX(0);
                setMotionY(0);
                setMotionZ(0);
                setPosition(x + dx, y + dy, z + dz);

                try {
                    Thread.sleep(25 + rand.nextInt(15));
                } catch (InterruptedException ignored) {
                }

                double smallDx = -Math.sin(yaw) * 0.2;
                double smallDz = Math.cos(yaw) * 0.2;
                setPosition(getPosX() + smallDx, getPosY(), getPosZ() + smallDz);

                try {
                    Thread.sleep(20 + rand.nextInt(10));
                } catch (InterruptedException ignored) {
                }
                int i = moduleNames.indexOf(name);
                if (i != -1) {
                    moduleEnabled.set(i, false);
                    if (moduleOnDisable.size() > i) {
                        moduleOnDisable.get(i).run();
                    }
                }
            }
        };
    }

