    public static Field findInventoryContainer(byte[] classBytes) throws Exception {
        ClassReader cr = new ClassReader(classBytes);
        ClassNode cn = new ClassNode();
        cr.accept(cn, 0);

        Class<?> containerClass = get("Container");
        String containerDesc = org.objectweb.asm.Type.getDescriptor(containerClass);

        for (MethodNode m : cn.methods) {
            if (!m.name.equals("<init>"))
                continue;

            InsnList insns = m.instructions;

            for (int i = 0; i < insns.size(); i++) {
                AbstractInsnNode insn = insns.get(i);
                if (insn.getOpcode() == PUTFIELD) {
                    FieldInsnNode f = (FieldInsnNode) insn;

                    if (f.desc.equals(containerDesc)) {
                        return asmFieldToReflectionField(get("EntityPlayer"), f.name, f.desc);
                    }
                }
            }
        }
        return null;
    }

    private static int getParamCountFromDescriptor(String desc) {

        int count = 0;
        int i = 1;
        while (desc.charAt(i) != ')') {
            char c = desc.charAt(i);
            if (c == 'L') {
                i = desc.indexOf(';', i) + 1;
                count++;
                continue;
            } else if (c == '[') {

                i++;
                continue;
            } else {

                count++;
                i++;
            }
        }
        return count;
    }

    public static Method findGetSizeInventoryMethod(byte[] classBytes, Class<?> clazz) {
        ClassReader reader = new ClassReader(classBytes);
        ClassNode classNode = new ClassNode();
        reader.accept(classNode, 0);

        String internalName = clazz.getName().replace('.', '/');

        for (MethodNode method : classNode.methods) {
            if (!method.desc.endsWith(")I"))
                continue;

            boolean containsGetField = false;
            boolean containsConstantReturn = false;

            for (AbstractInsnNode insn : method.instructions.toArray()) {
                int opcode = insn.getOpcode();

                if (opcode == Opcodes.ICONST_0 || opcode == Opcodes.ICONST_1 || opcode == Opcodes.ICONST_2 ||
                        opcode == Opcodes.ICONST_3 || opcode == Opcodes.ICONST_4 || opcode == Opcodes.ICONST_5 ||
                        opcode == Opcodes.BIPUSH || opcode == Opcodes.SIPUSH) {
                    containsConstantReturn = true;
                } else if (opcode == Opcodes.LDC) {
                    LdcInsnNode ldc = (LdcInsnNode) insn;
                    if (ldc.cst instanceof Integer) {
                        containsConstantReturn = true;
                    }
                } else if (opcode == Opcodes.GETFIELD) {
                    FieldInsnNode fin = (FieldInsnNode) insn;
                    if (fin.owner.equals(internalName)) {
                        containsGetField = true;
                    }
                }
            }

            if (containsGetField && !containsConstantReturn) {
                try {
                    Method reflMethod = clazz.getDeclaredMethod(method.name, getParameterTypesFromDesc(method.desc));
                    reflMethod.setAccessible(true);
                    return reflMethod;
                } catch (NoSuchMethodException e) {
                    e.printStackTrace();
                }
            }
        }

        return null;
    }

    private static Class<?>[] getParameterTypesFromDesc(String desc) {
        org.objectweb.asm.Type[] argTypes = org.objectweb.asm.Type.getArgumentTypes(desc);
        Class<?>[] classes = new Class<?>[argTypes.length];
        try {
            for (int i = 0; i < argTypes.length; i++) {
                classes[i] = Class.forName(argTypes[i].getClassName());
            }
        } catch (ClassNotFoundException e) {
            e.printStackTrace();
        }
        return classes;
    }

    public static Field getUpperInventory(byte[] classBytes, Class<?> clazz) {
        ClassReader reader = new ClassReader(classBytes);
        ClassNode classNode = new ClassNode();
        reader.accept(classNode, 0);

        String internalName = clazz.getName().replace('.', '/');

        for (MethodNode method : classNode.methods) {
            if (!method.name.equals("<init>"))
                continue;

            org.objectweb.asm.Type[] args = org.objectweb.asm.Type.getArgumentTypes(method.desc);
            if (args.length != 2 || !args[0].equals(args[1]) || args[0].getClassName().startsWith("java."))
                continue;

            AbstractInsnNode insn = method.instructions.getFirst();
            while (insn != null) {
                if (insn.getOpcode() == PUTFIELD) {
                    FieldInsnNode fieldInsn = (FieldInsnNode) insn;
                    AbstractInsnNode prev = insn.getPrevious();
                    if (fieldInsn.owner.equals(internalName) && prev.getOpcode() == Opcodes.ALOAD
                            && ((VarInsnNode) prev).var == 1) {
                        return asmFieldToReflectionField(clazz, fieldInsn.name, fieldInsn.desc);
                    }
                }
                insn = insn.getNext();
            }
        }

        return null;
    }

    public static Method findGetStackInSlotMethod(byte[] classBytes, Class<?> clazz) {
        ClassReader reader = new ClassReader(classBytes);
        ClassNode classNode = new ClassNode();
        reader.accept(classNode, 0);

        Class<?> itemStackClass = get("ItemStack");
        String itemStackInternalName = itemStackClass.getName().replace('.', '/');

        for (MethodNode method : classNode.methods) {

            if (!method.desc.equals("(I)L" + itemStackInternalName + ";"))
                continue;

            if ((method.access & Opcodes.ACC_PUBLIC) == 0)
                continue;

            boolean hasArrayLoad = false;
            boolean hasArrayStore = false;
            boolean hasIndexCheck = false;
            boolean returnsArrayElement = false;

            for (AbstractInsnNode insn : method.instructions.toArray()) {
                int opcode = insn.getOpcode();

                if (opcode == Opcodes.AALOAD)
                    hasArrayLoad = true;
                if (opcode == Opcodes.AASTORE)
                    hasArrayStore = true;
                if (opcode == Opcodes.IF_ICMPLT || opcode == Opcodes.IF_ICMPGE ||
                        opcode == Opcodes.IF_ICMPGT || opcode == Opcodes.IF_ICMPLE)
                    hasIndexCheck = true;
                if (opcode == Opcodes.ARETURN)
                    returnsArrayElement = true;
            }

            if (hasArrayLoad && !hasArrayStore && hasIndexCheck && returnsArrayElement) {
                try {
                    Method reflMethod = clazz.getDeclaredMethod(method.name, int.class);
                    if (!java.lang.reflect.Modifier.isPublic(reflMethod.getModifiers())) {
                        continue;
                    }
                    reflMethod.setAccessible(true);
                    return reflMethod;
                } catch (NoSuchMethodException e) {
                    e.printStackTrace();
                }
            }
        }

        return null;
    }

