    public static Class<?> findPlayerControllerMP() {
        outerLoop: for (Class<?> clazz : getClasses()) {
            int passedChecks = 0;

            Constructor<?> matchingConstructor = null;
            for (Constructor<?> ctor : clazz.getDeclaredConstructors()) {
                if (ctor.getParameterCount() == 2 &&
                        ctor.getParameterTypes()[0] == get("Minecraft") &&
                        ctor.getParameterTypes()[1] == get("NetHandlerPlayClient")) {
                    matchingConstructor = ctor;
                    break;
                }
            }
            if (matchingConstructor == null)
                continue;

            boolean hasMinecraftField = false;
            boolean hasNetHandlerField = false;
            boolean hasItemStackField = false;

            for (Field field : clazz.getDeclaredFields()) {
                if (!Modifier.isPrivate(field.getModifiers()))
                    continue;

                if (field.getType() == get("Minecraft")) {
                    hasMinecraftField = true;
                } else if (field.getType() == get("NetHandlerPlayClient")) {
                    hasNetHandlerField = true;
                } else if (field.getType() == get("ItemStack")) {
                    hasItemStackField = true;
                }
            }

            if (hasMinecraftField && hasNetHandlerField && hasItemStackField) {
                passedChecks++;
            }

            for (Method method : clazz.getMethods()) {
                if (Modifier.isPublic(method.getModifiers()) &&
                        method.getReturnType() == float.class &&
                        method.getParameterCount() == 0) {
                    passedChecks++;
                    break;
                }
            }

            for (Method method : clazz.getMethods()) {
                Class<?>[] params = method.getParameterTypes();
                if (Modifier.isPublic(method.getModifiers()) &&
                        params.length == 2 &&
                        params[0] == get("ItemStack") &&
                        params[1] == int.class) {
                    passedChecks++;
                    break;
                }
            }

            if (passedChecks == 3) {
                return clazz;
            }
        }
        return null;
    }

