    void drawRoundedRect(float x, float y, float width, float height, float radius, Color color) {
        GL11.glEnable(GL11.GL_BLEND);
        GL11.glDisable(GL11.GL_TEXTURE_2D);
        GL11.glBlendFunc(GL11.GL_SRC_ALPHA, GL11.GL_ONE_MINUS_SRC_ALPHA);
        GL11.glColor4f(color.getRed() / 255f, color.getGreen() / 255f, color.getBlue() / 255f, color.getAlpha() / 255f);

        int segments = 16;

        drawRect(x + radius, y, x + width - radius, y + height);
        drawRect(x, y + radius, x + width, y + height - radius);

        drawQuarterCircle(x + radius, y + radius, radius, 180, 270, segments);
        drawQuarterCircle(x + width - radius, y + radius, radius, 270, 360, segments);
        drawQuarterCircle(x + radius, y + height - radius, radius, 90, 180, segments);
        drawQuarterCircle(x + width - radius, y + height - radius, radius, 0, 90, segments);

        GL11.glEnable(GL11.GL_TEXTURE_2D);
        GL11.glDisable(GL11.GL_BLEND);
    }

    void drawRect(float x1, float y1, float x2, float y2) {
        GL11.glBegin(GL11.GL_QUADS);
        GL11.glVertex2f(x1, y1);
        GL11.glVertex2f(x2, y1);
        GL11.glVertex2f(x2, y2);
        GL11.glVertex2f(x1, y2);
        GL11.glEnd();
    }

    public static float getWidth() {
        return Math.max(getStringWidth(getName(closestTarget)), 110);
    }

    void drawQuarterCircle(float cx, float cy, float radius, int startAngle, int endAngle, int segments) {
        GL11.glBegin(GL11.GL_TRIANGLE_FAN);
        GL11.glVertex2f(cx, cy);
        for (int i = startAngle; i <= endAngle; i += (endAngle - startAngle) / segments) {
            double rad = Math.toRadians(i);
            float x = cx + (float) (Math.cos(rad) * radius);
            float y = cy + (float) (Math.sin(rad) * radius);
            GL11.glVertex2f(x, y);
        }
        GL11.glEnd();
    }

