    static void drawNewTargetHUD(Object target) {
        if (!isModuleEnabled("TargetHUD"))
            return;

        float x = targetCenter.x + 4.0F;
        float y = targetCenter.y + 4.0F;
        float width = 120.0F;
        float height = 40.0F;

        float targethealth = getHealth(target);
        float selfhealth = getHealth(getPlayer());


        int sw = getScreenWidth();
        int sh = getScreenHeight();
        float bX = x, bY = y, bW = width, bH = height;
        if (bX + bW > sw) bW = sw - bX;
        if (bX < 0) { bW += bX; bX = 0; }
        if (bY + bH > sh) bH = sh - bY;
        if (bY < 0) { bH += bY; bY = 0; }
        if (bW > 0 && bH > 0 && bX < sw && bY < sh) {
            renderRoundedBlur(x, y, width, height, 35, 6.0f);
        }
        roundedRect(x, y, width, height, 6.0F, new Color(10, 10, 10, 70));


        GL11.glEnable(3042);
        GL11.glColor4f(1f, 1f, 1f, 1f);
        bindTexture(getLocationSkin(target));
        drawScaledCustomSizeModalRect(x + 6.0F, y + 6.0F, 3.0F, 3.0F, 3.0F, 3.0F, 20.0F, 20.0F, 24.0F, 24.0F);
        bindTexture(getLocationSkin(target));
        drawScaledCustomSizeModalRect(x + 6.0F, y + 6.0F, 15.0F, 3.0F, 3.0F, 3.0F, 20.0F, 20.0F, 24.0F, 24.0F);
        GL11.glDisable(3042);


        drawString(getName(target), x + 32.0F, y + 6.0F, Color.WHITE.getRGB());
        float distance = Math.round(distanceTo(target) * 100.0F) / 100.0F;
        drawString(distance + "m", x + 32.0F, y + 18.0F, new Color(200, 200, 200).getRGB());


        String status;
        if (selfhealth > targethealth) {
            float diff = selfhealth - targethealth;
            status = diff > 10 ? "WIN" : diff > 5 ? "W" : "w";
        } else if (targethealth > selfhealth) {
            float diff = targethealth - selfhealth;
            status = diff > 10 ? "LOSE" : diff > 5 ? "L" : "l";
        } else {
            status = "=";
        }
        drawString(status, x + width - 25.0F, y + 6.0F, Color.WHITE.getRGB());


        float healthBarWidth = (getHealth(target) / 20.0F) * (width - 12.0F);
        roundedRect(x + 6.0F, y + height - 8.0F, width - 12.0F, 4.0F, 2.0F, new Color(30, 30, 30, 150));
        roundedRect(x + 6.0F, y + height - 8.0F, healthBarWidth, 4.0F, 2.0F, new Color(220, 220, 220, 200));
    }

