    private static float notifEaseOutBack(float t) {
        float c1 = 1.70158f;
        float c3 = c1 + 1f;
        float t1 = t - 1f;
        return 1f + c3 * t1 * t1 * t1 + c1 * t1 * t1;
    }

    private static float notifEaseInCubic(float t) {
        return t * t * t;
    }

    private static float notifEaseOutCubic(float t) {
        float t1 = t - 1f;
        return 1f + t1 * t1 * t1;
    }

    private static float notifEaseInOutSine(float t) {
        return -(float) (Math.cos(Math.PI * t) - 1f) / 2f;
    }

    private static float notifEaseOutQuint(float t) {
        float t1 = t - 1f;
        return 1f + t1 * t1 * t1 * t1 * t1;
    }

    private static float notifEaseOutElastic(float t) {
        if (t == 0f || t == 1f)
            return t;
        float c4 = (float) (2.0 * Math.PI) / 3f;
        return (float) (Math.pow(2, -10 * t) * Math.sin((t * 10f - 0.75f) * c4) + 1f);
    }

    private static float notifLerp(float a, float b, float t) {
        return a + (b - a) * t;
    }

    private static float notifClamp(float val, float min, float max) {
        return val < min ? min : (val > max ? max : val);
    }

    private static int notifArgb(int a, int r, int g, int b) {
        return ((a & 0xFF) << 24) | ((r & 0xFF) << 16) | ((g & 0xFF) << 8) | (b & 0xFF);
    }

    private static int notifLerpColor(int c1, int c2, float t) {
        int a1 = (c1 >> 24) & 0xFF, r1 = (c1 >> 16) & 0xFF, g1 = (c1 >> 8) & 0xFF, b1 = c1 & 0xFF;
        int a2 = (c2 >> 24) & 0xFF, r2 = (c2 >> 16) & 0xFF, g2 = (c2 >> 8) & 0xFF, b2 = c2 & 0xFF;
        int a = (int) (a1 + (a2 - a1) * t);
        int r = (int) (r1 + (r2 - r1) * t);
        int g = (int) (g1 + (g2 - g1) * t);
        int b = (int) (b1 + (b2 - b1) * t);
        return notifArgb(a, r, g, b);
    }

