    public static void post(String type, String title, String description, float seconds) {

        while (notifDataList.size() >= NOTIF_MAX_VISIBLE) {
            notifRemoveAt(0);
        }
        notifDataList.add(new String[] { type.toUpperCase(), title, description });
        notifTimingList.add(new long[] {
                System.currentTimeMillis(),
                (long) (NOTIF_SLIDE_IN_MS),
                (long) (seconds * 1000f),
                (long) (NOTIF_SLIDE_OUT_MS),
                ++notifIdCounter
        });
        notifStateList.add(new int[] { NOTIF_STATE_SLIDE_IN });
        notifAnimList.add(new float[] {
                0f,
                0f,
                0f,
                0f,
                0f,
                0f,
                0f
        });
        notifParticles.add(notifCreateParticles());
        notifTargetYList.add(new float[] { 0f });
        notifCurrentYList.add(new float[] { -getNotifHeight() });
    }

