    public static void render1() {
        if (!isModuleEnabled("Notifications"))
            return;
        if (notifDataList.isEmpty())
            return;

        GL11.glPushAttrib(GL11.GL_ALL_ATTRIB_BITS);
        GL11.glPushMatrix();
        GL11.glEnable(GL11.GL_BLEND);
        GL11.glBlendFunc(GL11.GL_SRC_ALPHA, GL11.GL_ONE_MINUS_SRC_ALPHA);

        int screenW = getScreenWidth();
        int screenH = getScreenHeight();


        long nowMs = System.currentTimeMillis();
        float dt = 1f / 60f;
        if (notifLastFrameMs != 0) {
            dt = (nowMs - notifLastFrameMs) / 1000f;
            if (dt > 0.1f) dt = 0.1f;
            if (dt < 0.001f) dt = 0.001f;
        }
        notifLastFrameMs = nowMs;

        float scale = hudNotifPos != null ? getHudScale(0) : 1.0f;

        GL11.glPushMatrix();
        GL11.glScalef(scale, scale, 1.0f);


        float stackY = hudNotifPos != null ? (hudNotifPos[1] + hudNotifPos[3]) / scale : screenH - NOTIF_MARGIN_BOTTOM;
        for (int i = notifDataList.size() - 1; i >= 0; i--) {
            stackY -= getNotifHeight();
            notifTargetYList.get(i)[0] = stackY;
            stackY -= NOTIF_CARD_GAP;
        }


        for (int i = 0; i < notifDataList.size(); i++) {
            notifUpdateState(i, dt);

            float targetY = notifTargetYList.get(i)[0];
            float currentY = notifCurrentYList.get(i)[0];
            float smoothSpeed = 1f - (float) Math.exp(-dt / 0.08f);
            currentY += (targetY - currentY) * smoothSpeed;
            notifCurrentYList.get(i)[0] = currentY;

            notifUpdateParticles(notifParticles.get(i), dt);

            float baseX = hudNotifPos != null
                    ? (hudNotifPos[0] + hudNotifPos[2]) / scale - getNotifWidth()
                    : screenW - getNotifWidth() - NOTIF_MARGIN_RIGHT;
            notifRenderCard(i, baseX, currentY);
        }

        GL11.glPopMatrix();


        for (int i = notifDataList.size() - 1; i >= 0; i--) {
            if (notifStateList.get(i)[0] == NOTIF_STATE_DEAD) {
                notifRemoveAt(i);
            }
        }

        GL11.glPopMatrix();
        GL11.glPopAttrib();
    }

