    public static void drawGradientRect(float left, float top, float right, float bottom, int startColor,
                                        int endColor) {
        GL11.glEnable(GL11.GL_BLEND);
        GL11.glDisable(GL11.GL_TEXTURE_2D);
        GL11.glBlendFunc(GL11.GL_SRC_ALPHA, GL11.GL_ONE_MINUS_SRC_ALPHA);
        GL11.glShadeModel(GL11.GL_SMOOTH);

        GL11.glBegin(GL11.GL_QUADS);
        {

            GL11.glColor4f((startColor >> 16 & 255) / 255.0F, (startColor >> 8 & 255) / 255.0F,
                    (startColor & 255) / 255.0F, (startColor >> 24 & 255) / 255.0F);
            GL11.glVertex2f(left, top);

            GL11.glColor4f((startColor >> 16 & 255) / 255.0F, (startColor >> 8 & 255) / 255.0F,
                    (startColor & 255) / 255.0F, (startColor >> 24 & 255) / 255.0F);
            GL11.glVertex2f(left, bottom);

            GL11.glColor4f((endColor >> 16 & 255) / 255.0F, (endColor >> 8 & 255) / 255.0F, (endColor & 255) / 255.0F,
                    (endColor >> 24 & 255) / 255.0F);
            GL11.glVertex2f(right, bottom);

            GL11.glColor4f((endColor >> 16 & 255) / 255.0F, (endColor >> 8 & 255) / 255.0F, (endColor & 255) / 255.0F,
                    (endColor >> 24 & 255) / 255.0F);
            GL11.glVertex2f(right, top);
        }
        GL11.glEnd();

        GL11.glShadeModel(GL11.GL_FLAT);
        GL11.glEnable(GL11.GL_TEXTURE_2D);
        GL11.glDisable(GL11.GL_BLEND);
    }

