    private static float barAnimationValue = 20f;

    public static void updateBarAnimation(float currentHp) {
        float speed = 0.1f;
        if (barAnimationValue < currentHp) {
            barAnimationValue += speed;
            if (barAnimationValue > currentHp)
                barAnimationValue = currentHp;
        } else if (barAnimationValue > currentHp) {
            barAnimationValue -= speed;
            if (barAnimationValue < currentHp)
                barAnimationValue = currentHp;
        }
    }

