    private static int calculateAdaptiveResetThreshold() {
        int baseThreshold = 260 + patternRandom.nextInt(220);
        double phaseModifier = 1.0 - (sessionPhase * 0.07);
        double accuracyModifier = calculateRecentAccuracy() > 0.7 ? 1.15 : 0.92;
        double jitterFactor = 0.9 + patternRandom.nextDouble() * 0.3;
        int val = (int) (baseThreshold * phaseModifier * accuracyModifier * jitterFactor);
        return Math.max(120, val);
    }

