    public static boolean isPlayerMoving(Object entity) {
        if (entity == null) {
            wasMovingLastTick = false;
            return false;
        }


        double mx = getMotionX(entity);
        double my = getMotionY(entity);
        double mz = getMotionZ(entity);

        boolean motionMoving = Math.abs(mx) > MOTION_EPSILON ||
                Math.abs(my) > MOTION_EPSILON ||
                Math.abs(mz) > MOTION_EPSILON;


        double x = getPosX(entity);
        double y = getPosY(entity);
        double z = getPosZ(entity);

        boolean posMoving = false;

        if (!Double.isNaN(lastX)) {
            posMoving = Math.abs(x - lastX) > POS_EPSILON ||
                    Math.abs(y - lastY) > POS_EPSILON ||
                    Math.abs(z - lastZ) > POS_EPSILON;
        }


        lastX = x;
        lastY = y;
        lastZ = z;

        wasMovingLastTick = motionMoving || posMoving;
        return wasMovingLastTick;
    }

