    private static final double MOTION_EPSILON = 1.0E-4;
    private static final double POS_EPSILON = 1.0E-3;

    private static float[] getRotationsToPosition(double x, double y, double z) {
        try {
            Object player = getPlayer();
            if (player == null)
                return new float[] { 0, 0 };

            double playerX = getPosX(player);
            double playerY = getPosY(player) + getEyeHeight(player);
            double playerZ = getPosZ(player);

            double deltaX = x - playerX;
            double deltaY = y - playerY;
            double deltaZ = z - playerZ;

            double horizontalDistance = Math.sqrt(deltaX * deltaX + deltaZ * deltaZ);

            float yaw = (float) Math.toDegrees(Math.atan2(deltaZ, deltaX)) - 90F;
            float pitch = (float) -Math.toDegrees(Math.atan2(deltaY, horizontalDistance));

            return new float[] { yaw, pitch };
        } catch (Exception e) {
            return new float[] { 0, 0 };
        }
    }

