    private static UUID getEntityUUID(Object entity) {
        try {
            if (entity == null) return null;


            try {
                Method getUniqueID = entity.getClass().getMethod("getUniqueID");
                Object uuidObj = getUniqueID.invoke(entity);
                if (uuidObj instanceof UUID) {
                    return (UUID) uuidObj;
                }
            } catch (NoSuchMethodException ignored) {}


            try {
                Method getGameProfile = entity.getClass().getMethod("getGameProfile");
                Object profile = getGameProfile.invoke(entity);
                if (profile != null) {
                    Method getId = profile.getClass().getMethod("getId");
                    Object uuidObj = getId.invoke(profile);
                    if (uuidObj instanceof UUID) {
                        return (UUID) uuidObj;
                    }
                }
            } catch (Exception ignored) {}


            Class<?> clazz = entity.getClass();
            while (clazz != null && !clazz.equals(Object.class)) {
                for (Field field : clazz.getDeclaredFields()) {
                    if (field.getType().equals(UUID.class)) {
                        field.setAccessible(true);
                        Object uuidObj = field.get(entity);
                        if (uuidObj instanceof UUID) {
                            return (UUID) uuidObj;
                        }
                    }
                }
                clazz = clazz.getSuperclass();
            }
        } catch (Exception e) {

        }
        return null;
    }

