    private static void cleanupHealthTracking() {
        try {
            long currentTime = System.currentTimeMillis();


            if (currentTime - lastHealthTrackingCleanup < 30000) {
                return;
            }
            lastHealthTrackingCleanup = currentTime;

            List<UUID> toRemove = new ArrayList<>();
            for (Map.Entry<UUID, Long> entry : playerFirstSeenTime.entrySet()) {

                if (currentTime - entry.getValue() > 120000) {
                    toRemove.add(entry.getKey());
                }
            }

            for (UUID uuid : toRemove) {
                playerFirstSeenTime.remove(uuid);
                playerFirstHealth.remove(uuid);
                playerLastHealth.remove(uuid);
                playerHealthCheckCount.remove(uuid);
                playerHealthChanged.remove(uuid);
            }
        } catch (Exception e) {

        }
    }

