    public static List<Object> getNearbyEntities(Object sourceEntity, double radius) {
        List<Object> nearby = new ArrayList<>();
        if (sourceEntity == null)
            return nearby;

        try {
            double sourceX = getPosX(sourceEntity);
            double sourceY = getPosY(sourceEntity);
            double sourceZ = getPosZ(sourceEntity);

            Object worldObj = getWorldObj();
            if (worldObj == null)
                return nearby;

            List<Object> entities = getPlayerEntitiesInWorld();
            if (entities == null || entities.isEmpty())
                return nearby;

            for (Object entity : entities) {
                double x = getPosX(entity);
                double y = getPosY(entity);
                double z = getPosZ(entity);

                double dx = x - sourceX;
                double dy = y - sourceY;
                double dz = z - sourceZ;
                double distSq = dx * dx + dy * dy + dz * dz;

                if (distSq <= radius * radius) {
                    nearby.add(entity);
                }
            }

        } catch (Exception e) {
            e.printStackTrace();
        }

        return nearby;
    }

