    public static void teleportBehindEntityStep(Object target, double totalDistance, double step) {
        try {
            float yaw = getRotationYaw(target);
            double rad = Math.toRadians(yaw + 180f);

            double dirX = -Math.sin(rad);
            double dirZ = Math.cos(rad);

            double baseX = getPosX(target);
            double baseY = getPosY(target) + 0.2;
            double baseZ = getPosZ(target);

            double moved = 0.0;

            while (moved < totalDistance) {
                double currentStep = Math.min(step, totalDistance - moved);

                double x = baseX + dirX * moved;
                double z = baseZ + dirZ * moved;

                setPosition(x, baseY, z);

                setMotionX(0.0);
                setMotionY(0.0);
                setMotionZ(0.0);

                faceEntity(target);

                moved += currentStep;
            }

        } catch (Exception e) {
            e.printStackTrace();
        }
    }

    public static void faceEntity(Object target) {
        try {
            double dx = getPosX(target) - getPosX();
            double dz = getPosZ(target) - getPosZ();
            double dy = (getPosY(target) + 1.5) - (getPosY() + 1.5);

            double dist = Math.sqrt(dx * dx + dz * dz);

            float yaw = (float) (Math.toDegrees(Math.atan2(dz, dx)) - 90F);
            float pitch = (float) (-Math.toDegrees(Math.atan2(dy, dist)));

            setRotationYaw(yaw);
            setRotationPitch(pitch);

        } catch (Exception e) {
            e.printStackTrace();
        }
    }

    private static float generateRandomFloat(float minValue, float maxValue) {
        if (minValue >= maxValue) {
            return minValue;
        }
        return minValue + random.nextFloat() * (maxValue - minValue);
    }

    public static void lookAtDragonHead(Object dragon) {
        try {
            double dragonX = getPosX(dragon);
            double dragonY = getPosY(dragon);
            double dragonZ = getPosZ(dragon);

            double headY = dragonY + 8.0;

            Object player = getPlayer();
            double playerX = getPosX(player);
            double playerY = getPosY(player);
            double playerZ = getPosZ(player);

            double diffX = dragonX - playerX;
            double diffY = headY - (playerY + getEyeHeight(player));
            double diffZ = dragonZ - playerZ;

            double dist = Math.sqrt(diffX * diffX + diffZ * diffZ);

            float yaw = (float) (Math.atan2(diffZ, diffX) * 180.0 / Math.PI) - 90.0f;
            float pitch = (float) (-(Math.atan2(diffY, dist) * 180.0 / Math.PI));

            setRotationYawAndPitch(yaw, pitch);

        } catch (Exception e) {
            e.printStackTrace();
        }
    }

    public static void teleportBehindTarget(Object target) {
        float yaw = getRotationYaw(target);
        double rad = Math.toRadians(yaw);

        double tpX = getPosX(target) - Math.sin(rad);
        double tpY = getPosY(target);
        double tpZ = getPosZ(target) + Math.cos(rad);

        try {
            Object player = getThePlayer();
            Field posXField = getField("Entity.posX");
            Field posYField = getField("Entity.posY");
            Field posZField = getField("Entity.posZ");

            posXField.setDouble(player, tpX);
            posYField.setDouble(player, tpY);
            posZField.setDouble(player, tpZ);

        } catch (Exception e) {
            e.printStackTrace();
        }

        faceTarget(target);
    }

    public static void faceTarget(Object target) {
        double diffX = getPosX(target) - getPosX(getThePlayer());
        double diffZ = getPosZ(target) - getPosZ(getThePlayer());
        double diffY = getPosY(target) + getEyeHeight(target)
                - (getPosY(getThePlayer()) + getEyeHeight(getThePlayer()));

        double distXZ = Math.sqrt(diffX * diffX + diffZ * diffZ);
        float yaw = (float) Math.toDegrees(Math.atan2(diffZ, diffX)) - 90F;
        float pitch = (float) -Math.toDegrees(Math.atan2(diffY, distXZ));

        setRotationYawAndPitch(yaw, pitch);
    }

    public static Color applyOpacity(Color color, float opacity) {
        opacity = Math.min(1.0f, Math.max(0.0f, opacity));
        int r = clamp(color.getRed(), 0, 255);
        int g = clamp(color.getGreen(), 0, 255);
        int b = clamp(color.getBlue(), 0, 255);
        int a = clamp((int) (color.getAlpha() * opacity), 0, 255);
        return new Color(r, g, b, a);
    }

    private static int clamp(int val, int min, int max) {
        if (val < min)
            return min;
        if (val > max)
            return max;
        return val;
    }

    public static Color brighter(Color color, float FACTOR) {
        int r = color.getRed();
        int g = color.getGreen();
        int b = color.getBlue();
        int alpha = color.getAlpha();
        int i = (int) (1.0 / (1.0 - FACTOR));
        if (r == 0 && g == 0 && b == 0) {
            return new Color(i, i, i, alpha);
        }
        if (r > 0 && r < i)
            r = i;
        if (g > 0 && g < i)
            g = i;
        if (b > 0 && b < i)
            b = i;

        return new Color(Math.min((int) (r / FACTOR), 255),
                Math.min((int) (g / FACTOR), 255),
                Math.min((int) (b / FACTOR), 255),
                alpha);
    }

