    public static float getYawDifference(Object player, Object target) {
        try {
            double[] playerPos = getPosition(player);
            double[] targetPos = getPosition(target);

            double dx = targetPos[0] - playerPos[0];
            double dz = targetPos[2] - playerPos[2];

            float yawToTarget = (float) Math.toDegrees(Math.atan2(dz, dx)) - 90;
            float playerYaw = getYaw(player);

            float yawDiff = Math.abs((yawToTarget - playerYaw) % 360);
            if (yawDiff > 180)
                yawDiff = 360 - yawDiff;

            return yawDiff;
        } catch (Exception e) {
            System.err.println("getYawDifference genel hata:");
            e.printStackTrace();
            return Float.MAX_VALUE;
        }
    }

    public static byte[] toByteArray(InputStream is) throws IOException {
        ByteArrayOutputStream buffer = new ByteArrayOutputStream();
        int nRead;
        byte[] data = new byte[16384];
        while ((nRead = is.read(data, 0, data.length)) != -1) {
            buffer.write(data, 0, nRead);
        }
        buffer.flush();
        return buffer.toByteArray();
    }

