    private static void performSoftTeleport() {
        double targetX = getPosX();
        double targetY = getPosY();
        double targetZ = getPosZ();

        double teleportSpeed = 0.8;
        double deltaX = targetX - heldPosition[0];
        double deltaY = targetY - heldPosition[1];
        double deltaZ = targetZ - heldPosition[2];

        double distance = Math.sqrt(deltaX * deltaX + deltaY * deltaY + deltaZ * deltaZ);

        if (distance > 0.2) {
            double ratio = Math.min(teleportSpeed / distance, 0.5);
            heldPosition[0] += deltaX * ratio;
            heldPosition[1] += deltaY * ratio;
            heldPosition[2] += deltaZ * ratio;

            simulatedFallDistance += 0.015f;
        } else {
            isHoldingPackets = false;
            heldPosition = null;
        }
    }

