    public static void c03cancelfly() {
        Object player = getThePlayer();
        if (player == null)
            return;


        lastX1 = getPosX(player);
        lastY1 = getPosY(player);
        lastZ1 = getPosZ(player);

        wasFlying = true;
        double baseSpeed = getSettingValue("Fly", "Speed");

        double tps = getServerTPS();
        long ping = getPlayerPing();

        double tpsMultiplier = Math.max(0.8, tps / 20.0);
        double pingComp = 1.0 + (ping * 0.002);

        double speed = baseSpeed * tpsMultiplier * pingComp;

        float yaw = getRotationYaw();
        float yawRad = degreesToRadians(yaw);

        double motionX = 0.0;
        double motionY = 0.0;
        double motionZ = 0.0;


        if (Keyboard.isKeyDown(17)) {
            motionX += -Math.sin(yawRad) * speed;
            motionZ += Math.cos(yawRad) * speed;
        }


        if (Keyboard.isKeyDown(31)) {
            motionX += Math.sin(yawRad) * speed;
            motionZ += -Math.cos(yawRad) * speed;
        }


        if (Keyboard.isKeyDown(30)) {
            double sideYaw = yawRad - Math.PI / 2;
            motionX += -Math.sin(sideYaw) * speed;
            motionZ += Math.cos(sideYaw) * speed;
        }


        if (Keyboard.isKeyDown(32)) {
            double sideYaw = yawRad + Math.PI / 2;
            motionX += -Math.sin(sideYaw) * speed;
            motionZ += Math.cos(sideYaw) * speed;
        }


        if (Keyboard.isKeyDown(57)) {
            motionY += speed;
        }


        if (Keyboard.isKeyDown(42)) {
            motionY -= speed;
        }


        setMotionX(motionX);
        setMotionY(motionY);
        setMotionZ(motionZ);

        setFallDistance(0);

        setOnGround(true);
    }

