    public static void flymotiontest() {
        if (getThePlayer() == null)
            return;

        if (!flyInitialized) {
            flyStartTime = System.currentTimeMillis();
            lastSentY = getPosY();
            flyInitialized = true;
        }

        long currentTime = System.currentTimeMillis();
        flyTicks++;

        double tps = getServerTPS();
        long ping = getPlayerPing();
        double tpsMultiplier = Math.max(0.5, tps / 20.0);
        double pingCompensation = 1.0 + (ping / 100.0 * 0.1);

        double baseSpeed = getSettingValue("Fly", "Speed");
        double speed = baseSpeed * tpsMultiplier * pingCompensation;

        double currentPosX = getPosX();
        double currentPosY = getPosY();
        double currentPosZ = getPosZ();

        double motionX = 0;
        double motionY = 0;
        double motionZ = 0;

        setOnGround(true);
        setFallDistance(0);

        double smoothness = 0.8;
        setMotionX((getMotionX() * smoothness) + (motionX * (1.0 - smoothness)));
        setMotionY((getMotionY() * smoothness) + (motionY * (1.0 - smoothness)));
        setMotionZ((getMotionZ() * smoothness) + (motionZ * (1.0 - smoothness)));

        lastSentY = currentPosY;
    }

