    private static double approach(double cur, double target, double accel, double decel) {
        double diff = target - cur;
        if (Math.abs(diff) < 1e-6)
            return target;

        double step = (Math.abs(target) > Math.abs(cur)) ? accel : decel;
        if (diff > 0) {
            cur += Math.min(diff, step);
        } else {
            cur -= Math.min(-diff, step);
        }

        double absMax = Math.max(Math.abs(target), step * 10);
        if (cur > absMax)
            cur = absMax;
        if (cur < -absMax)
            cur = -absMax;
        return cur;
    }

    public static Field analyzeNetworkPlayerInfoField(Class<?> clazz) {
        for (Field field : clazz.getDeclaredFields()) {
            int mod = field.getModifiers();
            Object instance = getThePlayer();

            if (Modifier.isPrivate(mod)
                    && !Modifier.isStatic(mod)
                    && !Modifier.isFinal(mod)
                    && !field.getType().isPrimitive()
                    && field.getType() != String.class) {

                try {
                    field.setAccessible(true);
                    Object value = field.get(instance);

                    if (value != null) {
                        return field;
                    }

                } catch (Exception e) {
                    e.printStackTrace();
                }
            }
        }

        return null;
    }

