    public static float getDirection() {
        float yaw = getRotationYaw();
        float forward = getMoveForward();
        float strafe = getMoveStrafing();
        if (forward > 0) {
            if (strafe > 0)
                yaw += 90;
            else if (strafe < 0)
                yaw -= 90;
        } else if (forward < 0) {
            if (strafe > 0)
                yaw -= 90;
            else if (strafe < 0)
                yaw += 90;
        } else {
            if (strafe > 0)
                yaw += 90;
            else if (strafe < 0)
                yaw -= 90;
        }

        return yaw * 0.017453292f;
    }

