    public static void handleStrafe() {
        if (getThePlayer() == null || getCurrentScreen() != null)
            return;


        boolean frontTabEnabled = getSettingBoolean("Strafe", "Front Tab");
        double frontTabStrength = getSettingValue("Strafe", "Front Tab Strength");
        int hurtTime = getHurtTime();
        if (hurtTime > 0) {
            if (frontTabEnabled) {

                if (hurtTime >= 8) {
                    float yawRad = (float) Math.toRadians(getRotationYaw());
                    setMotionX(-Math.sin(yawRad) * frontTabStrength);
                    setMotionZ(Math.cos(yawRad) * frontTabStrength);
                }


            } else {

                return;
            }
        }



        if (!isMoving() && !(frontTabEnabled && hurtTime > 0)) return;

        double motionX = getMotionX();
        double motionZ = getMotionZ();
        double speed = Math.sqrt(motionX * motionX + motionZ * motionZ);
        if (speed < 0.001) return;

        float forward = getMoveForward();
        float strafe = getMoveStrafing();
        float yaw = getRotationYaw();

        if (forward < 0.0f) {
            yaw += 180.0f;
        }

        float forwardFactor = 1.0f;

        if (forward < 0.0f) {
            forwardFactor = -0.5f;
        } else if (forward > 0.0f) {
            forwardFactor = 0.5f;
        }

        if (strafe > 0.0f) {
            yaw -= 90.0f * forwardFactor;
        }

        if (strafe < 0.0f) {
            yaw += 90.0f * forwardFactor;
        }

        double direction = Math.toRadians(yaw);

        setMotionX(-Math.sin(direction) * speed);
        setMotionZ(Math.cos(direction) * speed);
    }

