    private static void addModule(String name, int bindKey, Runnable onUpdate, Runnable onEnable, Runnable onDisable,
                                  String category) {
        moduleNames.add(name);
        moduleBindKeys.add(bindKey);
        moduleEnabled.add(false);
        moduleOnUpdate.add(onUpdate);
        moduleOnEnable.add(() -> {
            onEnable.run();
            post("ENABLE", name, "Module enabled");
        });
        moduleOnDisable.add(() -> {
            onDisable.run();
            post("DISABLE", name, "Module disabled");
        });
        moduleCategories.add(category);
    }

    private static void addModule(String name, int bindKey, Runnable onUpdate, Runnable onEnable, Runnable onDisable,
                                  String category, boolean startEnabled) {
        moduleNames.add(name);
        moduleBindKeys.add(bindKey);
        moduleEnabled.add(startEnabled);
        moduleOnUpdate.add(onUpdate);
        Runnable enableTask = () -> {
            onEnable.run();
            post("ENABLE", name, "Module enabled");
        };
        moduleOnEnable.add(enableTask);
        moduleOnDisable.add(() -> {
            onDisable.run();
            post("DISABLE", name, "Module disabled");
        });
        moduleCategories.add(category);

        if (startEnabled) {
            enableTask.run();
        }
    }

    private static boolean isKeyPressedOnce(int key) {
        boolean current = Keyboard.isKeyDown(key);
        boolean last = keyStates.getOrDefault(key, false);
        keyStates.put(key, current);
        return current && !last;
    }

