    public static void dumpAllClasses() throws IOException {

        List<String> missingClasses = Files.readAllLines(Paths.get(CLASS_LIST));
        Set<String> runtimeClasses = new HashSet<>();


        for (Class<?> clazz : getClasses()) {
            runtimeClasses.add(clazz.getName());
        }

        Map<String, byte[]> classBytesMap = new HashMap<>();

        for (String className : missingClasses) {
            className = className.trim();
            if (className.isEmpty())
                continue;


            if (className.startsWith("[L") && className.endsWith(";"))
                continue;

            if (runtimeClasses.contains(className)) {
                Class<?> clazz = null;
                for (Class<?> c : getClasses()) {
                    if (c.getName().equals(className)) {
                        clazz = c;
                        break;
                    }
                }
                if (clazz != null) {
                    byte[] bytes = getClassBytes(clazz);
                    if (bytes != null) {
                        classBytesMap.put(className, bytes);
                        System.out.println("Captured: " + className);
                    } else {
                        System.out.println("Cannot get bytes: " + className);
                    }
                }
            } else {
                System.out.println("Not found in runtime: " + className);
            }
        }

        if (classBytesMap.isEmpty()) {
            System.out.println("Hiç class bulunamadı. Jar değişmedi.");
            return;
        }


        File jarFile = new File(OUTPUT_JAR);
        File tempJar = new File(OUTPUT_JAR + ".tmp");

        try (JarOutputStream jos = new JarOutputStream(new FileOutputStream(tempJar))) {


            if (jarFile.exists()) {
                try (JarFile oldJar = new JarFile(jarFile)) {
                    Enumeration<JarEntry> entries = oldJar.entries();
                    while (entries.hasMoreElements()) {
                        JarEntry entry = entries.nextElement();
                        if (classBytesMap.containsKey(entry.getName().replace("/", ".").replace(".class", ""))) {
                            continue;
                        }
                        jos.putNextEntry(new JarEntry(entry.getName()));
                        copyStream(oldJar.getInputStream(entry), jos);
                        jos.closeEntry();
                    }
                }

            }


            for (Map.Entry<String, byte[]> entry : classBytesMap.entrySet()) {
                String path = entry.getKey().replace(".", "/") + ".class";
                jos.putNextEntry(new JarEntry(path));
                jos.write(entry.getValue());
                jos.closeEntry();
            }
        }

        Files.move(tempJar.toPath(), jarFile.toPath(), StandardCopyOption.REPLACE_EXISTING);
        System.out.println("Eksik class'lar output.jar'a eklendi: " + classBytesMap.size());
    }

    static final String CLASS_LIST = "C:\\pulse\\sinif.txt";
    static final String OUTPUT_JAR = "C:\\pulse\\output.jar";

    private static void copyStream(InputStream in, OutputStream out) throws IOException {
        byte[] buffer = new byte[8192];
        int read;
        while ((read = in.read(buffer)) != -1) {
            out.write(buffer, 0, read);
        }
    }

