    public static boolean isPlayerEating() {

        if (isAutoGappling) return true;




        try {
            Object player = getPlayer();
            if (player != null) {
                Class<?> itemStackClass = get("ItemStack");
                if (itemStackClass != null) {
                    Method heldMethod = getMethod("EntityPlayer.getHeldItem");
                    String heldName = (heldMethod != null) ? heldMethod.getName() : "";

                    for (Method m : player.getClass().getMethods()) {
                        if (m.getParameterCount() != 0) continue;
                        if (!m.getReturnType().equals(itemStackClass)) continue;

                        if (m.getName().equals(heldName)) continue;
                        m.setAccessible(true);
                        Object itemInUse = m.invoke(player);

                        if (itemInUse != null) return true;

                        break;
                    }
                }
            }
        } catch (Exception ignored) {}


        try {
            if (Mouse.isButtonDown(1)) {
                Object heldItem = getHeldItem();
                if (heldItem != null) {
                    String name = heldItem.toString().toLowerCase();
                    if (name.contains("apple")   || name.contains("bread")    ||
                            name.contains("beef")    || name.contains("pork")     ||
                            name.contains("chicken") || name.contains("fish")     ||
                            name.contains("carrot")  || name.contains("potato")   ||
                            name.contains("melon")   || name.contains("cookie")   ||
                            name.contains("steak")   || name.contains("mutton")   ||
                            name.contains("rabbit")  || name.contains("mushroom") ||
                            name.contains("soup")    || name.contains("cake")) {
                        return true;
                    }
                }
            }
        } catch (Exception ignored) {}

        return false;
    }

