    private static Map<Object, float[]> lastRotations = new HashMap<>();

    private static boolean hasPerfectAim(Object entity) {
        if (entity == null)
            return false;

        float currentYaw = getRotationYaw(entity);
        float currentPitch = getRotationPitch(entity);

        float[] prevRot = lastRotations.get(entity);
        if (prevRot == null) {
            lastRotations.put(entity, new float[] { currentYaw, currentPitch });
            return false;
        }

        float yawDiff = Math.abs(currentYaw - prevRot[0]);
        float pitchDiff = Math.abs(currentPitch - prevRot[1]);

        boolean perfectYaw = yawDiff > 0.01f && yawDiff < 0.001f;
        boolean perfectPitch = pitchDiff > 0.01f && pitchDiff < 0.001f;

        lastRotations.put(entity, new float[] { currentYaw, currentPitch });
        return perfectYaw && perfectPitch;
    }

    private static final Map<Object, Float> lastYawMap = new WeakHashMap<>();
    private static final Map<Object, Float> lastPitchMap = new WeakHashMap<>();

    private static float getEntityYawChange(Object player) {
        if (player == null)
            return 0f;
        try {
            float currentYaw = getRotationYaw(player);
            float previousYaw = lastYawMap.getOrDefault(player, currentYaw);
            float yawChange = currentYaw - previousYaw;

            while (yawChange > 180f)
                yawChange -= 360f;
            while (yawChange < -180f)
                yawChange += 360f;

            lastYawMap.put(player, currentYaw);
            return yawChange;
        } catch (Exception e) {
            return 0f;
        }
    }

    private static float getEntityPitchChange(Object player) {
        if (player == null)
            return 0f;
        try {
            float currentPitch = getRotationPitch(player);
            float previousPitch = lastPitchMap.getOrDefault(player, currentPitch);
            float pitchChange = currentPitch - previousPitch;

            while (pitchChange > 180f)
                pitchChange -= 360f;
            while (pitchChange < -180f)
                pitchChange += 360f;

            lastPitchMap.put(player, currentPitch);
            return pitchChange;
        } catch (Exception e) {
            return 0f;
        }
    }

