    public static void writeVarIntToBuffer(Object packetBuffer, int input) {
        while ((input & -128) != 0) {
            writeByte(packetBuffer, input & 127 | 128);
            input >>>= 7;
        }

        writeByte(packetBuffer, input);
    }

