    public static void writeVarIntToByteBuf(ByteBuf buf, int value) {
        while (true) {
            if ((value & ~0x7F) == 0) {
                buf.writeByte(value);
                return;
            } else {
                buf.writeByte((value & 0x7F) | 0x80);
                value >>>= 7;
            }
        }
    }

    public static void writeEnumValueToByteBuf(ByteBuf buf, Enum<?> e) {
        buf.writeByte(e.ordinal());
    }

    private static final SecureRandom RANDOMvvv = new SecureRandom();
    private static final String CHARACTERS = "abcdefgkjlsdljfweLKSJDFJWRNBNWRKj";

    public static String generateRandomString(int length) {
        StringBuilder sb = new StringBuilder(length);

        for (int i = 0; i < length; i++) {
            int randomIndex = RANDOMvvv.nextInt(CHARACTERS.length());
            sb.append(CHARACTERS.charAt(randomIndex));
        }

        return sb.toString();
    }

    public static void sendChatMessage(String message) {
        try {
            Channel channel = getChannel();
            ByteBuf buf = Unpooled.buffer();
            buf.writeByte(1);
            writeStringToByteBuf(buf, message);
            channel.writeAndFlush(buf);
        } catch (Exception e) {
            e.printStackTrace();
        }
    }

    public static void writeStringToByteBuf(ByteBuf buf, String str) {
        byte[] bytes = str.getBytes(StandardCharsets.UTF_8);
        writeVarIntToByteBuf(buf, bytes.length);
        buf.writeBytes(bytes);
    }

    public static void attackEntity(Object entity) {
        try {
            Object inventory = getInventory();
            Field currentItemField = getField("InventoryPlayer.currentItem");
            int oldSlot = -1;
            int swordSlot = -1;
            boolean autoSword = isModuleEnabled("AutoSword");

            if (autoSword && inventory != null && currentItemField != null) {
                currentItemField.setAccessible(true);
                oldSlot = currentItemField.getInt(inventory);
                swordSlot = findSwordSlot();
            }

            boolean doSwitch = autoSword && swordSlot != -1 && swordSlot != oldSlot;

            if (doSwitch) {

                currentItemField.setInt(inventory, swordSlot);
                syncCurrentPlayItem();
            }


            Channel channel = getChannel();
            ByteBuf buf = Unpooled.buffer();
            buf.writeByte(2);
            writeVarIntToByteBuf(buf, getId(entity));
            Class<?> actionClass = get("C02PacketUseEntityAction");
            Enum<?> attackEnum = Enum.valueOf((Class<Enum>) actionClass, "ATTACK");
            writeEnumValueToByteBuf(buf, attackEnum);
            buf.writeFloat(1.65f);
            channel.writeAndFlush(buf);

            if (autoSword) {



                if (!isPlayerEating()) {
                    Object swordStack = null;
                    if (inventory != null) {
                        Field mainInventoryField = getField("InventoryPlayer.mainInventory");
                        if (mainInventoryField != null) {
                            mainInventoryField.setAccessible(true);
                            Object[] main = (Object[]) mainInventoryField.get(inventory);
                            int slot = (swordSlot != -1) ? swordSlot : oldSlot;
                            if (slot >= 0 && slot < main.length) swordStack = main[slot];
                        }
                    }
                    if (swordStack != null) {
                        Object c08 = createC08(swordStack);
                        if (c08 != null) sendPacket(c08);
                    }
                }
            }

            if (doSwitch) {

                currentItemField.setInt(inventory, oldSlot);
                syncCurrentPlayItem();
            }
        } catch (Exception e) {
            e.printStackTrace();
        }
    }

    private static int findSwordSlot() {
        try {
            Object inventory = getInventory();
            if (inventory == null)
                return -1;
            Field mainInventoryField = getField("InventoryPlayer.mainInventory");
            mainInventoryField.setAccessible(true);
            Object[] main = (Object[]) mainInventoryField.get(inventory);
            for (int i = 0; i < 9; i++) {
                Object stack = main[i];
                if (stack == null)
                    continue;
                String name = stack.toString().toLowerCase();
                if (name.contains("sword"))
                    return i;
            }
        } catch (Exception ignored) {
        }
        return -1;
    }

