    public static Object createC07(Object blockPos, int facingInt, String actionName) {
        try {
            Class<?> c07Class = get("C07PacketPlayerDigging");
            if (c07Class == null) return null;
            Class<?> actionEnum = get("C07PacketPlayerDigging.Action");
            if (actionEnum == null) return null;
            Class<?> enumFacingClass = get("EnumFacing");
            if (enumFacingClass == null) return null;

            Object action = null;
            for (Object constant : actionEnum.getEnumConstants()) {
                if (constant.toString().equalsIgnoreCase(actionName)) {
                    action = constant;
                    break;
                }
            }
            if (action == null) return null;

            Object[] facingValues = enumFacingClass.getEnumConstants();
            Object facing = facingValues[facingInt < facingValues.length ? facingInt : 0];


            Constructor<?> ctor = c07Class.getDeclaredConstructor(
                    actionEnum,
                    blockPos.getClass(),
                    enumFacingClass);
            ctor.setAccessible(true);
            return ctor.newInstance(action, blockPos, facing);
        } catch (Exception e) {
            e.printStackTrace();
            return null;
        }
    }

