    public static Object createC02(Object entity) {
        try {
            if (entity == null)
                return null;

            int entityId = getId(entity);
            if (entityId == -1)
                return null;

            Object c02PacketUseEntityClass = get("C02PacketUseEntity");
            Object c02PacketUseEntityActionClass = get("C02PacketUseEntityAction");

            if (c02PacketUseEntityClass == null || c02PacketUseEntityActionClass == null) {
                return null;
            }

            Object c02Instance = ((Class<?>) c02PacketUseEntityClass).getDeclaredConstructor().newInstance();

            Field attackEnumField = ((Class<?>) c02PacketUseEntityActionClass).getField("ATTACK");
            attackEnumField.setAccessible(true);
            Object attackEnumValue = attackEnumField.get(null);

            Field entityIdField = findPrivateIntField((Class<?>) c02PacketUseEntityClass);
            Field entityActionField = getFieldByType((Class<?>) c02PacketUseEntityClass,
                    (Class<?>) c02PacketUseEntityActionClass);

            entityIdField.setAccessible(true);
            entityActionField.setAccessible(true);

            entityIdField.set(c02Instance, entityId);
            entityActionField.set(c02Instance, attackEnumValue);

            return c02Instance;

        } catch (Exception e) {
            return null;
        }
    }

