    private static float fakeYaw = 0;
    private static float fakePitch = 0;
    private static boolean pitchIncreasing = true;

    public static void setPosition(Object player, double x, double y, double z) {
        try {
            Method setPositionAndRotation = getMethod("Entity.setPositionAndRotation");
            if (player != null && setPositionAndRotation != null) {
                setPositionAndRotation.setAccessible(true);

                fakeYaw += 10;
                if (fakeYaw >= 360)
                    fakeYaw -= 360;

                if (pitchIncreasing) {
                    fakePitch += 5;
                    if (fakePitch >= 45)
                        pitchIncreasing = false;
                } else {
                    fakePitch -= 5;
                    if (fakePitch <= -45)
                        pitchIncreasing = true;
                }

                setPositionAndRotation.invoke(player, x, y, z, fakeYaw, fakePitch);
            }
        } catch (Exception e) {
        }
    }

