    public static void addChatMessage(String val, Boolean prefix) {
        try {
            Class<?> chatComponentTextClass = get("ChatComponentText");
            Method addChatMessageMethod = getMethod("EntityPlayerSP.addChatMessage");

            Constructor<?> constructor = chatComponentTextClass.getConstructor(String.class);
            String message;

            if (prefix) {

                message = GRAY + "[" +
                        WHITE + "Aether+" +
                        RESET + "" + GRAY + "]" +
                        WHITE + " " + val;
            } else {
                message = WHITE + val;
            }

            Object chatComponent = constructor.newInstance(message);
            Object thePlayer = getMethod("Minecraft.getThePlayer").invoke(getField("Minecraft.theMinecraft").get(null));

            addChatMessageMethod.invoke(thePlayer, chatComponent);

        } catch (Exception e) {
            e.printStackTrace();
        }
    }

