    public static void onRender3D(float partialTick) {
        if (started) {
            if (getPlayer() == null)
                return;

            if (isModuleEnabled("Xray")) {
                try {
                    xrayRun();
                } catch (Exception e) {
                    e.printStackTrace();
                }
            }
            if (isModuleEnabled("PenisESP")) {
                espon3d();
            }
            if (isModuleEnabled("AuraESP")) {
                drawAuraESP();
            }

            if (closestTarget != null) {
                updateTargetCenter(closestTarget);
            }

            if (isModuleEnabled("ChinaHat")) {
                chinahat();
            }
            if (isModuleEnabled("Chams")) {
                chamsRenderer();
            }
            if (isModuleEnabled("ESP")) {
                String espMode = getMode("ESP", "ModeSetting");
                if ("2D".equals(espMode)) {
                    espOn3D();
                } else if ("3D".equals(espMode)) {
                    espOn3DD();
                }
            }
            if (isModuleEnabled("NameTag")) {
                espOn3D();
            }

            if (closestTarget != null) {
                faceEntityClientSideYawOnly(closestTarget);
            } else if (isModuleEnabled("AntiAim")) {
                mevlana();
            } else {
                setRotationPitchHead(getRotationPitch());
            }

            if (isModuleEnabled("BreadCrumbs")) {
                renderBreadCrumbs();
            }

            if (isModuleEnabled("Schematic") || !schematicBlocks.isEmpty()) {
                renderSchematicOverlay();
            }
        }
    }

    public static void faceEntityClientSideYawOnly(Object target) {
        double diffX = getPosX(target) - getPosX(getThePlayer());
        double diffZ = getPosZ(target) - getPosZ(getThePlayer());
        double diffY = (getPosY(target) + getEyeHeight(target))
                - (getPosY(getThePlayer()) + getEyeHeight(getThePlayer()));

        double distXZ = Math.sqrt(diffX * diffX + diffZ * diffZ);

        float yaw = (float) Math.toDegrees(Math.atan2(diffZ, diffX)) - 90F;

        float pitch = (float) -Math.toDegrees(Math.atan2(diffY, distXZ));

        pitch = Math.max(-90, Math.min(90, pitch));

        setRenderYawOffset(yaw);
        setRotationYawHead(yaw);
        setRotationPitchHead(pitch);
    }

