    public static int[] getLookedBlock(Object player, Object world) {
        double px = getPosX(player);
        double py = getPosY(player) + 1.62;
        double pz = getPosZ(player);

        double[] look = getLookVec(getRotationYaw(), getRotationPitch());

        for (double i = 0; i < 50; i += 0.2) {
            int bx = (int) Math.floor(px + look[0] * i);
            int by = (int) Math.floor(py + look[1] * i);
            int bz = (int) Math.floor(pz + look[2] * i);

            try {
                Object block = getMethod("World.getBlock").invoke(world, bx, by, bz);
                int id = (int) getMethod("Block.getIdFromBlock").invoke(null, block);

                if (id != 0)
                    return new int[] { bx, by, bz, id };

            } catch (Exception ignored) {
            }
        }
        return null;
    }

    public static double[] getLookVec(float yaw, float pitch) {
        float yawRad = (float) Math.toRadians(-yaw - 180F);
        float pitchRad = (float) Math.toRadians(-pitch);

        return new double[] {
                Math.sin(yawRad) * Math.cos(pitchRad),
                Math.sin(pitchRad),
                Math.cos(yawRad) * Math.cos(pitchRad)
        };
    }

