    public static void mapGetHealth() {
        try {

            Class<?> clazz = get("EntityLivingBase");
            if (clazz == null) {
                System.out.println("[mapGetHealth] EntityLivingBase bulunamadı!");
                return;
            }

            byte[] bytes = getClassBytes(clazz);
            if (bytes == null) {
                System.out.println("[mapGetHealth] class bytes NULL!");
                return;
            }

            ClassReader cr = new ClassReader(bytes);
            ClassNode cn = new ClassNode();
            cr.accept(cn, 0);

            MethodNode target = null;

            for (MethodNode mn : cn.methods) {
                InsnList insns = mn.instructions;
                if (insns.size() < 6)
                    continue;

                try {
                    AbstractInsnNode i0 = insns.get(0);
                    AbstractInsnNode i1 = insns.get(1);
                    AbstractInsnNode i2 = insns.get(2);
                    AbstractInsnNode i3 = insns.get(3);
                    AbstractInsnNode i4 = insns.get(4);
                    AbstractInsnNode i5 = insns.get(5);

                    if (i0.getOpcode() == 25 &&
                            i1.getOpcode() == 180 &&
                            i2.getOpcode() == 178 &&
                            i3.getOpcode() == 182 &&
                            i4.getOpcode() == 182 &&
                            i5.getOpcode() == 174) {

                        target = mn;

                        break;
                    }
                } catch (Exception ignored) {
                }
            }

            if (target == null) {

                return;
            }

            for (AbstractInsnNode ins : target.instructions) {

            }

            Method real = clazz.getDeclaredMethod(target.name);
            real.setAccessible(true);

            putMethod("EntityLivingBase.getHealth", real);

        } catch (Throwable t) {
            t.printStackTrace();
        }
    }

