    public static float[] getChinaHatOffset(Object player) {
        if (player == null)
            return new float[] { 0f, 0f, 0f };

        float partialTicks = getRenderPartialTicks();

        double px = getPrevPosX(player) + (getPosX(player) - getPrevPosX(player)) * partialTicks;
        double py = getPrevPosY(player) + (getPosY(player) - getPrevPosY(player)) * partialTicks + getEyeHeight(player)
                + 0.18;
        double pz = getPrevPosZ(player) + (getPosZ(player) - getPrevPosZ(player)) * partialTicks;

        Object viewer = getThePlayer();
        double camX = getPrevPosX(viewer) + (getPosX(viewer) - getPrevPosX(viewer)) * partialTicks;
        double camY = getPrevPosY(viewer) + (getPosY(viewer) - getPrevPosY(viewer)) * partialTicks;
        double camZ = getPrevPosZ(viewer) + (getPosZ(viewer) - getPrevPosZ(viewer)) * partialTicks;

        double x = px - camX;
        double y = py - camY;
        double z = pz - camZ;

        return new float[] { (float) x, (float) y, (float) z };
    }

    public static int getRainbow(float seconds, float saturation, float brightness, float indexOffset) {
        if (seconds <= 0f)
            seconds = 5f;

        float t = (System.currentTimeMillis() % (int) (seconds * 1000L)) / (seconds * 1000f);
        float hue = t + indexOffset;
        hue = hue - (float) Math.floor(hue);
        saturation = Math.max(0f, Math.min(1f, saturation));
        brightness = Math.max(0f, Math.min(1f, brightness));

        int rgb = java.awt.Color.HSBtoRGB(hue, saturation, brightness);
        return rgb;
    }

    public static Field findWindowID(Class<?> clazz) throws Exception {
        byte[] bytes = getClassBytes(clazz);

        ClassReader cr = new ClassReader(bytes);
        ClassNode cn = new ClassNode();
        cr.accept(cn, 0);

        Set<String> initializedInCtor = new HashSet<>();
        for (MethodNode mn : cn.methods) {
            if ("<init>".equals(mn.name)) {
                for (AbstractInsnNode insn : mn.instructions) {
                    if (insn.getOpcode() == PUTFIELD) {
                        FieldInsnNode fin = (FieldInsnNode) insn;
                        if ("I".equals(fin.desc)) {
                            initializedInCtor.add(fin.name);
                        }
                    }
                }
            }
        }

        for (FieldNode fn : cn.fields) {
            boolean isPublic = (fn.access & Opcodes.ACC_PUBLIC) != 0;
            boolean isInt = "I".equals(fn.desc);
            boolean hasConstantValue = fn.value != null;

            if (isPublic && isInt && !hasConstantValue && !initializedInCtor.contains(fn.name)) {
                Field f = clazz.getDeclaredField(fn.name);
                f.setAccessible(true);
                return f;
            }
        }

        return null;
    }

