    public static void scanCurrentChunk() {
        try {
            Object world = getWorldObj();
            Object player = getThePlayer();
            if (world == null || player == null)
                return;

            int cx = (int) Math.floor(getPosX(player)) >> 4;
            int cz = (int) Math.floor(getPosZ(player)) >> 4;

            Object chunk = getChunkFromChunkCoords(world, cx, cz);
            if (chunk == null)
                return;

            System.out.println("Scanning chunk: [" + cx + "," + cz + "]");

            for (int x = 0; x < 16; x++) {
                for (int z = 0; z < 16; z++) {
                    for (int y = 0; y < 256; y++) {
                        Object block = getBlock(chunk, x, y, z);
                        if (block == null)
                            continue;

                        String blockName = block.toString().toLowerCase();

                        if (blockName.contains("air"))
                            continue;
                        if (blockName.contains("minecraft:air"))
                            continue;

                        int worldX = (cx << 4) + x;
                        int worldZ = (cz << 4) + z;
                        System.out.println("X: " + worldX + " Y: " + y + " Z: " + worldZ + " Block: " + blockName);
                    }
                }
            }
        } catch (Exception e) {
            e.printStackTrace();
        }
    }

