    public static void rotateTo(double x, double y, double z) {
        double dx = x - getPosX();
        double dz = z - getPosZ();
        double dy = y - (getPosY() + 1.62);
        double distXZ = Math.sqrt(dx * dx + dz * dz);

        float yaw = (float) Math.toDegrees(Math.atan2(dz, dx)) - 90f;
        float pitch = (float) (-Math.toDegrees(Math.atan2(dy, distXZ)));
        setRotationYawAndPitch(yaw, pitch);
    }

    public static float[] getRotationsToBlock(double x, double y, double z, double eyeHeight) {
        double dx = x - getPosX();
        double dy = y - (getPosY() + eyeHeight);
        double dz = z - getPosZ();
        double dist = Math.sqrt(dx * dx + dz * dz);
        float yaw = (float) Math.toDegrees(Math.atan2(dz, dx)) - 90.0f;
        float pitch = (float) -Math.toDegrees(Math.atan2(dy, dist));
        return new float[] { yaw, pitch };
    }

    public static Method findMethodFromParam(Class<?> clazz, Class<?>[] paramTypes) {
        for (Method method : clazz.getDeclaredMethods()) {
            Class<?>[] params = method.getParameterTypes();
            if (params.length != paramTypes.length)
                continue;

            boolean match = true;
            for (int i = 0; i < params.length; i++) {
                if (params[i] != paramTypes[i]) {
                    match = false;
                    break;
                }
            }
            if (match) {
                return method;
            }
        }
        return null;
    }

