    public static void analyzePFieldUsage() {
        try {
            System.out.println("=== COMPREHENSIVE P FIELD USAGE ANALYSIS ===");

            Class<?> entityClass = get("Entity");
            if (entityClass == null)
                return;

            byte[] entityBytes = getClassBytes(entityClass);
            if (entityBytes == null)
                return;

            ClassNode entityNode = new ClassNode();
            ClassReader entityReader = new ClassReader(entityBytes);
            entityReader.accept(entityNode, ClassReader.SKIP_DEBUG);

            FieldNode pField = null;
            for (FieldNode field : entityNode.fields) {
                if (field.name.equals("P") && field.desc.equals("I")) {
                    pField = field;
                    break;
                }
            }

            if (pField == null) {
                return;
            }

            analyzeClassForPFieldUsage(entityNode, "Entity");

            String[] importantClasses = {
                    "EntityLivingBase", "EntityPlayer", "World", "EntityAnimal",
                    "EntityMob", "EntityItem", "EntityArrow", "EntityXPOrb"
            };

            for (String className : importantClasses) {
                Class<?> targetClass = get(className);
                if (targetClass != null) {
                    byte[] classBytes = getClassBytes(targetClass);
                    if (classBytes != null) {
                        ClassNode classNode = new ClassNode();
                        ClassReader classReader = new ClassReader(classBytes);
                        classReader.accept(classNode, ClassReader.SKIP_DEBUG);

                        analyzeClassForPFieldUsage(classNode, className);
                    }
                }
            }

            analyzeWorldForPFieldIncrement();

        } catch (Exception e) {
            e.printStackTrace();
        }
    }

    private static void analyzeClassForPFieldUsage(ClassNode classNode, String className) {
        int totalReferences = 0;
        int getFieldCount = 0;
        int putFieldCount = 0;

        Map<String, List<String>> methodUsage = new HashMap<>();

        for (MethodNode method : classNode.methods) {
            List<String> methodReferences = new ArrayList<>();
            int methodInstructionIndex = 0;

            for (AbstractInsnNode insn : method.instructions) {
                methodInstructionIndex++;

                if (insn instanceof FieldInsnNode) {
                    FieldInsnNode fieldInsn = (FieldInsnNode) insn;
                    if (fieldInsn.name.equals("P") && fieldInsn.desc.equals("I")) {
                        totalReferences++;

                        String opcodeName = getOpcodeName(fieldInsn.getOpcode());
                        String referenceInfo = String.format("Insn %d: %s (owner: %s)",
                                methodInstructionIndex, opcodeName, fieldInsn.owner);

                        StringBuilder context = new StringBuilder();
                        context.append("Context: ");

                        AbstractInsnNode prev = insn.getPrevious();
                        for (int i = 0; i < 3 && prev != null; i++) {
                            context.append(getInsnDescription(prev)).append(" <- ");
                            prev = prev.getPrevious();
                        }

                        context.append("[").append(opcodeName).append(" P]");

                        AbstractInsnNode next = insn.getNext();
                        for (int i = 0; i < 3 && next != null; i++) {
                            context.append(" -> ").append(getInsnDescription(next));
                            next = next.getNext();
                        }

                        referenceInfo += " | " + context.toString();

                        methodReferences.add(referenceInfo);

                        if (fieldInsn.getOpcode() == Opcodes.GETFIELD) {
                            getFieldCount++;
                        } else if (fieldInsn.getOpcode() == PUTFIELD) {
                            putFieldCount++;
                        }
                    }
                }

                if (insn.getOpcode() == Opcodes.IINC) {
                    IincInsnNode iincInsn = (IincInsnNode) insn;

                    AbstractInsnNode prev = insn.getPrevious();
                    int checkCount = 0;
                    while (prev != null && checkCount < 5) {
                        if (prev instanceof FieldInsnNode) {
                            FieldInsnNode fieldInsn = (FieldInsnNode) prev;
                            if (fieldInsn.name.equals("P") && fieldInsn.desc.equals("I") &&
                                    fieldInsn.getOpcode() == Opcodes.GETFIELD) {

                                String referenceInfo = String.format("Insn %d: IINC (var: %d, incr: %d) on P field",
                                        methodInstructionIndex, iincInsn.var, iincInsn.incr);
                                methodReferences.add(referenceInfo);
                                totalReferences++;
                                break;
                            }
                        }
                        prev = prev.getPrevious();
                        checkCount++;
                    }
                }
            }

            if (!methodReferences.isEmpty()) {
                methodUsage.put(method.name + method.desc, methodReferences);
            }
        }

        for (Map.Entry<String, List<String>> entry : methodUsage.entrySet()) {
            for (String reference : entry.getValue()) {
            }
        }

        if (totalReferences == 0) {
        }
    }

    private static void analyzeWorldForPFieldIncrement() {
        try {

            Class<?> worldClass = get("World");
            if (worldClass == null)
                return;

            byte[] worldBytes = getClassBytes(worldClass);
            if (worldBytes == null)
                return;

            ClassNode worldNode = new ClassNode();
            ClassReader worldReader = new ClassReader(worldBytes);
            worldReader.accept(worldNode, ClassReader.SKIP_DEBUG);

            int incrementPatterns = 0;

            for (MethodNode method : worldNode.methods) {

                Iterator<AbstractInsnNode> iterator = method.instructions.iterator();
                while (iterator.hasNext()) {
                    AbstractInsnNode insn = iterator.next();

                    if (insn instanceof FieldInsnNode) {
                        FieldInsnNode fieldInsn = (FieldInsnNode) insn;
                        if (fieldInsn.name.equals("P") && fieldInsn.desc.equals("I") &&
                                fieldInsn.getOpcode() == PUTFIELD) {

                            AbstractInsnNode current = insn.getPrevious();
                            for (int i = 0; i < 10 && current != null; i++) {

                                if (current.getOpcode() == Opcodes.IADD) {
                                    incrementPatterns++;
                                } else if (current.getOpcode() == Opcodes.IINC) {
                                    incrementPatterns++;
                                } else if (current.getOpcode() == Opcodes.ICONST_1) {
                                }

                                current = current.getPrevious();
                            }

                            AbstractInsnNode next = insn.getNext();
                            for (int i = 0; i < 5 && next != null; i++) {
                                next = next.getNext();
                            }
                        }
                    }
                }
            }

        } catch (Exception e) {
        }
    }

    private static String getInsnDescription(AbstractInsnNode insn) {
        if (insn == null)
            return "null";

        if (insn instanceof FieldInsnNode) {
            FieldInsnNode field = (FieldInsnNode) insn;
            return getOpcodeName(insn.getOpcode()) + " " + field.owner + "." + field.name + ":" + field.desc;
        } else if (insn instanceof MethodInsnNode) {
            MethodInsnNode method = (MethodInsnNode) insn;
            return getOpcodeName(insn.getOpcode()) + " " + method.owner + "." + method.name + method.desc;
        } else if (insn instanceof VarInsnNode) {
            VarInsnNode var = (VarInsnNode) insn;
            return getOpcodeName(insn.getOpcode()) + " var" + var.var;
        } else if (insn instanceof LdcInsnNode) {
            LdcInsnNode ldc = (LdcInsnNode) insn;
            return "LDC " + ldc.cst;
        } else if (insn instanceof IntInsnNode) {
            IntInsnNode intInsn = (IntInsnNode) insn;
            return getOpcodeName(insn.getOpcode()) + " " + intInsn.operand;
        } else if (insn instanceof IincInsnNode) {
            IincInsnNode iinc = (IincInsnNode) insn;
            return "IINC var" + iinc.var + " by " + iinc.incr;
        } else {
            return getOpcodeName(insn.getOpcode());
        }
    }

