    private static void setRotationAngles(float f11) {
        if (wing == null || wingTip == null)
            return;

        try {

            float wingX = -1.4F - (float) Math.cos(f11) * 0.2F;
            float wingY = 0.35F + (float) Math.sin(f11) * 0.4F;
            float wingZ = 0.35F;

            float wingTipZ = -(float) (Math.sin(f11 + 2.0F) + 0.5) * 0.75F;

            Class<?> mrClass = wing.getClass();
            Field rotateAngleX = mrClass.getDeclaredField("rotateAngleX");
            Field rotateAngleY = mrClass.getDeclaredField("rotateAngleY");
            Field rotateAngleZ = mrClass.getDeclaredField("rotateAngleZ");
            Field wingTipRotateAngleZ = mrClass.getDeclaredField("rotateAngleZ");

            rotateAngleX.setAccessible(true);
            rotateAngleY.setAccessible(true);
            rotateAngleZ.setAccessible(true);
            wingTipRotateAngleZ.setAccessible(true);

            rotateAngleX.setFloat(wing, wingX);
            rotateAngleY.setFloat(wing, wingY);
            rotateAngleZ.setFloat(wing, wingZ);
            wingTipRotateAngleZ.setFloat(wingTip, wingTipZ);

        } catch (Exception e) {
            e.printStackTrace();
        }
    }

