    private static final Int2ObjectOpenHashMap<int[]> charData = new Int2ObjectOpenHashMap<>();
    private static int textureID;
    private static int fontHeight;
    private static Font font;

    public static void startFont() {
        try {
            font = Font.createFont(Font.TRUETYPE_FONT, new FileInputStream("C:/pulse/poppins.ttf"))
                    .deriveFont(Font.PLAIN, 17);
        } catch (Exception e) {
            font = new Font("Arial", Font.PLAIN, 21);
        }

        BufferedImage image = new BufferedImage(512, 512, BufferedImage.TYPE_INT_ARGB);
        Graphics2D g = image.createGraphics();
        g.setFont(font);
        g.setRenderingHint(RenderingHints.KEY_ANTIALIASING, RenderingHints.VALUE_ANTIALIAS_ON);
        g.setRenderingHint(RenderingHints.KEY_TEXT_ANTIALIASING, RenderingHints.VALUE_TEXT_ANTIALIAS_ON);
        FontMetrics metrics = g.getFontMetrics();
        fontHeight = metrics.getHeight();

        int x = 4, y = 4;
        for (char c = 0; c < 256; c++) {
            int w = metrics.charWidth(c);
            int h = fontHeight;

            if (x + w + 8 >= 512) {
                x = 4;
                y += h + 8;
            }

            g.setColor(new Color(0, 0, 0, 0));
            g.fillRect(x, y, w, h);

            g.setColor(Color.WHITE);
            g.drawString(String.valueOf(c), x, y + metrics.getAscent());

            charData.put(c, new int[] { x, y, w, h });
            x += w + 8;
        }

        g.dispose();

        int[] pixels = new int[512 * 512];
        image.getRGB(0, 0, 512, 512, pixels, 0, 512);

        ByteBuffer buffer = BufferUtils.createByteBuffer(512 * 512 * 4);
        for (int pixel : pixels) {
            buffer.put((byte) ((pixel >> 16) & 0xFF));
            buffer.put((byte) ((pixel >> 8) & 0xFF));
            buffer.put((byte) (pixel & 0xFF));
            buffer.put((byte) ((pixel >> 24) & 0xFF));
        }
        buffer.flip();

        textureID = GL11.glGenTextures();
        GL11.glBindTexture(GL11.GL_TEXTURE_2D, textureID);
        GL11.glTexParameteri(GL11.GL_TEXTURE_2D, GL11.GL_TEXTURE_MIN_FILTER, GL11.GL_LINEAR);
        GL11.glTexParameteri(GL11.GL_TEXTURE_2D, GL11.GL_TEXTURE_MAG_FILTER, GL11.GL_LINEAR);
        GL11.glTexImage2D(GL11.GL_TEXTURE_2D, 0, GL11.GL_RGBA, 512, 512, 0, GL11.GL_RGBA, GL11.GL_UNSIGNED_BYTE,
                buffer);
    }

    public static void drawString(String string, int xpos, int ypos) {
        for (int i = 0; i < string.length(); i++) {
            String s = String.valueOf(string.charAt(i));
            int color = getRiceColor(i);
            drawString(s, xpos, ypos, color);
            xpos += getStringWidthCustomFont(s);
        }
    }

    public static void drawString(String text, float x, float y, int color) {
        if (text == null || textureID == 0)
            return;

        GL11.glPushMatrix();
        GL11.glPushAttrib(GL11.GL_COLOR_BUFFER_BIT);

        GL11.glEnable(GL11.GL_BLEND);
        GL11.glBlendFunc(GL11.GL_SRC_ALPHA, GL11.GL_ONE_MINUS_SRC_ALPHA);
        GL11.glEnable(GL11.GL_TEXTURE_2D);
        GL11.glBindTexture(GL11.GL_TEXTURE_2D, textureID);

        float red = (color >> 16 & 255) / 255.0f;
        float green = (color >> 8 & 255) / 255.0f;
        float blue = (color & 255) / 255.0f;
        float alpha = (color >> 24 & 255) / 255.0f;
        GL11.glColor4f(red, green, blue, alpha);

        GL11.glScalef(0.5f, 0.5f, 1f);
        x *= 2;
        y *= 2;

        for (char ch : text.toCharArray()) {
            int[] data = charData.get(ch);
            if (data == null)
                continue;

            float tx = data[0] / 512f;
            float ty = data[1] / 512f;
            float tw = data[2] / 512f;
            float th = data[3] / 512f;

            GL11.glBegin(GL11.GL_QUADS);
            GL11.glTexCoord2f(tx, ty);
            GL11.glVertex2f(x, y);
            GL11.glTexCoord2f(tx, ty + th);
            GL11.glVertex2f(x, y + data[3]);
            GL11.glTexCoord2f(tx + tw, ty + th);
            GL11.glVertex2f(x + data[2], y + data[3]);
            GL11.glTexCoord2f(tx + tw, ty);
            GL11.glVertex2f(x + data[2], y);
            GL11.glEnd();

            x += data[2];
        }

        GL11.glPopAttrib();
        GL11.glPopMatrix();

        int error = GL11.glGetError();
        if (error != GL11.GL_NO_ERROR) {
            System.err.println("OpenGL Hatası (drawString): " + error);
        }
    }

    public static int getStringWidthCustomFont(String text) {
        if (text == null)
            return 0;
        int width = 0;
        for (char ch : text.toCharArray()) {
            int[] data = charData.get(ch);
            if (data != null)
                width += data[2];
        }
        return width / 2;
    }

