    @Override
    public void keyPressed(KeyEvent e) {
        if (currentKeyLabel == null || currentIndex == -1)
            return;

        int keyCode = e.getKeyCode();

        if (keyCode == KeyEvent.VK_ESCAPE || keyCode == KeyEvent.VK_0) {
            moduleBindKeys.set(currentIndex, Keyboard.KEY_NONE);
            currentKeyLabel.setText("Current Key: NONE");
        } else {
            moduleBindKeys.set(currentIndex, keyCode);
            currentKeyLabel.setText("Current Key: " + KeyEvent.getKeyText(keyCode));
        }

        currentKeyLabel = null;
        currentIndex = -1;
    }

