    private static boolean containsComplexOperations(MethodNode methodNode) {
        for (AbstractInsnNode instruction : methodNode.instructions) {
            int opcode = instruction.getOpcode();
            if (opcode == Opcodes.FDIV || opcode == Opcodes.FMUL ||
                    opcode == Opcodes.LDIV || opcode == Opcodes.LMUL ||
                    opcode == Opcodes.IDIV || opcode == Opcodes.IMUL ||
                    instruction.getOpcode() == Opcodes.CHECKCAST ||
                    (opcode >= Opcodes.I2F && opcode <= Opcodes.L2I)) {
                return true;
            }
        }
        return false;
    }

