    private static Map<String, Integer> guiCategoryIcons = new ConcurrentHashMap<>();
    private static Map<String, Float> guiAnimMap = new ConcurrentHashMap<>();
    private static long guiLastTime = System.currentTimeMillis();

    public static float guiAnimate(String key, float target, float speed) {
        float current = guiAnimMap.getOrDefault(key, target);
        long now = System.currentTimeMillis();
        float delta = (now - guiLastTime) / 1000f;
        if (delta > 0.1f)
            delta = 0.016f;
        current += (target - current) * (speed * delta * 50f);
        if (Math.abs(target - current) < 0.01f)
            current = target;
        guiAnimMap.put(key, current);
        return current;
    }

    public static int guiLoadTexture(String path) {
        try {
            InputStream is = GL11.class.getResourceAsStream("/eternalpro/icons/" + path);
            if (is == null)
                is = GL11.class.getResourceAsStream("/icons/" + path);
            if (is == null)
                is = GL11.class.getResourceAsStream("/eternalpro/" + path);
            if (is == null)
                is = GL11.class.getResourceAsStream("/" + path);
            if (is == null)
                return -1;
            BufferedImage img = ImageIO.read(is);
            if (img == null)
                return -1;
            int[] pixels = new int[img.getWidth() * img.getHeight()];
            img.getRGB(0, 0, img.getWidth(), img.getHeight(), pixels, 0, img.getWidth());
            ByteBuffer buffer = BufferUtils.createByteBuffer(img.getWidth() * img.getHeight() * 4);
            for (int y = 0; y < img.getHeight(); y++) {
                for (int x = 0; x < img.getWidth(); x++) {
                    int pixel = pixels[y * img.getWidth() + x];
                    buffer.put((byte) ((pixel >> 16) & 0xFF));
                    buffer.put((byte) ((pixel >> 8) & 0xFF));
                    buffer.put((byte) (pixel & 0xFF));
                    buffer.put((byte) ((pixel >> 24) & 0xFF));
                }
            }
            buffer.flip();
            int tex = glGenTextures();
            glBindTexture(GL_TEXTURE_2D, tex);
            glTexParameteri(GL_TEXTURE_2D, GL_TEXTURE_MIN_FILTER, GL_LINEAR);
            glTexParameteri(GL_TEXTURE_2D, GL_TEXTURE_MAG_FILTER, GL_LINEAR);
            glTexImage2D(GL_TEXTURE_2D, 0, GL_RGBA, img.getWidth(), img.getHeight(), 0, GL_RGBA, GL_UNSIGNED_BYTE,
                    buffer);
            return tex;
        } catch (Exception e) {
            return -1;
        }
    }

    public static void guiDrawIcon(int texture, float x, float y, float size, float alpha) {
        if (texture == -1)
            return;
        GL11.glPushAttrib(GL11.GL_ALL_ATTRIB_BITS);
        GL11.glEnable(GL11.GL_TEXTURE_2D);
        GL11.glBindTexture(GL11.GL_TEXTURE_2D, texture);
        GL11.glEnable(GL11.GL_BLEND);
        GL11.glBlendFunc(GL11.GL_SRC_ALPHA, GL11.GL_ONE_MINUS_SRC_ALPHA);
        GL11.glColor4f(1, 1, 1, alpha);
        GL11.glBegin(GL11.GL_QUADS);
        GL11.glTexCoord2f(0, 0);
        GL11.glVertex2f(x, y);
        GL11.glTexCoord2f(0, 1);
        GL11.glVertex2f(x, y + size);
        GL11.glTexCoord2f(1, 1);
        GL11.glVertex2f(x + size, y + size);
        GL11.glTexCoord2f(1, 0);
        GL11.glVertex2f(x + size, y);
        GL11.glEnd();
        GL11.glColor4f(1.0f, 1.0f, 1.0f, 1.0f);
        GL11.glPopAttrib();
    }


