    public static void drawRoundOutline(double x, double y, double width, double height, double edgeRadius,
                                        float thickness, int color) {
        GL11.glPushAttrib(GL11.GL_ALL_ATTRIB_BITS);
        GL11.glEnable(GL11.GL_BLEND);
        GL11.glDisable(GL11.GL_TEXTURE_2D);
        GL11.glBlendFunc(GL11.GL_SRC_ALPHA, GL11.GL_ONE_MINUS_SRC_ALPHA);
        GL11.glEnable(GL11.GL_LINE_SMOOTH);
        GL11.glLineWidth(thickness);

        float a = (color >> 24 & 255) / 255.0F;
        float r = (color >> 16 & 255) / 255.0F;
        float g = (color >> 8 & 255) / 255.0F;
        float b = (color & 255) / 255.0F;
        GL11.glColor4f(r, g, b, a);

        GL11.glBegin(GL11.GL_LINE_LOOP);

        for (int i = 0; i <= 90; i += 3)
            GL11.glVertex2d(x + edgeRadius + Math.sin(i * Math.PI / 180.0) * edgeRadius * -1.0,
                    y + edgeRadius + Math.cos(i * Math.PI / 180.0) * edgeRadius * -1.0);

        for (int i = 90; i <= 180; i += 3)
            GL11.glVertex2d(x + edgeRadius + Math.sin(i * Math.PI / 180.0) * edgeRadius * -1.0,
                    y + height - edgeRadius + Math.cos(i * Math.PI / 180.0) * edgeRadius * -1.0);

        for (int i = 0; i <= 90; i += 3)
            GL11.glVertex2d(x + width - edgeRadius + Math.sin(i * Math.PI / 180.0) * edgeRadius,
                    y + height - edgeRadius + Math.cos(i * Math.PI / 180.0) * edgeRadius);

        for (int i = 90; i <= 180; i += 3)
            GL11.glVertex2d(x + width - edgeRadius + Math.sin(i * Math.PI / 180.0) * edgeRadius,
                    y + edgeRadius + Math.cos(i * Math.PI / 180.0) * edgeRadius);
        GL11.glEnd();

        GL11.glPopAttrib();
    }

    private static void drawGuiRect(int x, int y, int width, int height, int color) {
        if (PANEL_RADIUS > 0)
            roundedRect(x, y, width, height, PANEL_RADIUS, new Color(color, true));
        else
            drawRect(x, y, width, height, color);
    }

    private static void drawGuiOutline(int x, int y, int width, int height, int color) {
        if (PANEL_RADIUS > 0)
            drawRoundOutline(x, y, width, height, PANEL_RADIUS, 1.0f, color);
        else
            drawOutline(x, y, width, height, color);
    }

