    public static void animations(float equipProgress, float swingProgress) {
        doCustomAnimation(equipProgress, swingProgress);
    }

    public static void doCustomAnimation(float equipProgress, float swingProgress) {
        String mode = getMode("Animations", "Mode");
        if (mode == null)
            mode = "Spin";
        if (mode.equals("Swing")) {
            animSwing(equipProgress, swingProgress);
        }
        if (mode.equals("Helicopter")) {
            animBlockhit(equipProgress, swingProgress);
        }
        if (mode.equals("Spin")) {
            animSpin(equipProgress, swingProgress);
        }
        if (mode.equals("TryTena")) {
            animTryTena(equipProgress, swingProgress);
        }
        if (mode.equals("Around")) {
            animAround(equipProgress, swingProgress);
        }
    }

    private static float smoothSwing = 0.0f;

    private static void animSpin(float equipProgress, float swingProgress) {
        float X = (float) getSettingValue("Animations", "X");
        float Y = (float) getSettingValue("Animations", "Y");
        float Z = (float) getSettingValue("Animations", "Z");
        float scale = (float) getSettingValue("Animations", "Scale");
        float spinSpeed = (float) getSettingValue("Animations", "SpinSpeed");

        GL11.glTranslatef(X, Y, Z);
        GL11.glTranslatef(0.0f, equipProgress * -0.6f, 0.0f);

        GL11.glRotatef(delay1, 0.0f, 1.0f, 0.0f);

        if (delay1 > 360.0f)
            delay1 = 0.0f;
        delay1 += spinSpeed;

        float v3 = (float) Math.sin(swingProgress * swingProgress * Math.PI);
        float v4 = (float) Math.sin(Math.sqrt(swingProgress) * Math.PI);

        GL11.glRotatef(v3 * -20.0f, 0.0f, 1.0f, 0.0f);
        GL11.glRotatef(v4 * -20.0f, 0.0f, 0.0f, 1.0f);
        GL11.glRotatef(v4 * -80.0f, 1.0f, 0.0f, 0.0f);

        GL11.glScalef(scale, scale, scale);
    }


    private static void animSwing(float equipProgress, float swingProgress) {
        float X = (float) getSettingValue("Animations", "X");
        float Y = (float) getSettingValue("Animations", "Y");
        float Z = (float) getSettingValue("Animations", "Z");
        float scale = (float) getSettingValue("Animations", "Scale");

        GL11.glTranslatef(X, Y, Z);
        GL11.glTranslatef(0.0f, equipProgress * -0.6f, 0.0f);
        GL11.glRotatef(45.0f, 0.0f, 1.0f, 0.0f);

        float var3 = (float) Math.sin(swingProgress * swingProgress * Math.PI);
        float var4 = (float) Math.sin(Math.sqrt(swingProgress) * Math.PI);

        GL11.glRotatef(var3 * -20.0f, 0.0f, 1.0f, 0.0f);
        GL11.glRotatef(var4 * -20.0f, 0.0f, 0.0f, 1.0f);
        GL11.glRotatef(var4 * -80.0f, 1.0f, 0.0f, 0.0f);

        GL11.glScalef(scale, scale, scale);
    }


    private static void animBlockhit(float equipProgress, float swingProgress) {
        float X = (float) getSettingValue("Animations", "X");
        float Y = (float) getSettingValue("Animations", "Y");
        float Z = (float) getSettingValue("Animations", "Z");
        float scale = (float) getSettingValue("Animations", "Scale");
        float spinSpeed = (float) getSettingValue("Animations", "SpinSpeed");


        GL11.glTranslatef(X, Y, Z);
        GL11.glTranslatef(0.0f, equipProgress * -0.6f, 0.0f);
        GL11.glRotatef(45.0f, 0.0f, 1.0f, 0.0f);

        float f = (float) Math.sin(swingProgress * swingProgress * Math.PI);
        float f1 = (float) Math.sin(Math.sqrt(swingProgress) * Math.PI);

        GL11.glRotatef(f * -20.0f, 0.0f, 1.0f, 0.0f);
        GL11.glRotatef(f1 * -20.0f, 0.0f, 0.0f, 1.0f);
        GL11.glRotatef(f1 * -80.0f, 1.0f, 0.0f, 0.0f);
        GL11.glScalef(scale, scale, scale);


        GL11.glTranslatef(-0.5f, 0.2f, 0.0f);
        GL11.glRotatef(30.0f, 0.0f, 1.0f, 0.0f);
        GL11.glRotatef(-80.0f, 1.0f, 0.0f, 0.0f);
        GL11.glRotatef(60.0f, 0.0f, 1.0f, 0.0f);


        GL11.glRotatef(delay1, 1.0f, 0.0f, 1.0f);

        if (delay1 > 360.0f)
            delay1 = 0.0f;
        delay1 += spinSpeed;
    }


    private static void animTryTena(float equipProgress, float swingProgress) {
        float X = (float) getSettingValue("Animations", "X");
        float Y = (float) getSettingValue("Animations", "Y");
        float Z = (float) getSettingValue("Animations", "Z");
        float scale = (float) getSettingValue("Animations", "Scale");

        float speed = (float) getSettingValue("Animations", "SwingSpeed");
        if (speed <= 0.1f)
            speed = 1.0f;


        GL11.glTranslatef(X, Y, Z);
        GL11.glTranslatef(0.0f, equipProgress * -0.6f, 0.0f);
        GL11.glRotatef(45.0f, 0.0f, 1.0f, 0.0f);


        boolean killauraActive = isModuleEnabled("KillAura") && closestTarget != null;

        if (killauraActive) {
            float f = (float) Math.sin(Math.sqrt(swingProgress) * Math.PI);
            float yMotion = -f * (0.2f * speed);

            GL11.glTranslatef(0.0f, yMotion, 0.0f);

            GL11.glRotatef(-90.0f, 1.0f, 0.0f, 0.0f);
            GL11.glRotatef(-20.0f, 0.0f, 1.0f, 0.0f);
            GL11.glRotatef(-60.0f, 1.0f, 0.0f, 0.0f);

            GL11.glRotatef(-f * (10.0f * speed), 1.0f, 0.0f, 0.0f);

        } else {
            float f1 = (float) Math.sin(swingProgress * swingProgress * Math.PI);
            float f2 = (float) Math.sin(Math.sqrt(swingProgress) * Math.PI);

            GL11.glRotatef(f1 * -20.0f, 0.0f, 1.0f, 0.0f);
            GL11.glRotatef(f2 * -20.0f, 0.0f, 0.0f, 1.0f);
            GL11.glRotatef(f2 * -80.0f, 1.0f, 0.0f, 0.0f);
        }

        GL11.glScalef(scale, scale, scale);
    }


    private static void animAround(float equipProgress, float swingProgress) {
        float X = (float) getSettingValue("Animations", "X");
        float Y = (float) getSettingValue("Animations", "Y");
        float Z = (float) getSettingValue("Animations", "Z");
        float scale = (float) getSettingValue("Animations", "Scale");
        float speed = (float) getSettingValue("Animations", "SwingSpeed");

        if (speed <= 0.1f)
            speed = 1.0f;

        if (swingProgress > 0.0f) {
            GL11.glTranslatef(0.0f, 0.0f, -2.0f + Z);

            float time = (float) System.currentTimeMillis();
            float rotation = (time * speed * 0.5f) % 360.0f;
            GL11.glRotatef(-rotation, 0.0f, 0.0f, 1.0f);

            float currentRadius = 0.5f + X;
            GL11.glTranslatef(0.0f, currentRadius, 0.0f);

            GL11.glRotatef(-90.0f, 0.0f, 0.0f, 1.0f);
            GL11.glRotatef(-45.0f, 0.0f, 1.0f, 0.0f);
            GL11.glRotatef(45.0f, 1.0f, 0.0f, 0.0f);

            GL11.glTranslatef(0.0f, equipProgress * -0.6f, 0.0f);

            GL11.glScalef(scale, scale, scale);
        } else {
            GL11.glTranslatef(X, Y, Z);
            GL11.glTranslatef(0.0f, equipProgress * -0.6f, 0.0f);

            GL11.glRotatef(45.0f, 0.0f, 1.0f, 0.0f);

            GL11.glScalef(scale, scale, scale);
        }
    }

    public static float fakeEquip = 0.0f;
    static float fakeSwing = 0;

    public static float getFakeSwing() {
        fakeSwing += 0.15f;
        if (fakeSwing > 1.0f)
            fakeSwing = 0.0f;
        return fakeSwing;
    }

    public static float getFakeEquipProgress() {
        boolean hasItem = getHeldItem() != null;

        float target = hasItem ? 1.0f : 0.0f;
        fakeEquip += (target - fakeEquip) * 0.35f;

        return fakeEquip;
    }

    private static float delay1;

    public static void updateAnimations() {
        for (Integer index : targetHeights.keySet()) {
            float target = targetHeights.get(index);
            float current = panelHeights.getOrDefault(index, target);
            float diff = target - current;

            if (Math.abs(diff) < 0.5f) {
                panelHeights.put(index, target);
            } else {
                panelHeights.put(index, current + (diff * ANIMATION_SPEED));
            }
        }
    }

    public static void renderClickGui(int mouseX, int mouseY, float partialTicks) {
        GL11.glPushAttrib(GL11.GL_ALL_ATTRIB_BITS);
        GL11.glPushMatrix();
        try {
            GL11.glDisable(GL11.GL_SCISSOR_TEST);
            GL11.glDisable(GL11.GL_DEPTH_TEST);
            GL11.glDisable(GL11.GL_LIGHTING);
            GL11.glEnable(GL11.GL_BLEND);
            GL11.glBlendFunc(GL11.GL_SRC_ALPHA, GL11.GL_ONE_MINUS_SRC_ALPHA);
            GL11.glColor4f(1.0f, 1.0f, 1.0f, 1.0f);

            renderClickGuiInternal(mouseX, mouseY, partialTicks);
        } finally {
            GL11.glColor4f(1.0f, 1.0f, 1.0f, 1.0f);
            GL11.glPopMatrix();
            GL11.glPopAttrib();
        }
    }

