    private static int getSchematicBoolBindKey(String boolName) {
        if (boolName == null) return 0;
        switch (boolName) {
            case "Pos1": return clipboardKeyPos1;
            case "Pos2": return clipboardKeyPos2;
            case "Copy": return clipboardKeyCopy;
            case "Paste": return clipboardKeyPaste;
            case "Clear": return clipboardKeyClear;
            default:
                return schematicToggleBindKeys.getOrDefault(boolName, 0);
        }
    }

    private static void setSchematicBoolBindKey(String boolName, int key) {
        if (boolName == null) return;
        switch (boolName) {
            case "Pos1": clipboardKeyPos1 = key; break;
            case "Pos2": clipboardKeyPos2 = key; break;
            case "Copy": clipboardKeyCopy = key; break;
            case "Paste": clipboardKeyPaste = key; break;
            case "Clear": clipboardKeyClear = key; break;
            default:
                if (key == 0) schematicToggleBindKeys.remove(boolName);
                else schematicToggleBindKeys.put(boolName, key);
                break;
        }
    }

    private static void clearSchematicBindKeyElsewhere(int key, String exceptName) {
        if (key == 0) return;
        String[] clip = {"Pos1", "Pos2", "Copy", "Paste", "Clear"};
        for (String s : clip) {
            if (s.equals(exceptName)) continue;
            if (getSchematicBoolBindKey(s) == key) setSchematicBoolBindKey(s, 0);
        }
        for (String s : SCHEMATIC_TOGGLE_BIND_NAMES) {
            if (s.equals(exceptName)) continue;
            if (schematicToggleBindKeys.getOrDefault(s, 0) == key) schematicToggleBindKeys.put(s, 0);
        }
    }

    private static float computeSchematicMenuContentHeight() {
        String modName = "Schematic";
        int boolCount = moduleBooleanSettingNames.getOrDefault(modName, new ArrayList<>()).size();
        int numCount = moduleSettingsNames.getOrDefault(modName, new ArrayList<>()).size();
        int modeCount = moduleModeSettingNames.getOrDefault(modName, new ArrayList<>()).size();
        int chunkRow = 30;
        int extraBindRow = 0;
        if (schem_expandedBoolRowForBind >= 0) {
            extraBindRow = 30; // keybind satırı
            // Show Grid satırı genişletilmişse Color satırı da var (+30)
            List<String> boolNames = moduleBooleanSettingNames.getOrDefault(modName, new ArrayList<>());
            if (schem_expandedBoolRowForBind < boolNames.size()
                    && "Show Grid".equals(boolNames.get(schem_expandedBoolRowForBind))) {
                extraBindRow += 30;
            }
        }
        return chunkRow + numCount * 30 + modeCount * 30 + boolCount * 30 + extraBindRow + 20;
    }

    private static void renderSchematicMenuPanelSettings(int modIdx, float x, float y, int mouseX, int mouseY) {
        String modName = "Schematic";
        float cy = y;

        boolean hChunk = isInside(x, cy, 385, 30, mouseX, mouseY);
        drawText("Chunk Copy", x, cy + 5, 0xFFDDDDDD);
        drawRoundedRectImgui(x + 220, cy + 2, 150, 20, 4, hChunk ? 0xFF5C2F73 : 0xFF333333);
        drawText(".schematic chunk", x + 228, cy + 5, 0xFFC084FC);
        cy += 30;

        List<String> numNames = moduleSettingsNames.getOrDefault(modName, new ArrayList<>());
        List<Double> numVals = moduleSettingsValues.getOrDefault(modName, new ArrayList<>());
        List<double[]> numRanges = moduleSettingsRanges.getOrDefault(modName, new ArrayList<>());
        for (int i = 0; i < numNames.size(); i++) {
            String nName = numNames.get(i);
            double val = numVals.get(i);
            double[] range = numRanges.get(i);
            drawText(nName + ": " + formatDouble(nName, val), x, cy + 5, 0xFFDDDDDD);
            float sx = x + 120, sw = 250;
            drawRoundedRectImgui(sx, cy + 12, sw, 4, 2, 0xFF333333);
            float pct = Math.max(0, Math.min(1, (float) ((val - range[0]) / (range[1] - range[0]))));
            drawRoundedRectImgui(sx, cy + 12, pct * sw, 4, 2, 0xFFC084FC);
            float hX = guiAnimate("rise_slider_h_" + nName, sx + pct * sw - 4, 0.8f);
            drawRoundedRectImgui(hX, cy + 8, 8, 12, 4, 0xFFFFFFFF);
            cy += 30;
        }
        List<String> modeNames = moduleModeSettingNames.getOrDefault(modName, new ArrayList<>());
        List<String> modeVals = moduleModeSettingValues.getOrDefault(modName, new ArrayList<>());
        for (int i = 0; i < modeNames.size(); i++) {
            drawText(modeNames.get(i), x, cy + 5, 0xFFDDDDDD);
            float bx = x + 220;
            drawRoundedRectImgui(bx, cy + 2, 150, 20, 4, 0xFF333333);
            drawText(modeVals.get(i), bx + 10, cy + 5, 0xFFFFFFFF);
            cy += 30;
        }

        List<String> boolNames = moduleBooleanSettingNames.getOrDefault(modName, new ArrayList<>());
        List<Boolean> boolVals = moduleSettingsBooleans.getOrDefault(modName, new ArrayList<>());
        for (int i = 0; i < boolNames.size(); i++) {
            String bn = boolNames.get(i);
            drawText(bn, x, cy + 5, 0xFFDDDDDD);
            float cx = x + 350;
            boolean bVal = boolVals.get(i);
            drawRoundedRectImgui(cx, cy + 4, 16, 16, 4, bVal ? 0xFFC084FC : 0xFF333333);
            if (schem_expandedBoolRowForBind == i) {
                float ky = cy + 30;
                int bk = getSchematicBoolBindKey(bn);
                boolean waitingThis = waitingForSchematicBoolSettingKeybind.equals(bn);
                String keyText = bk != 0 ? Keyboard.getKeyName(bk) : "None";
                drawText("Keybind", x, ky + 5, 0xFFDDDDDD);
                float kbX = x + 220;
                drawRoundedRectImgui(kbX, ky + 2, 150, 20, 4, waitingThis ? 0xFF5C2F73 : 0xFF333333);
                drawText(waitingThis ? "..." : ("Keybind: " + keyText), kbX + 10, ky + 5, 0xFFC084FC);
                ky += 30;
                // Show Grid için Color seçeneği
                if ("Show Grid".equals(bn)) {
                    String curColor = getMode("Schematic", "Grid Color");
                    if (curColor == null) curColor = "White";
                    drawText("Color", x, ky + 5, 0xFFDDDDDD);
                    float colX = x + 220;
                    drawRoundedRectImgui(colX, ky + 2, 150, 20, 4, 0xFF333333);
                    drawText(curColor, colX + 10, ky + 5, 0xFFC084FC);
                    cy += 90; // 30 (keybind) + 30 (color) + 30 (base)
                } else {
                    cy += 60;
                }
            } else {
                cy += 30;
            }
        }
    }

    private static boolean handleSchematicMenuPanelClick(int modIdx, float x, float y, int mouseX, int mouseY, int button) {
        String modName = "Schematic";
        float cy = y;

        if (isInside(x, cy, 385, 30, mouseX, mouseY)) {
            if (button == 0) {
                schematicStartChunkCopyAsync();
                return true;
            }
            return true;
        }
        cy += 30;

        List<String> numNames = moduleSettingsNames.getOrDefault(modName, new ArrayList<>());
        for (int i = 0; i < numNames.size(); i++) {
            if (button == 0 && isInside(x + 120, cy + 8, 250, 12, mouseX, mouseY)) {
                draggingSliderModuleIndex = modIdx;
                draggingSliderSetting = numNames.get(i);
                return true;
            }
            cy += 30;
        }
        List<String> modeNames = moduleModeSettingNames.getOrDefault(modName, new ArrayList<>());
        List<String> modeVals = moduleModeSettingValues.getOrDefault(modName, new ArrayList<>());
        List<List<String>> modeOpts = moduleModeOptions.getOrDefault(modName, new ArrayList<>());
        for (int i = 0; i < modeNames.size(); i++) {
            if (button == 0 && isInside(x + 220, cy + 2, 150, 20, mouseX, mouseY)) {
                List<String> opts = modeOpts.get(i);
                int idx = opts.indexOf(modeVals.get(i));
                if (idx != -1) modeVals.set(i, opts.get((idx + 1) % opts.size()));
                return true;
            }
            cy += 30;
        }

        List<String> boolNames = moduleBooleanSettingNames.getOrDefault(modName, new ArrayList<>());
        List<Boolean> boolVals = moduleSettingsBooleans.getOrDefault(modName, new ArrayList<>());
        for (int i = 0; i < boolNames.size(); i++) {
            float rowY = cy;
            if (button == 0 && isInside(x + 350, rowY + 4, 16, 16, mouseX, mouseY)) {
                boolVals.set(i, !boolVals.get(i));
                return true;
            }
            if (button == 1 && isInside(x, rowY, 340, 30, mouseX, mouseY)
                    && !isInside(x + 350, rowY + 4, 16, 16, mouseX, mouseY)) {
                schem_expandedBoolRowForBind = (schem_expandedBoolRowForBind == i) ? -1 : i;
                return true;
            }
            if (schem_expandedBoolRowForBind == i) {
                float ky = rowY + 30;
                if (button == 0 && isInside(x + 220, ky + 2, 150, 20, mouseX, mouseY)) {
                    waitingForSchematicBoolSettingKeybind = boolNames.get(i);
                    waitingForSchematicKeybind = false;
                    waitingForKeybind = false;
                    keybindModuleIndex = -1;
                    return true;
                }
                ky += 30;
                // Show Grid için Color butonu
                if ("Show Grid".equals(boolNames.get(i))) {
                    if (button == 0 && isInside(x + 220, ky + 2, 150, 20, mouseX, mouseY)) {
                        // Rengi döngüsel olarak değiştir
                        List<String> modeNamesL = moduleModeSettingNames.getOrDefault(modName, new ArrayList<>());
                        List<String> modeValsL = moduleModeSettingValues.getOrDefault(modName, new ArrayList<>());
                        List<List<String>> modeOptsL = moduleModeOptions.getOrDefault(modName, new ArrayList<>());
                        int mIdx = modeNamesL.indexOf("Grid Color");
                        if (mIdx != -1) {
                            List<String> opts = modeOptsL.get(mIdx);
                            int cur = opts.indexOf(modeValsL.get(mIdx));
                            modeValsL.set(mIdx, opts.get((cur + 1) % opts.size()));
                        }
                        return true;
                    }
                    cy += 90;
                } else {
                    cy += 60;
                }
            } else {
                cy += 30;
            }
        }
        return false;
    }

    private static void renderSchematicMenuRise6(int mouseX, int mouseY) {
        int modIdx = moduleNames.indexOf("Schematic");
        if (modIdx == -1) return;

        float contentH = computeSchematicMenuContentHeight();
        float visibleH = schem_guiH - 50;
        float maxScroll = Math.min(0, visibleH - contentH);

        int wheel = org.lwjgl.input.Mouse.getDWheel();
        if (wheel < 0) schem_targetScrollY -= 30;
        if (wheel > 0) schem_targetScrollY += 30;
        if (schem_targetScrollY > 0) schem_targetScrollY = 0;
        if (schem_targetScrollY < maxScroll) schem_targetScrollY = maxScroll;
        schem_scrollY = guiAnimate("schem_scrollY", schem_targetScrollY, 0.4f);

        drawRoundedRectImgui(schem_guiX, schem_guiY, schem_guiW, schem_guiH, 8, 0xFF0F0F10);
        drawRoundedRectImgui(schem_guiX, schem_guiY, schem_guiW, 40, 8, 0xFF18181B);
        GL11.glEnable(GL11.GL_TEXTURE_2D);


        boolean hoverExit = isInside((int)schem_guiX + 5, (int)schem_guiY + 5, 25, 30, mouseX, mouseY);
        drawText("<-", schem_guiX + 10, schem_guiY + 15, hoverExit ? 0xFFC084FC : 0xFFFFFFFF);

        drawText("SCHEMATIC", schem_guiX + 35, schem_guiY + 15, 0xFFFFFFFF);

        boolean enabled = moduleEnabled.get(modIdx);

        float switchX = schem_guiX + schem_guiW - 45;
        float switchY = schem_guiY + 12;
        GL11.glDisable(GL11.GL_TEXTURE_2D);
        drawRoundedRectImgui(switchX, switchY, 30, 16, 8, enabled ? 0xFFC084FC : 0xFF333333);
        float toggleCircleX = guiAnimate("schem_toggle", enabled ? switchX + 16 : switchX + 2, 0.3f);
        drawRoundedRectImgui(toggleCircleX, switchY + 2, 12, 12, 6, 0xFFFFFFFF);

        GL11.glEnable(GL11.GL_TEXTURE_2D);
        prepareScissorBox(schem_guiX, schem_guiY + 40, schem_guiX + schem_guiW, schem_guiY + schem_guiH);
        renderSchematicMenuPanelSettings(modIdx, schem_guiX + 15, schem_guiY + 50 + schem_scrollY, mouseX, mouseY);
        stopScissor();
    }

