    private static List<Integer> exhibitionModulesForCategory(String category) {
        List<Integer> out = new ArrayList<>();
        for (int i = 0; i < moduleNames.size(); i++) {
            if (moduleCategories.get(i).equals(category) && !isModuleHidden(moduleNames.get(i)))
                out.add(i);
        }
        return out;
    }

    private static void toggleModule(int modIndex) {
        if (modIndex < 0 || modIndex >= moduleEnabled.size())
            return;
        boolean newState = !moduleEnabled.get(modIndex);
        moduleEnabled.set(modIndex, newState);
        if (newState)
            moduleOnEnable.get(modIndex).run();
        else
            moduleOnDisable.get(modIndex).run();
    }


