    private static String k(int modIndex, String name) {
        return modIndex + "|" + name;
    }

    private static boolean exhibitionHasSettings(String modName) {
        return !moduleSettingsNames.getOrDefault(modName, Collections.emptyList()).isEmpty()
                || !moduleSettingsBooleans.getOrDefault(modName, Collections.emptyList()).isEmpty()
                || !moduleModeSettingNames.getOrDefault(modName, Collections.emptyList()).isEmpty();
    }

    private static int exhibitionCardHeightFor(int modIndex, int cardW) {
        String modName = moduleNames.get(modIndex);
        boolean has = exhibitionHasSettings(modName);
        int headerH = 18;
        if (!has)
            return headerH + 10;

        int y = headerH + 6;
        if (!moduleModeSettingNames.getOrDefault(modName, Collections.emptyList()).isEmpty()
                && !moduleModeSettingValues.getOrDefault(modName, Collections.emptyList()).isEmpty()) {
            y += 12;
        }

        int numCount = Math.min(3, Math.min(
                moduleSettingsNames.getOrDefault(modName, Collections.emptyList()).size(),
                Math.min(moduleSettingsValues.getOrDefault(modName, Collections.emptyList()).size(),
                        moduleSettingsRanges.getOrDefault(modName, Collections.emptyList()).size())));
        y += numCount * 14;

        int boolCount = Math.min(3, Math.min(
                moduleBooleanSettingNames.getOrDefault(modName, Collections.emptyList()).size(),
                moduleSettingsBooleans.getOrDefault(modName, Collections.emptyList()).size()));
        y += boolCount * 12;


        return Math.max(headerH + 10, Math.min(110, y + 6));
    }

