    private static void handleExhibitionDrag(int mouseX, int mouseY, int button) {
        if (button != 0)
            return;
        if (draggingSliderModuleIndex == -1 || draggingSliderSetting.isEmpty())
            return;

        int modIndex = draggingSliderModuleIndex;
        String modName = moduleNames.get(modIndex);

        int[] sr = exhibitionSliderRect.get(k(modIndex, draggingSliderSetting));
        if (sr == null)
            return;

        List<String> numNames = moduleSettingsNames.getOrDefault(modName, Collections.emptyList());
        List<Double> numVals = moduleSettingsValues.getOrDefault(modName, Collections.emptyList());
        List<double[]> numRanges = moduleSettingsRanges.getOrDefault(modName, Collections.emptyList());

        int sIdx = numNames.indexOf(draggingSliderSetting);
        if (sIdx < 0 || sIdx >= numVals.size() || sIdx >= numRanges.size())
            return;

        int sx = sr[0], sw = sr[2];
        float pct = Math.max(0f, Math.min(1f, (mouseX - sx) / (float) sw));
        double[] range = numRanges.get(sIdx);
        double nv = range[0] + pct * (range[1] - range[0]);
        numVals.set(sIdx, formatSliderValue(draggingSliderSetting, nv));
        if (moduleOnUpdate.get(modIndex) != null)
            moduleOnUpdate.get(modIndex).run();
    }

    public static void prepareScissorBox(double x, double y, double x2, double y2) {
        int displayHeight = Display.getHeight();
        int scaleFactor = getScaleFactor();

        int sx = (int) (x * scaleFactor);
        int sy = (int) (displayHeight - (y2 * scaleFactor));
        int sw = (int) ((x2 - x) * scaleFactor);
        int sh = (int) ((y2 - y) * scaleFactor);

        GL11.glScissor(sx, sy, sw, sh);
        GL11.glEnable(GL11.GL_SCISSOR_TEST);
    }

