    private static String formatDouble(double value) {
        if (value == (int) value) {
            return String.format("%d", (int) value);
        } else {
            return String.format("%.2f", value);
        }
    }

    private static String formatDouble(String settingName, double value) {
        if ("Render Distance".equals(settingName) && value >= 100.0) {
            return "Unlimited";
        }
        return formatDouble(value);
    }

