    private static boolean isInsideSettingsMenu(int mouseX, int mouseY, int settingsX, int settingsY, String modName) {
        int settingsHeight = getSettingsMenuHeight(modName);
        return isInside(settingsX, settingsY, SETTINGS_WIDTH, settingsHeight, mouseX, mouseY);
    }

    private static int getSettingsMenuHeight(String modName) {
        int height = SETTINGS_PADDING;
        List<String> settings = moduleSettingsNames.getOrDefault(modName, new ArrayList<>());
        List<Double> values = moduleSettingsValues.getOrDefault(modName, new ArrayList<>());
        List<double[]> ranges = moduleSettingsRanges.getOrDefault(modName, new ArrayList<>());
        int validSettings = 0;
        for (int i = 0; i < settings.size(); i++) {
            if (i < values.size() && i < ranges.size()) validSettings++;
        }
        height += validSettings * (SETTINGS_ITEM_HEIGHT + 1);
        height += moduleSettingsBooleans.getOrDefault(modName, new ArrayList<>()).size() * (SETTINGS_ITEM_HEIGHT + 1);
        height += moduleModeSettingNames.getOrDefault(modName, new ArrayList<>()).size() * (SETTINGS_ITEM_HEIGHT + 1);
        height += SETTINGS_ITEM_HEIGHT + 2;

        if (modName.equals("Schematic")) {
            height += 5 * (SETTINGS_ITEM_HEIGHT + 1);
        }
        height += SETTINGS_PADDING;
        return height;
    }

    private static boolean handleSettingsMenuClick(String modName, int x, int y, int mouseX, int mouseY, int button) {
        int currentY = y + SETTINGS_PADDING;
        List<String> settings = moduleSettingsNames.getOrDefault(modName, new ArrayList<>());
        List<Boolean> boolSettings = moduleSettingsBooleans.getOrDefault(modName, new ArrayList<>());
        List<String> modeSettings = moduleModeSettingNames.getOrDefault(modName, new ArrayList<>());
        List<Double> values = moduleSettingsValues.getOrDefault(modName, new ArrayList<>());
        List<double[]> ranges = moduleSettingsRanges.getOrDefault(modName, new ArrayList<>());
        for (int i = 0; i < settings.size(); i++) {
            if (i >= values.size() || i >= ranges.size()) continue;
            int sliderY = currentY + SETTINGS_ITEM_HEIGHT - 4;

            if (isInside(x + SETTINGS_PADDING, sliderY, SETTINGS_WIDTH - SETTINGS_PADDING * 2,
                    SLIDER_HEIGHT, mouseX, mouseY) && button == 0) {
                draggingSliderModuleIndex = moduleNames.indexOf(modName);
                draggingSliderSetting = settings.get(i);
                return true;
            }
            currentY += SETTINGS_ITEM_HEIGHT + 1;
        }
        for (int i = 0; i < boolSettings.size(); i++) {
            if (isInside(x + SETTINGS_PADDING, currentY, CHECKBOX_SIZE, CHECKBOX_SIZE, mouseX, mouseY) && button == 0) {
                boolSettings.set(i, !boolSettings.get(i));
                return true;
            }
            currentY += SETTINGS_ITEM_HEIGHT + 1;
        }
        for (int i = 0; i < modeSettings.size(); i++) {
            String setting = modeSettings.get(i);
            String currentValue = moduleModeSettingValues.get(modName).get(i);
            int modeButtonWidth = 60;
            int buttonX = x + SETTINGS_WIDTH - SETTINGS_PADDING - modeButtonWidth;
            int buttonY = currentY;

            if (isInside(buttonX, buttonY, modeButtonWidth, MODE_BUTTON_HEIGHT, mouseX, mouseY) && button == 0) {
                openModeMenuModuleIndex = moduleNames.indexOf(modName);
                openModeMenuSetting = setting;
                return true;
            }
            currentY += SETTINGS_ITEM_HEIGHT + 1;
        }
        int modIndex = moduleNames.indexOf(modName);
        if (modIndex >= 0) {
            if (isInside(x + SETTINGS_PADDING, currentY, SETTINGS_WIDTH - SETTINGS_PADDING * 2, SETTINGS_ITEM_HEIGHT,
                    mouseX, mouseY) && button == 0) {
                waitingForKeybind = true;
                keybindModuleIndex = modIndex;
                return true;
            }
            currentY += SETTINGS_ITEM_HEIGHT + 1;


            if (modName.equals("Schematic")) {
                String[] bindTargets = {"Pos1", "Pos2", "Copy", "Paste", "Clear"};
                int badgeW = 50;
                int badgeH = 12;
                for (int bi = 0; bi < 5; bi++) {
                    int badgeX = x + SETTINGS_WIDTH - SETTINGS_PADDING - badgeW;
                    int badgeY = currentY;
                    if (isInside(badgeX, badgeY, badgeW, badgeH, mouseX, mouseY) && button == 0) {
                        waitingForSchematicKeybind = true;
                        schematicKeybindTarget = bindTargets[bi];
                        return true;
                    }
                    currentY += SETTINGS_ITEM_HEIGHT + 1;
                }
            }
        }

        return false;
    }

