    private static boolean handleRiseSettingClick(int modIdx, float x, float y, int mouseX, int mouseY, int button, boolean includeKeybind) {
        String modName = moduleNames.get(modIdx);
        float currentY = y;
        List<String> boolNames = moduleBooleanSettingNames.getOrDefault(modName, new ArrayList<>());
        List<Boolean> boolVals = moduleSettingsBooleans.getOrDefault(modName, new ArrayList<>());
        for (int i = 0; i < boolNames.size(); i++) {
            if (button == 0 && isInside(x + 350, currentY + 4, 16, 16, mouseX, mouseY)) {
                boolVals.set(i, !boolVals.get(i));
                return true;
            }
            currentY += 30;
        }
        List<String> numNames = moduleSettingsNames.getOrDefault(modName, new ArrayList<>());
        for (int i = 0; i < numNames.size(); i++) {
            if (button == 0 && isInside(x + 120, currentY + 8, 250, 12, mouseX, mouseY)) {
                draggingSliderModuleIndex = modIdx;
                draggingSliderSetting = numNames.get(i);
                return true;
            }
            currentY += 30;
        }
        List<String> modeNames = moduleModeSettingNames.getOrDefault(modName, new ArrayList<>());
        List<String> modeVals = moduleModeSettingValues.getOrDefault(modName, new ArrayList<>());
        List<List<String>> modeOpts = moduleModeOptions.getOrDefault(modName, new ArrayList<>());
        for (int i = 0; i < modeNames.size(); i++) {
            if (button == 0 && isInside(x + 220, currentY + 2, 150, 20, mouseX, mouseY)) {
                List<String> opts = modeOpts.get(i);
                int idx = opts.indexOf(modeVals.get(i));
                if (idx != -1)
                    modeVals.set(i, opts.get((idx + 1) % opts.size()));
                return true;
            }
            currentY += 30;
        }
        if (includeKeybind && button == 0 && isInside(x + 220, currentY + 2, 150, 20, mouseX, mouseY)) {
            waitingForKeybind = true;
            keybindModuleIndex = modIdx;
            return true;
        }
        return false;
    }

    private static void handleLucilleClick(int mouseX, int mouseY, int button) {
        if (button == 0 && isInside(lucille_guiX, lucille_guiY, lucille_guiW, 20, mouseX, mouseY)) {
            isDraggingPanel = true;
            lucille_dragOffsetX = mouseX - lucille_guiX;
            lucille_dragOffsetY = mouseY - lucille_guiY;
        }
        float sidebarW = 60, cy = lucille_guiY + 20;
        List<String> cats = new ArrayList<>(new LinkedHashSet<>(moduleCategories));
        for (String c : cats) {
            if (button == 0 && isInside(lucille_guiX, cy, sidebarW, 40, mouseX, mouseY)) {
                lucille_selectedCategory = c;
                return;
            }
            cy += 50;
        }
        float modX = lucille_guiX + sidebarW + 20, modY = lucille_guiY + 40;
        for (int i = 0; i < moduleNames.size(); i++) {
            if (!moduleCategories.get(i).equals(lucille_selectedCategory) || isModuleHidden(moduleNames.get(i)))
                continue;
            if (isInside(modX, modY, lucille_guiW - sidebarW - 40, 20, mouseX, mouseY)) {
                if (button == 0) {
                    moduleEnabled.set(i, !moduleEnabled.get(i));
                    if (moduleEnabled.get(i)) {
                        if (moduleOnEnable.get(i) != null)
                            moduleOnEnable.get(i).run();
                    } else {
                        if (moduleOnDisable.get(i) != null)
                            moduleOnDisable.get(i).run();
                    }
                } else if (button == 1) {
                    lucille_expandedModule = (lucille_expandedModule == i) ? -1 : i;
                }
                return;
            }
            modY += 20;
            if (lucille_expandedModule == i) {
                float res = handleLucilleSettingClick(i, modX + 20, modY, lucille_guiW - sidebarW - 60, mouseX, mouseY,
                        button);
                if (res == -1)
                    return;
                modY = res;
            }
        }
    }

    private static float handleLucilleSettingClick(int modIdx, float x, float y, float w, int mouseX, int mouseY,
                                                   int button) {
        String modName = moduleNames.get(modIdx);
        float currentY = y;
        List<String> boolNames = moduleBooleanSettingNames.getOrDefault(modName, new ArrayList<>());
        List<Boolean> boolVals = moduleSettingsBooleans.getOrDefault(modName, new ArrayList<>());
        for (int i = 0; i < boolNames.size(); i++) {
            if (button == 0 && isInside(x, currentY, w, 18, mouseX, mouseY)) {
                boolVals.set(i, !boolVals.get(i));
                return -1;
            }
            currentY += 18;
        }
        List<String> numNames = moduleSettingsNames.getOrDefault(modName, new ArrayList<>());
        for (int i = 0; i < numNames.size(); i++) {
            if (button == 0 && isInside(x + 80, currentY + 5, w - 100, 8, mouseX, mouseY)) {
                draggingSliderModuleIndex = modIdx;
                draggingSliderSetting = numNames.get(i);
                return -1;
            }
            currentY += 20;
        }
        List<String> modeNames = moduleModeSettingNames.getOrDefault(modName, new ArrayList<>());
        List<String> modeVals = moduleModeSettingValues.getOrDefault(modName, new ArrayList<>());
        List<List<String>> modeOpts = moduleModeOptions.getOrDefault(modName, new ArrayList<>());
        for (int i = 0; i < modeNames.size(); i++) {
            if (button == 0 && isInside(x + 80, currentY + 2, w - 100, 16, mouseX, mouseY)) {
                List<String> opts = modeOpts.get(i);
                int idx = opts.indexOf(modeVals.get(i));
                if (idx != -1)
                    modeVals.set(i, opts.get((idx + 1) % opts.size()));
                return -1;
            }
            currentY += 22;
        }
        return currentY;
    }

