    public static int activeTextInputModuleIndex = -1;
    public static String activeTextInputSetting = "";

    public static void handleKeyPress(int keyCode, char keyChar) {
        if (waitingForSchematicBoolSettingKeybind != null && !waitingForSchematicBoolSettingKeybind.isEmpty()) {
            int assignKey = (keyCode == 1) ? 0 : keyCode;
            String target = waitingForSchematicBoolSettingKeybind;
            clearSchematicBindKeyElsewhere(assignKey, target);
            setSchematicBoolBindKey(target, assignKey);
            waitingForSchematicBoolSettingKeybind = "";
            if (assignKey != 0) {
                addChatMessage("§b[Schematic] §f" + target + " §7tuşu: §e" + Keyboard.getKeyName(assignKey));
            } else {
                addChatMessage("§7[Schematic] §f" + target + " §7tuşu temizlendi.");
            }
            return;
        }

        if (waitingForKeybind && keybindModuleIndex != -1) {
            if (keyCode == 1) {
                moduleBindKeys.set(keybindModuleIndex, 0);
            } else {
                moduleBindKeys.set(keybindModuleIndex, keyCode);
            }
            waitingForKeybind = false;
            keybindModuleIndex = -1;
            return;
        }


        if (waitingForSchematicKeybind && !schematicKeybindTarget.isEmpty()) {
            int assignKey = (keyCode == 1) ? 0 : keyCode;
            String targetName = schematicKeybindTarget;
            if (targetName.equals("Pos1")) {
                clipboardKeyPos1 = assignKey;
                clearSchematicBindKeyElsewhere(assignKey, "Pos1");
            } else if (targetName.equals("Pos2")) {
                clipboardKeyPos2 = assignKey;
                clearSchematicBindKeyElsewhere(assignKey, "Pos2");
            } else if (targetName.equals("Copy")) {
                clipboardKeyCopy = assignKey;
                clearSchematicBindKeyElsewhere(assignKey, "Copy");
            } else if (targetName.equals("Paste")) {
                clipboardKeyPaste = assignKey;
                clearSchematicBindKeyElsewhere(assignKey, "Paste");
            } else if (targetName.equals("Clear")) {
                clipboardKeyClear = assignKey;
                clearSchematicBindKeyElsewhere(assignKey, "Clear");
            }
            waitingForSchematicKeybind = false;
            schematicKeybindTarget = "";
            if (assignKey != 0) {
                addChatMessage("§b[Schematic] §f" + targetName + " key: §e" + Keyboard.getKeyName(assignKey));
            }
            return;
        }

        if (activeTextInputModuleIndex != -1 && !activeTextInputSetting.isEmpty()) {
            String modName = moduleNames.get(activeTextInputModuleIndex);
            String current = getString(modName, activeTextInputSetting);

            if (keyCode == 1) {
                activeTextInputModuleIndex = -1;
                activeTextInputSetting = "";
                return;
            } else if (keyCode == 14) {
                if (current.length() > 0) {
                    setString(modName, activeTextInputSetting, current.substring(0, current.length() - 1));
                }
                return;
            } else if (keyCode == 28) {
                activeTextInputModuleIndex = -1;
                activeTextInputSetting = "";
                return;
            }


            if (keyChar >= 32 && keyChar != 127) {
                setString(modName, activeTextInputSetting, current + keyChar);
            }
        }
    }

    private static boolean isInside(float x, float y, float w, float h, float mx, float my) {
        return mx >= x && mx <= x + w && my >= y && my <= y + h;
    }

    private static boolean isInside(int x, int y, int w, int h, int mx, int my) {
        return mx >= x && mx <= x + w && my >= y && my <= y + h;
    }

    private static int rgba(int r, int g, int b, int a) {
        return ((a & 0xFF) << 24) | ((r & 0xFF) << 16) | ((g & 0xFF) << 8) | (b & 0xFF);
    }

    private static void drawOutline(int x, int y, int w, int h, int color) {
        drawRect(x, y, w, 1, color);
        drawRect(x, y + h - 1, w, 1, color);
        drawRect(x, y, 1, h, color);
        drawRect(x + w - 1, y, 1, h, color);
    }

    private static void drawShadow(int x, int y, int width, int height, int shadowSize, int alpha) {
        for (int i = 0; i < shadowSize; i++) {
            int a = (int) (alpha * (1 - (float) i / shadowSize / 2));
            drawRect(x + i, y + height + i, width - i * 2, 1, rgba(0, 0, 0, a));
            drawRect(x + i, y + i, 1, height - i * 2, rgba(0, 0, 0, a));
            drawRect(x + width - i - 1, y + i, 1, height - i * 2, rgba(0, 0, 0, a));
            drawRect(x + i, y + i, width - i * 2, 1, rgba(0, 0, 0, a));
        }
    }

    private static double formatSliderValue(String name, double val) {
        String lower = name.toLowerCase();
        if (lower.contains("slot") || lower.equals("hits") || lower.contains("delay") || lower.contains("hp")
                || lower.contains("heart")) {
            return Math.round(val);
        } else if (lower.contains("cps")) {
            return Math.round(val * 10.0) / 10.0;
        }
        return Math.round(val * 100.0) / 100.0;
    }

    private static String getSliderDisplayString(String name, double val) {
        double formatted = formatSliderValue(name, val);
        String lower = name.toLowerCase();
        if (lower.contains("slot") || lower.equals("hits") || lower.contains("delay") || lower.contains("hp")
                || lower.contains("heart")) {
            return String.valueOf((int) Math.round(formatted));
        } else if (lower.contains("cps")) {
            return String.valueOf(formatted).replace(',', '.');
        }
        return String.valueOf(formatted).replace(',', '.');
    }

