    private static int lastScreenWidth = 0;
    private static int lastScreenHeight = 0;

    public static void handleScreenResize() {
        int currentScreenWidth = getScreenWidth();
        int currentScreenHeight = getScreenHeight();

        if (lastScreenWidth != 0 && lastScreenHeight != 0 &&
                (currentScreenWidth != lastScreenWidth || currentScreenHeight != lastScreenHeight)) {
            repositionPanels();
        }

        lastScreenWidth = currentScreenWidth;
        lastScreenHeight = currentScreenHeight;
    }

    private static void repositionPanels() {
        List<String> categories = new ArrayList<>(new LinkedHashSet<>(moduleCategories));
        if (categories.isEmpty())
            return;
        int screenW = getScreenWidth();
        int screenH = getScreenHeight();
        int totalPanels = categories.size();
        int totalWidth = totalPanels * PANEL_WIDTH + (totalPanels - 1) * PANEL_GAP;
        int startX = (screenW - totalWidth) / 2;
        for (int i = 0; i < categories.size(); i++) {
            int[] currentPos = panelPositions.getOrDefault(i, new int[] { 100, 100 });
            int newX = startX + i * (PANEL_WIDTH + PANEL_GAP);


            int baseH = (lastScreenHeight > 0) ? lastScreenHeight : screenH;
            int newY = (int)((float)currentPos[1] * screenH / baseH);
            newY = Math.max(0, Math.min(screenH - 200, newY));

            panelPositions.put(i, new int[] { newX, newY });
        }
    }






