                    "    for (float f = 1.0; f <= radius; f++) {\n" +
                    "        int idx = int(f);\n" +
                    "        col += texture2D(textureIn, gl_TexCoord[0].st + f * off).rgb * weights[idx];\n" +
                    "        col += texture2D(textureIn, gl_TexCoord[0].st - f * off).rgb * weights[idx];\n" +
                    "    }\n" +
                    "    gl_FragColor = vec4(col, 1.0);\n" +
                    "}";

