    private static void drawMediaRect(float x, float y, float w, float h, int r, int g, int b, int a) {
        if (a <= 0)
            return;
        GL11.glDisable(GL11.GL_TEXTURE_2D);
        GL11.glEnable(GL11.GL_BLEND);
        GL11.glBlendFunc(GL11.GL_SRC_ALPHA, GL11.GL_ONE_MINUS_SRC_ALPHA);
        GL11.glColor4f(r / 255.0f, g / 255.0f, b / 255.0f, a / 255.0f);
        GL11.glBegin(GL11.GL_QUADS);
        GL11.glVertex2f(x, y);
        GL11.glVertex2f(x, y + h);
        GL11.glVertex2f(x + w, y + h);
        GL11.glVertex2f(x + w, y);
        GL11.glEnd();
        GL11.glColor4f(1, 1, 1, 1);
    }


    private static boolean mediaPrevLeftDown = false;

    private static void handleMediaWidgetMouse() {
        if (getCurrentScreen() != null)
            return;
        if (!hudEditorMode)
            return;

        int mx = mapMouseToGuiX(Mouse.getX());
        int my = mapMouseToGuiY(Mouse.getY());
        boolean leftDown = Mouse.isButtonDown(0);
        boolean justPressed = leftDown && !mediaPrevLeftDown;
        boolean justReleased = !leftDown && mediaPrevLeftDown;
        mediaPrevLeftDown = leftDown;

        float wx = mediaWidgetX;
        float wy = mediaWidgetY;
        float ww = mediaWidgetW;
        float wh = mediaWidgetH;


        float rz = 12;
        boolean inResizeZone = mx >= wx + ww - rz && mx <= wx + ww + 2 && my >= wy + wh - rz && my <= wy + wh + 2;

        boolean inRightEdge = mx >= wx + ww - 5 && mx <= wx + ww + 2 && my >= wy && my <= wy + wh;

        boolean inBottomEdge = mx >= wx && mx <= wx + ww && my >= wy + wh - 5 && my <= wy + wh + 2;

        boolean inside = mx >= wx && mx <= wx + ww && my >= wy && my <= wy + wh;

        if (justPressed) {
            if (inResizeZone) {
                mediaResizing = true;
                mediaResizeEdge = 3;
            } else if (inRightEdge) {
                mediaResizing = true;
                mediaResizeEdge = 1;
            } else if (inBottomEdge) {
                mediaResizing = true;
                mediaResizeEdge = 2;
            } else if (inside) {
                mediaDragging = true;
                mediaDragOffX = mx - wx;
                mediaDragOffY = my - wy;
            }
        }

        if (justReleased) {
            mediaDragging = false;
            mediaResizing = false;
            mediaResizeEdge = 0;
        }

        if (leftDown && mediaDragging) {
            mediaWidgetX = mx - mediaDragOffX;
            mediaWidgetY = my - mediaDragOffY;

            int sw = getScreenWidth();
            int sh = getScreenHeight();
            mediaWidgetX = Math.max(0, Math.min(sw - ww, mediaWidgetX));
            mediaWidgetY = Math.max(0, Math.min(sh - wh, mediaWidgetY));
        }

        if (leftDown && mediaResizing) {
            if (mediaResizeEdge == 1 || mediaResizeEdge == 3) {
                float newW = mx - wx + 5;
                mediaWidgetTargetW = Math.max(MEDIA_MIN_W, Math.min(MEDIA_MAX_W, newW));
            }
            if (mediaResizeEdge == 2 || mediaResizeEdge == 3) {
                float newH = my - wy + 5;
                mediaWidgetTargetH = Math.max(MEDIA_MIN_H, Math.min(MEDIA_MAX_H, newH));
            }
        }
    }


