            hudNotifPos = new float[]{sw - 210, sh - 140, 200, 120};
        if (hudArrayListPos == null)
            hudArrayListPos = new float[]{sw - 150, 12, 140, 200};
        if (hudWatermarkPos == null)
            hudWatermarkPos = new float[]{2, 2, 120, 50};
        if (hudScoreboardPos == null)
            hudScoreboardPos = new float[]{6, sh / 2f - 80, 140, 160};
