    private static float[] getHudPos(int idx) {
        switch (idx) {
            case 0: return hudNotifPos;
            case 1: return hudArrayListPos;
            case 2: return hudWatermarkPos;
            case 3: return hudScoreboardPos;
            case 4: return new float[]{mediaWidgetX, mediaWidgetY, mediaWidgetW, mediaWidgetH};
            default: return null;
        }
    }

    private static void setHudPos(int idx, float x, float y, float w, float h) {
        switch (idx) {
            case 0: hudNotifPos = new float[]{x, y, w, h}; break;
            case 1: hudArrayListPos = new float[]{x, y, w, h}; break;
            case 2: hudWatermarkPos = new float[]{x, y, w, h}; break;
            case 3: hudScoreboardPos = new float[]{x, y, w, h}; break;
            case 4:
                mediaWidgetX = x;
                mediaWidgetY = y;
                mediaWidgetTargetW = w;
                mediaWidgetTargetH = h;
                mediaWidgetW = w;
                mediaWidgetH = h;
                break;
        }
    }

    private static String getHudModuleName(int idx) {
        switch (idx) {
            case 0: return "Notifications";
            case 1: return "ArrayList";
            case 2: return "Watermark";
            case 3: return "ScoreBoard";
            case 4: return "MediaActivity";
            default: return "Unknown";
        }
    }

    public static float getHudScale(int idx) {
        float[] pos = getHudPos(idx);
        if (pos == null) return 1.0f;
        float[] def;
        switch (idx) {
            case 0: def = NOTIF_DEFAULT_SIZE; break;
            case 1: def = ARRAYLIST_DEFAULT_SIZE; break;
            case 2: def = WATERMARK_DEFAULT_SIZE; break;
            case 3: def = SCOREBOARD_DEFAULT_SIZE; break;
            case 4: return pos[2] / 260.0f;
            default: return 1.0f;
        }
        float scaleW = pos[2] / def[0];
        float scaleH = pos[3] / def[1];
        return Math.min(scaleW, scaleH);
    }

