    public static void handleHudEditorMouse(int mouseX, int mouseY, int button) {
        if (!hudEditorMode) return;
        if (!hudEditorInitialized) initHudEditorPositions();


        float backX = 10, backY = 10, backW = 70, backH = 26;
        if (button == 0 && mouseX >= backX && mouseX <= backX + backW && mouseY >= backY && mouseY <= backY + backH) {
            hudEditorMode = false;
            hudDraggingIndex = -1;
            hudResizingIndex = -1;
            return;
        }


        int screenW = getScreenWidth();
        float saveX = screenW - 80, saveY = 10, saveW = 70, saveH = 26;
        if (button == 0 && mouseX >= saveX && mouseX <= saveX + saveW && mouseY >= saveY && mouseY <= saveY + saveH) {
            saveConfig(currentConfig != null && !currentConfig.isEmpty() ? currentConfig : DEFAULT_CONFIG);
            post("INFO", "HUD", "Positions saved!");
            return;
        }


        if (button == 0) {
            for (int i = 4; i >= 0; i--) {
                float[] pos = getHudPos(i);
                if (pos == null) continue;
                float ex = pos[0], ey = pos[1], ew = pos[2], eh = pos[3];

                float rz = 14;
                boolean inResizeZone = mouseX >= ex + ew - rz && mouseX <= ex + ew + 2
                        && mouseY >= ey + eh - rz && mouseY <= ey + eh + 2;
                boolean inside = mouseX >= ex && mouseX <= ex + ew && mouseY >= ey && mouseY <= ey + eh;

                if (inResizeZone) {
                    hudResizingIndex = i;
                    hudResizeEdge = 3;
                    return;
                } else if (inside) {
                    hudDraggingIndex = i;
                    hudDragOffX = mouseX - ex;
                    hudDragOffY = mouseY - ey;
                    return;
                }
            }
        }
    }

    public static void handleHudEditorMouseDrag(int mouseX, int mouseY) {
        if (!hudEditorMode) return;

        int sw = getScreenWidth();
        int sh = getScreenHeight();

        if (hudDraggingIndex >= 0 && hudDraggingIndex <= 4) {
            float[] pos = getHudPos(hudDraggingIndex);
            if (pos != null) {
                float nx = mouseX - hudDragOffX;
                float ny = mouseY - hudDragOffY;
                nx = Math.max(0, Math.min(sw - pos[2], nx));
                ny = Math.max(0, Math.min(sh - pos[3], ny));
                setHudPos(hudDraggingIndex, nx, ny, pos[2], pos[3]);
            }
        }

        if (hudResizingIndex >= 0 && hudResizingIndex <= 4) {
            float[] pos = getHudPos(hudResizingIndex);
            if (pos != null) {
                float newW = mouseX - pos[0] + 5;
                float newH = mouseY - pos[1] + 5;
                newW = Math.max(60, Math.min(500, newW));
                newH = Math.max(24, Math.min(400, newH));
                setHudPos(hudResizingIndex, pos[0], pos[1], newW, newH);
            }
        }
    }

    public static void handleHudEditorMouseRelease() {
        hudDraggingIndex = -1;
        hudResizingIndex = -1;
        hudResizeEdge = 0;
    }




