    private static void handleLiesPlusClick(int mouseX, int mouseY, int button) {
        if (button == 0 && isInside(lies_guiX, lies_guiY, lies_guiW, 20, mouseX, mouseY)) {
            isDraggingPanel = true;
            lies_dragOffsetX = mouseX - lies_guiX;
            lies_dragOffsetY = mouseY - lies_guiY;
        }

        float sidebarW = 130;
        float cy = lies_guiY + 55;
        List<String> cats = new ArrayList<>(new LinkedHashSet<>(moduleCategories));
        for (String c : cats) {
            if (button == 0 && isInside(lies_guiX, cy, sidebarW, 30, mouseX, mouseY)) {
                lies_selectedCategory = c;
                lies_targetScrollY = 0;
                lies_scrollY = 0;
                return;
            }
            cy += 30;
        }

        float contentX = lies_guiX + sidebarW + 15;
        float contentW = lies_guiW - sidebarW - 30;
        float contentY = lies_guiY + 20 + lies_scrollY;

        for (int i = 0; i < moduleNames.size(); i++) {
            if (!moduleCategories.get(i).equals(lies_selectedCategory) || isModuleHidden(moduleNames.get(i)))
                continue;

            float modH = (lies_expandedModule == i) ? getLiesPlusSettingsHeight(i) + 40 : 40;

            if (isInside(contentX, contentY, contentW, 40, mouseX, mouseY)) {
                if (button == 0) {
                    moduleEnabled.set(i, !moduleEnabled.get(i));
                    if (moduleEnabled.get(i)) {
                        if (moduleOnEnable.get(i) != null)
                            moduleOnEnable.get(i).run();
                    } else {
                        if (moduleOnDisable.get(i) != null)
                            moduleOnDisable.get(i).run();
                    }
                } else if (button == 1) {
                    lies_expandedModule = (lies_expandedModule == i) ? -1 : i;
                }
                return;
            }

            if (lies_expandedModule == i) {
                if (handleLiesPlusSettingClick(i, contentX + 15, contentY + 40, contentW - 30, mouseX, mouseY, button))
                    return;
            }

            contentY += modH + 12;
        }
    }

    private static boolean handleLiesPlusSettingClick(int modIdx, float x, float y, float w, int mouseX, int mouseY,
                                                      int button) {
        String modName = moduleNames.get(modIdx);
        float currentY = y;

        List<String> boolNames = moduleBooleanSettingNames.getOrDefault(modName, new ArrayList<>());
        List<Boolean> boolVals = moduleSettingsBooleans.getOrDefault(modName, new ArrayList<>());
        for (int i = 0; i < boolNames.size(); i++) {
            if (button == 0 && isInside(x, currentY, w, 32, mouseX, mouseY)) {
                moduleSettingsBooleans.get(modName).set(i, !boolVals.get(i));
                return true;
            }
            currentY += 32;
        }

        List<String> numNames = moduleSettingsNames.getOrDefault(modName, new ArrayList<>());
        for (int i = 0; i < numNames.size(); i++) {
            if (button == 0 && isInside(x, currentY, w, 32, mouseX, mouseY)) {
                draggingSliderModuleIndex = modIdx;
                draggingSliderSetting = numNames.get(i);
                return true;
            }
            currentY += 32;
        }

        List<List<String>> modeOpts = moduleModeOptions.getOrDefault(modName, new ArrayList<>());
        List<String> modeVals = moduleModeSettingValues.getOrDefault(modName, new ArrayList<>());
        for (int i = 0; i < modeOpts.size(); i++) {
            if (button == 0 && isInside(x, currentY, w, 32, mouseX, mouseY)) {
                List<String> opts = modeOpts.get(i);
                int idx = opts.indexOf(modeVals.get(i));
                if (idx != -1) {
                    moduleModeSettingValues.get(modName).set(i, opts.get((idx + 1) % opts.size()));
                }
                return true;
            }
            currentY += 32;
        }

        List<String> stringNames = moduleStringSettingNames.getOrDefault(modName, new ArrayList<>());
        for (int i = 0; i < stringNames.size(); i++) {
            if (button == 0 && isInside(x, currentY, w, 32, mouseX, mouseY)) {
                activeTextInputModuleIndex = modIdx;
                activeTextInputSetting = stringNames.get(i);
                return true;
            }
            currentY += 32;
        }

        return false;
    }




