    public static List<double[]> computePath(double x1, double y1, double z1, double x2, double y2, double z2) {
        List<double[]> path = new ArrayList<>();
        double dx = x2 - x1;
        double dy = y2 - y1;
        double dz = z2 - z1;
        double distance = Math.sqrt(dx * dx + dy * dy + dz * dz);

        double stepSize = 8.5;
        int steps = (int) (distance / stepSize);

        for (int i = 1; i <= steps; i++) {
            double ratio = (i * stepSize) / distance;
            path.add(new double[] { x1 + dx * ratio, y1 + dy * ratio, z1 + dz * ratio });
        }
        path.add(new double[] { x2, y2, z2 });
        return path;
    }


