    public static int[] getMouseOverBlockManual(double range) {
        Object player = getThePlayer();
        if (player == null)
            return null;

        double px = getPosX(player);
        double py = getPosY(player) + getEyeHeight(player);
        double pz = getPosZ(player);

        float yaw = getYaw(player);
        float pitch = getRotationPitch(player);

        double yawRad = Math.toRadians(-yaw - 180);
        double pitchRad = Math.toRadians(-pitch);

        double dirX = Math.sin(yawRad) * Math.cos(pitchRad);
        double dirY = Math.sin(pitchRad);
        double dirZ = Math.cos(yawRad) * Math.cos(pitchRad);

        double step = 0.1;

        for (double d = 0; d <= range; d += step) {
            double cx = px + dirX * d;
            double cy = py + dirY * d;
            double cz = pz + dirZ * d;

            int bx = (int) Math.floor(cx);
            int by = (int) Math.floor(cy);
            int bz = (int) Math.floor(cz);

            Object chunk = getChunkFromChunkCoords(bx >> 4, bz >> 4);
            if (chunk == null)
                continue;

            Object block = getBlock(chunk, bx & 15, by, bz & 15);
            int id = getIdFromBlock(block);

            if (id != 0) {
                return new int[] { bx, by, bz };
            }
        }

        return null;
    }

