    public static Object getClosestPlayerInRange(double maxRange, double minRange) {
        Object closest = null;
        double closestDist = maxRange + 1.0;

        for (Object entity : getPlayerEntitiesInWorld()) {
            if (entity == getThePlayer()) continue;
            if (isBot(entity)) continue;

            String name = getName(entity);
            if (name == null) continue;
            name = name.replaceAll("§.", "").trim();
            if (name.toUpperCase().contains("[CR]")) continue;

            double dist = distanceTo(entity);
            if (dist < minRange) continue;
            if (dist > maxRange) continue;
            if (dist < closestDist) {
                closestDist = dist;
                closest = entity;
            }
        }

        return closest;
    }

    public static Object getClosestPlayer(double range) {
        Object closest = null;
        double closestDist = range + 1.0;

        for (Object entity : getPlayerEntitiesInWorld()) {
            if (entity == getThePlayer())
                continue;
            if (isBot(entity))
                continue;

            String name = getName(entity);
            if (name == null)
                continue;
            name = name.replaceAll("§.", "").trim();
            if (name.toUpperCase().contains("[CR]"))
                continue;

            double dist = distanceTo(entity);
            if (dist < closestDist) {
                closestDist = dist;
                closest = entity;
            }
        }

        return closest;
    }


    public static void sendAttackUpdate() {
        if (getPlayer() == null || getWorldObj() == null)
            return;

        double range = getSettingValue("SendAttack", "Range");
        Object closestEntity = null;
        double closestDist = range;

        for (Object entity : getPlayerEntitiesInWorld()) {
            if (entity == getPlayer() || !isValidTarget(entity))
                continue;

            double dist = GL11.distanceTo(entity);
            if (dist <= range && dist < closestDist) {
                closestDist = dist;
                closestEntity = entity;
            }
        }

        if (closestEntity != null) {
            try {
                sendSwing();
                attackEntity(closestEntity);
            } catch (Exception e) {
                e.printStackTrace();
            }
        }
    }


