    public static float getHungerLevel(Object player) {
        try {
            java.lang.reflect.Method[] methods = player.getClass().getMethods();
            Object foodStats = null;
            for (java.lang.reflect.Method m : methods) {
                if (m.getParameterCount() == 0) {
                    Class<?> retType = m.getReturnType();
                    if (retType != null && !retType.isPrimitive()
                            && !retType.getName().startsWith("java.")) {
                        try {
                            Object result = m.invoke(player);
                            if (result != null) {
                                java.lang.reflect.Method[] fsMethods = result.getClass().getMethods();
                                int intMethodCount = 0;
                                for (java.lang.reflect.Method fm : fsMethods) {
                                    if (fm.getParameterCount() == 0
                                            && fm.getReturnType() == int.class) {
                                        intMethodCount++;
                                    }
                                }
                                if (intMethodCount >= 2) {
                                    foodStats = result;
                                    break;
                                }
                            }
                        } catch (Exception ignored) {
                        }
                    }
                }
            }
            if (foodStats != null) {
                for (java.lang.reflect.Method fm : foodStats.getClass().getMethods()) {
                    if (fm.getParameterCount() == 0 && fm.getReturnType() == int.class) {
                        try {
                            int val = (int) fm.invoke(foodStats);
                            if (val >= 0 && val <= 20) {
                                return (float) val;
                            }
                        } catch (Exception ignored) {
                        }
                    }
                }
            }
        } catch (Exception e) {
        }
        return 20.0f;
    }


