    private static java.util.List<float[]> chatLines = new java.util.ArrayList<>();
    private static java.util.List<Object[]> chatTexts = new java.util.ArrayList<>();
    private static boolean chatActive = false;

    public static void chatStart() {
        chatLines.clear();
        chatTexts.clear();
        chatActive = true;
    }

    public static int chatText(Object fontRenderer, String text, float x, float y, int color) {
        if (chatActive) {
            float width = getStringWidth(text);
            chatLines.add(new float[] { x, y, width });
            chatTexts.add(new Object[] { text, x, y, color });
        }
        return 0;
    }

    public static void chatEnd() {
        if (!chatActive)
            return;
        chatActive = false;

        if (chatTexts.isEmpty())
            return;

        org.lwjgl.opengl.GL11.glPushAttrib(1048575);
        org.lwjgl.opengl.GL11.glPushMatrix();

        try {
            org.lwjgl.opengl.GL11.glEnable(org.lwjgl.opengl.GL11.GL_TEXTURE_2D);
            org.lwjgl.opengl.GL11.glEnable(org.lwjgl.opengl.GL11.GL_BLEND);
            org.lwjgl.opengl.GL11.glBlendFunc(
                    org.lwjgl.opengl.GL11.GL_SRC_ALPHA,
                    org.lwjgl.opengl.GL11.GL_ONE_MINUS_SRC_ALPHA);
            org.lwjgl.opengl.GL11.glColor4f(1f, 1f, 1f, 1f);

            if (isModuleEnabled("CustomChat")) {

                float minX = Float.MAX_VALUE;
                float minY = Float.MAX_VALUE;
                float maxY = Float.MIN_VALUE;

                for (Object[] txt : chatTexts) {
                    float x = (Float) txt[1];
                    float y = (Float) txt[2];

                    if (x < minX)
                        minX = x;
                    if (y < minY)
                        minY = y;
                    if (y + 9 > maxY)
                        maxY = y + 9;
                }

                float fixedWidth = 320f;
                float leftOffset = 8f;
                float textPadding = 6f;
                float padY = 3f;

                float rx = minX + leftOffset;
                float ry = minY - padY;
                float rw = fixedWidth;
                float rh = (maxY - minY) + (padY * 2);

                roundedRect(rx, ry, rw, rh, 10.0, new java.awt.Color(0, 0, 0, 70));

                for (Object[] txt : chatTexts) {
                    txt[1] = rx + textPadding;
                }
            }

            for (Object[] txt : chatTexts) {
                String text = (String) txt[0];
                float x = (Float) txt[1];
                float y = (Float) txt[2];
                int color = (Integer) txt[3];

                drawText(text, x, y, color);
            }

        } finally {
            org.lwjgl.opengl.GL11.glPopMatrix();
            org.lwjgl.opengl.GL11.glPopAttrib();
        }

        chatLines.clear();
        chatTexts.clear();
    }


