    private static final byte NBT_END       = 0;
    private static final byte NBT_BYTE      = 1;
    private static final byte NBT_SHORT     = 2;
    private static final byte NBT_INT       = 3;
    private static final byte NBT_LONG      = 4;
    private static final byte NBT_FLOAT     = 5;
    private static final byte NBT_DOUBLE    = 6;
    private static final byte NBT_BYTEARRAY = 7;
    private static final byte NBT_STRING    = 8;
    private static final byte NBT_LIST      = 9;
    private static final byte NBT_COMPOUND  = 10;
    private static final byte NBT_INTARRAY  = 11;
    private static final byte NBT_LONGARRAY = 12;

    private static String nbtReadString(java.io.DataInputStream dis) throws IOException {
        int len = dis.readUnsignedShort();
        byte[] bytes = new byte[len];
        dis.readFully(bytes);
        return new String(bytes, StandardCharsets.UTF_8);
    }

    private static Object nbtReadPayload(java.io.DataInputStream dis, byte tagType) throws IOException {
        switch (tagType) {
            case NBT_BYTE:      return dis.readByte();
            case NBT_SHORT:     return dis.readShort();
            case NBT_INT:       return dis.readInt();
            case NBT_LONG:      return dis.readLong();
            case NBT_FLOAT:     return dis.readFloat();
            case NBT_DOUBLE:    return dis.readDouble();
            case NBT_BYTEARRAY: {
                int len = dis.readInt();
                byte[] arr = new byte[len];
                dis.readFully(arr);
                return arr;
            }
            case NBT_STRING:    return nbtReadString(dis);
            case NBT_INTARRAY: {
                int len = dis.readInt();
                int[] arr = new int[len];
                for (int i = 0; i < len; i++) arr[i] = dis.readInt();
                return arr;
            }
            case NBT_LONGARRAY: {
                int len = dis.readInt();
                long[] arr = new long[len];
                for (int i = 0; i < len; i++) arr[i] = dis.readLong();
                return arr;
            }
            case NBT_LIST: {
                byte elemType = dis.readByte();
                int size = dis.readInt();
                List<Object> list = new ArrayList<>(size);
                for (int i = 0; i < size; i++) {
                    list.add(nbtReadPayload(dis, elemType));
                }
                return list;
            }
            case NBT_COMPOUND: {
                Map<String, Object> map = new LinkedHashMap<>();
                while (true) {
                    byte childType = dis.readByte();
                    if (childType == NBT_END) break;
                    String name = nbtReadString(dis);
                    Object value = nbtReadPayload(dis, childType);
                    map.put(name, value);
                }
                return map;
            }
            default:
                throw new IOException("Bilinmeyen NBT tag tipi: " + tagType);
        }
    }

    @SuppressWarnings("unchecked")
    private static Map<String, Object> nbtReadFile(String path) throws IOException {
        try (java.io.FileInputStream fis = new java.io.FileInputStream(path);
             java.util.zip.GZIPInputStream gzip = new java.util.zip.GZIPInputStream(fis);
             java.io.DataInputStream dis = new java.io.DataInputStream(gzip)) {

            byte rootType = dis.readByte();
            if (rootType != NBT_COMPOUND) {
                throw new IOException("Kök tag Compound değil: " + rootType);
            }

            nbtReadString(dis);

            Object root = nbtReadPayload(dis, NBT_COMPOUND);

            return (Map<String, Object>) root;
        }
    }



