    private static final String[] MC_COLOR_NAMES = {"white","orange","magenta","light_blue","yellow","lime","pink","gray","light_gray","cyan","purple","blue","brown","green","red","black"};
    @SuppressWarnings("unchecked")
    private static String resolveColoredBlock(String name, Map<String, Object> props) {
        if (name == null || props == null) return null;
        String base = name.replace("minecraft:", "");
        if (base.equals("wool") || base.equals("carpet") || base.equals("stained_hardened_clay") ||
                base.equals("concrete") || base.equals("concrete_powder") || base.equals("stained_glass")) {
            Object colorObj = props.get("color");
            if (colorObj != null) {
                String color = colorObj.toString();
                try {
                    int idx = Integer.parseInt(color);
                    if (idx >= 0 && idx < MC_COLOR_NAMES.length) color = MC_COLOR_NAMES[idx];
                } catch (NumberFormatException e) {}
                String type = base;
                if (type.equals("stained_hardened_clay")) type = "terracotta";
                return "minecraft:" + color + "_" + type;
            }
        }
        return null;
    }

    private static int paletteColorStringToDyeIndex(String colorStr) {
        if (colorStr == null) return 0;
        colorStr = colorStr.toLowerCase(java.util.Locale.ROOT).trim();
        try {
            int n = Integer.parseInt(colorStr);
            if (n >= 0 && n < 16) return n;
        } catch (NumberFormatException ignored) {}
        if ("silver".equals(colorStr)) colorStr = "light_gray";
        for (int i = 0; i < MC_COLOR_NAMES.length; i++) {
            if (MC_COLOR_NAMES[i].equals(colorStr)) return i;
        }
        return 0;
    }

