    private static float[] schematicGetBlockUV(int id, int meta) {
        if (!schematicRendererInitialized) schematicSetupRenderer();
        if (m_getBlockById == null || m_getParticleTexture == null || blockRendererDispatcher_instance == null) return null;
        int effectiveMeta = meta;
        if (id == 175) effectiveMeta = meta & 7;
        int cacheKey = (id << 4) | effectiveMeta;
        if (schematicUVBuffer.containsKey(cacheKey)) {
            float[] cached = schematicUVBuffer.get(cacheKey);
            return (cached != null && cached.length == 4) ? cached : null;
        }
        try {
            Object block = m_getBlockById.invoke(null, id);
            if (block == null) { schematicUVBuffer.put(cacheKey, new float[0]); return null; }
            Object state = m_getStateFromMeta.invoke(block, effectiveMeta);
            if (state == null) { schematicUVBuffer.put(cacheKey, new float[0]); return null; }
            Object model = m_getModelForState.invoke(blockRendererDispatcher_instance, state);
            if (model == null) { schematicUVBuffer.put(cacheKey, new float[0]); return null; }
            Object sprite = m_getParticleTexture.invoke(model);
            if (sprite == null) { schematicUVBuffer.put(cacheKey, new float[0]); return null; }

            float[] uvs = new float[4];
            if (m_textureUVs.length >= 4) {
                float f1 = (Float)m_textureUVs[0].invoke(sprite);
                float f2 = (Float)m_textureUVs[1].invoke(sprite);
                float f3 = (Float)m_textureUVs[2].invoke(sprite);
                float f4 = (Float)m_textureUVs[3].invoke(sprite);
                uvs[0] = Math.min(f1, f2);
                uvs[1] = Math.max(f1, f2);
                uvs[2] = Math.min(f3, f4);
                uvs[3] = Math.max(f3, f4);
            }

            schematicUVBuffer.put(cacheKey, uvs);
            return uvs;
        } catch(Exception e) {
            schematicUVBuffer.put(cacheKey, new float[0]);
            return null;
        }
    }
    private static double schematicRayAABB(double ox, double oy, double oz,
                                           double dx, double dy, double dz,
                                           double x0, double y0, double z0,
                                           double x1, double y1, double z1) {
        double tmin, tmax, tymin, tymax, tzmin, tzmax;
        if (Math.abs(dx) < 1e-8) {
            if (ox < x0 || ox > x1) return -1;
            tmin = Double.NEGATIVE_INFINITY; tmax = Double.POSITIVE_INFINITY;
        } else {
            tmin = (x0 - ox) / dx; tmax = (x1 - ox) / dx;
            if (tmin > tmax) { double t = tmin; tmin = tmax; tmax = t; }
        }
        if (Math.abs(dy) < 1e-8) {
            if (oy < y0 || oy > y1) return -1;
            tymin = Double.NEGATIVE_INFINITY; tymax = Double.POSITIVE_INFINITY;
        } else {
            tymin = (y0 - oy) / dy; tymax = (y1 - oy) / dy;
            if (tymin > tymax) { double t = tymin; tymin = tymax; tymax = t; }
        }
        if (tmin > tymax || tymin > tmax) return -1;
        if (tymin > tmin) tmin = tymin;
        if (tymax < tmax) tmax = tymax;
        if (Math.abs(dz) < 1e-8) {
            if (oz < z0 || oz > z1) return -1;
            tzmin = Double.NEGATIVE_INFINITY; tzmax = Double.POSITIVE_INFINITY;
        } else {
            tzmin = (z0 - oz) / dz; tzmax = (z1 - oz) / dz;
            if (tzmin > tzmax) { double t = tzmin; tzmin = tzmax; tzmax = t; }
        }
        if (tmin > tzmax || tzmin > tmax) return -1;
        if (tzmin > tmin) tmin = tzmin;
        return tmin >= 0 ? tmin : -1;
    }





    private static boolean bakedRendererInit = false;
    private static java.lang.reflect.Method m_getFaceQuads;
    private static java.lang.reflect.Method m_getGeneralQuads;
    private static java.lang.reflect.Method m_getQuads3;
    private static Class<?> enumFacingClass;
    private static Object[] enumFacingValues;
    private static java.lang.reflect.Method m_quadVertexDataMethod;
    private static java.lang.reflect.Field f_quadVertexDataField;
    private static java.lang.reflect.Method m_quadGetFace;
    private static java.lang.reflect.Method m_quadGetTintIdx;
    private static boolean quadClassFound = false;
    private static int bakedVertexStride = 7;
    private static final Map<Integer, float[][]> bakedModelCache = new ConcurrentHashMap<>();

    private static void initBakedRenderer() {
        if (bakedRendererInit) return;
        if (!schematicRendererInitialized) schematicSetupRenderer();
        if (m_getModelForState == null) return;
        try {
            Class<?> bmc = m_getModelForState.getReturnType();

            for (java.lang.reflect.Method m : bmc.getDeclaredMethods()) {
                if (!java.util.List.class.isAssignableFrom(m.getReturnType())) continue;
                for (Class<?> pt : m.getParameterTypes()) {
                    if (pt.isEnum()) {
                        Object[] ec = pt.getEnumConstants();
                        if (ec != null && ec.length == 6) { enumFacingClass = pt; enumFacingValues = ec; break; }
                    }
                }
                if (enumFacingClass != null) break;
            }
            if (enumFacingClass == null) {

                if (m_getStateFromMeta != null) {
                    Class<?> stateClass = m_getStateFromMeta.getReturnType();
                    for (java.lang.reflect.Method m : bmc.getDeclaredMethods()) {
                        Class<?>[] pts = m.getParameterTypes();
                        if (java.util.List.class.isAssignableFrom(m.getReturnType()) && pts.length >= 2) {
                            for (Class<?> pt : pts) {
                                if (pt.isEnum() && pt.getEnumConstants().length == 6) {
                                    enumFacingClass = pt; enumFacingValues = pt.getEnumConstants(); break;
                                }
                            }
                        }
                        if (enumFacingClass != null) break;
                    }
                }
            }
            System.out.println("[BakedModel] EnumFacing=" + enumFacingClass);
            if (enumFacingClass == null) return;


            for (java.lang.reflect.Method m : bmc.getDeclaredMethods()) {
                if (!java.util.List.class.isAssignableFrom(m.getReturnType())) continue;
                Class<?>[] pts = m.getParameterTypes();
                if (pts.length == 1 && pts[0] == enumFacingClass) {
                    m_getFaceQuads = m; m_getFaceQuads.setAccessible(true);
                } else if (pts.length == 0 && m_getGeneralQuads == null) {

                    m_getGeneralQuads = m; m_getGeneralQuads.setAccessible(true);
                } else if (pts.length >= 2) {
                    boolean hasEnum = false;
                    for (Class<?> pt : pts) if (pt == enumFacingClass) hasEnum = true;
                    if (hasEnum) { m_getQuads3 = m; m_getQuads3.setAccessible(true); }
                }
            }
            System.out.println("[BakedModel] getFaceQuads=" + m_getFaceQuads + " getGeneralQuads=" + m_getGeneralQuads + " getQuads3=" + m_getQuads3);

            if (enumFacingClass != null && (m_getFaceQuads != null || m_getQuads3 != null)) {
                bakedRendererInit = true;
            }
        } catch (Exception e) {
            System.out.println("[BakedModel] Init error: " + e.getMessage());
            e.printStackTrace();
        }
    }

    private static void discoverQuadStructure(Object quad) {
        if (quadClassFound) return;
        try {
            Class<?> qc = quad.getClass();

            for (java.lang.reflect.Method m : qc.getMethods()) {
                if (m.getReturnType() == int[].class && m.getParameterTypes().length == 0) {
                    m_quadVertexDataMethod = m; m.setAccessible(true); break;
                }
            }

            if (m_quadVertexDataMethod == null) {
                for (java.lang.reflect.Field f : qc.getDeclaredFields()) {
                    if (f.getType() == int[].class) { f.setAccessible(true); f_quadVertexDataField = f; break; }
                }
            }

            for (java.lang.reflect.Method m : qc.getMethods()) {
                if (m.getReturnType() == enumFacingClass && m.getParameterTypes().length == 0) {
                    m_quadGetFace = m; m.setAccessible(true); break;
                }
            }

            for (java.lang.reflect.Method m : qc.getMethods()) {
                if (m.getReturnType() == int.class && m.getParameterTypes().length == 0) {
                    String nm = m.getName();
                    if (nm.contains("int") || nm.contains("Tint") || nm.contains("tint")) {
                        m_quadGetTintIdx = m; m.setAccessible(true); break;
                    }
                }
            }

            int[] vd = getQuadVD(quad);
            if (vd != null && vd.length > 0) {
                bakedVertexStride = vd.length / 4;
                if (bakedVertexStride < 7) bakedVertexStride = 7;
            }
            System.out.println("[BakedModel] QuadClass=" + qc.getSimpleName() +
                    " vertexMethod=" + m_quadVertexDataMethod + " vertexField=" + f_quadVertexDataField +
                    " getFace=" + m_quadGetFace + " getTint=" + m_quadGetTintIdx + " stride=" + bakedVertexStride);
        } catch (Exception e) { e.printStackTrace(); }
        quadClassFound = true;
    }

    private static int[] getQuadVD(Object q) {
        try {
            if (m_quadVertexDataMethod != null) return (int[]) m_quadVertexDataMethod.invoke(q);
            if (f_quadVertexDataField != null) return (int[]) f_quadVertexDataField.get(q);
        } catch (Exception e) {}
        return null;
    }

    private static int getQuadFace(Object q) {
        try {
            if (m_quadGetFace != null) {
                Object f = m_quadGetFace.invoke(q);
                if (f != null) for (int i = 0; i < enumFacingValues.length; i++) if (f == enumFacingValues[i]) return i;
            }
        } catch (Exception e) {}
        return -1;
    }

    private static float[] convertQuad(Object quad, int defaultFace) {
        if (!quadClassFound) discoverQuadStructure(quad);
        int[] vd = getQuadVD(quad);
        if (vd == null || vd.length < bakedVertexStride * 4) return null;
        int face = getQuadFace(quad);
        if (face == -1) face = defaultFace;
        float[] out = new float[21];
        for (int v = 0; v < 4; v++) {
            int b = v * bakedVertexStride;
            out[v*5]   = Float.intBitsToFloat(vd[b]);
            out[v*5+1] = Float.intBitsToFloat(vd[b+1]);
            out[v*5+2] = Float.intBitsToFloat(vd[b+2]);
            out[v*5+3] = Float.intBitsToFloat(vd[b+4]);
            out[v*5+4] = Float.intBitsToFloat(vd[b+5]);
        }
        out[20] = face;
        return out;
    }

    /** IProperty nesnesinin adını döndürür (getName() veya toString() ile). */
    private static String getPropertyName(Object propKey) {
        if (propKey == null) return "";
        // Önce getName() metodunu dene (IProperty interface'inde tanımlı)
        try {
            java.lang.reflect.Method getName = propKey.getClass().getMethod("getName");
            Object result = getName.invoke(propKey);
            if (result instanceof String) return (String) result;
        } catch (Exception ignored) {}
        // Fallback: tüm String döndüren parametresiz metodları dene
        for (java.lang.reflect.Method pm : propKey.getClass().getMethods()) {
            if (pm.getParameterTypes().length == 0 && pm.getReturnType() == String.class) {
                String mn = pm.getName();
                if ("toString".equals(mn) || "getClass".equals(mn)) continue;
                try {
                    pm.setAccessible(true);
                    String val = (String) pm.invoke(propKey);
                    if (val != null && !val.isEmpty()) return val;
                } catch (Exception ignored) {}
            }
        }
        return "";
    }

