    private static final float[] BAKED_FACE_BR = {0.5f, 1.0f, 0.8f, 0.8f, 0.6f, 0.6f};

    public static boolean mRenderBakedModel(int blockId, int meta, int lowerMetaForUpperDoor, double rx, double ry, double rz,
                                            float alpha, float tintR, float tintG, float tintB,
                                            boolean[] skipFaces) {
        if (!bakedRendererInit) initBakedRenderer();
        if (blockId <= 0) return false;
        if (blockAtlasTextureId <= 0) return false;
        if (m_getFaceQuads == null && m_getQuads3 == null) return false;

        float[][] quads = getBakedQuads(blockId, meta, lowerMetaForUpperDoor);
        if (quads == null || quads.length == 0) return false;

        GL11.glEnable(GL11.GL_TEXTURE_2D);
        GL11.glBindTexture(GL11.GL_TEXTURE_2D, blockAtlasTextureId);

        GL11.glEnable(0x8037);
        GL11.glPolygonOffset(-1.0f, -1.0f);

        for (float[] q : quads) {
            if (q == null || q.length < 21) continue;
            int faceIdx = (int) q[20];


            if (skipFaces != null && faceIdx >= 0 && faceIdx < 6 && skipFaces[faceIdx]) continue;

            float br = (faceIdx >= 0 && faceIdx < 6) ? BAKED_FACE_BR[faceIdx] : 0.8f;
            GL11.glColor4f(tintR * br, tintG * br, tintB * br, alpha);

            GL11.glBegin(GL11.GL_QUADS);
            for (int v = 0; v < 4; v++) {
                GL11.glTexCoord2f(q[v*5+3], q[v*5+4]);
                GL11.glVertex3d(rx + q[v*5], ry + q[v*5+1], rz + q[v*5+2]);
            }
            GL11.glEnd();
        }
        GL11.glDisable(0x8037);
        return true;
    }

    public static boolean mRenderBakedModel(int blockId, int meta, int otherHalfMeta, double rx, double ry, double rz,
                                            float alpha, float tintR, float tintG, float tintB) {
        return mRenderBakedModel(blockId, meta, otherHalfMeta, rx, ry, rz, alpha, tintR, tintG, tintB, null);
    }

