    private static long packChunkKey(int cx, int cy, int cz) {
        return ((long)(cx & 0xFFFFF) << 40) | ((long)(cy & 0xFFFFF) << 20) | (long)(cz & 0xFFFFF);
    }
    private static int unpackChunkX(long key) {
        int v = (int)((key >> 40) & 0xFFFFF);
        return (v & 0x80000) != 0 ? v | 0xFFF00000 : v; // sign-extend
    }
    private static int unpackChunkY(long key) {
        int v = (int)((key >> 20) & 0xFFFFF);
        return (v & 0x80000) != 0 ? v | 0xFFF00000 : v;
    }
    private static int unpackChunkZ(long key) {
        int v = (int)(key & 0xFFFFF);
        return (v & 0x80000) != 0 ? v | 0xFFF00000 : v;
    }
