    private static void handleClipboardPaste() {
        try {
            if (clipboardBlocks.isEmpty()) {
                addChatMessage("§c[Schematic] §fKopyalanmış veri yok! Önce §e.pos1 §fve §e.pos2 §fkullan.");
                return;
            }
            Object player = getThePlayer();
            if (player == null) { addChatMessage("§c[Schematic] §fOyuncu yok!"); return; }


            schematicBlocks.clear();
            schematicBlockNames.clear();
            schematicBlockIds.clear();
            schematicBlockMetas.clear();
            schematicPlaced.clear();
            schematicPlaceAttempts.clear();


            for (int i = 0; i < clipboardBlocks.size(); i++) {
                int[] cb = clipboardBlocks.get(i);

                schematicBlocks.add(new int[]{cb[0], cb[1], cb[2], cb[3], cb[4], cb[5]});
                schematicBlockNames.add(i < clipboardBlockNames.size() ? clipboardBlockNames.get(i) : "Unknown");
                schematicBlockIds.add(cb.length > 6 ? cb[6] : 1);
                schematicBlockMetas.add(cb.length > 7 ? cb[7] : 0);
            }


            schematicOriginX = (int) Math.floor(getPosX(player));
            schematicOriginY = (int) Math.floor(getPosY(player));
            schematicOriginZ = (int) Math.floor(getPosZ(player));
            schematicOriginSet = true;
            schematicRotation = 0;
            clipboardPasteActive = true;


            if (!isModuleEnabled("Schematic")) {
                int modIdx = moduleNames.indexOf("Schematic");
                if (modIdx >= 0) moduleEnabled.set(modIdx, true);
            }

            addChatMessage("§a[Schematic] §fYapıştırıldı: §e"
                    + schematicOriginX + ", " + schematicOriginY + ", " + schematicOriginZ
                    + " §7(" + schematicBlocks.size() + " blok)");
            addChatMessage("§7Temizlemek için: §e.schematic clear");
        } catch (Exception e) { e.printStackTrace(); }
    }

