    private static Method cachedGetItemMethod = null;
    private static Method cachedGetBlockFromItem = null;
    private static Method cachedGetIdFromBlock = null;
    private static Method cachedGetIdFromItem = null;
    private static boolean autoPlaceMethodsInit = false;

    private static int getBlockIdFromStack(Object stack) {
        if (stack == null) return 0;
        try {
            if (!autoPlaceMethodsInit) {
                autoPlaceMethodsInit = true;
                Class<?> itemStackClass = get("ItemStack");
                Class<?> itemClass = get("Item");
                Class<?> blockClass = get("Block");
                if (itemStackClass == null || itemClass == null || blockClass == null) return 0;


                for (Method m : itemStackClass.getDeclaredMethods()) {
                    if (m.getParameterCount() == 0 && itemClass.isAssignableFrom(m.getReturnType())) {
                        m.setAccessible(true); cachedGetItemMethod = m; break;
                    }
                }

                for (Method m : blockClass.getDeclaredMethods()) {
                    if (java.lang.reflect.Modifier.isStatic(m.getModifiers()) &&
                            m.getParameterCount() == 1 && itemClass.isAssignableFrom(m.getParameterTypes()[0]) &&
                            blockClass.isAssignableFrom(m.getReturnType())) {
                        m.setAccessible(true); cachedGetBlockFromItem = m; break;
                    }
                }

                cachedGetIdFromBlock = getMethod("Block.getIdFromBlock");

                for (Method m : itemClass.getDeclaredMethods()) {
                    if (java.lang.reflect.Modifier.isStatic(m.getModifiers()) &&
                            m.getParameterCount() == 1 && itemClass.isAssignableFrom(m.getParameterTypes()[0]) &&
                            m.getReturnType() == int.class) {
                        m.setAccessible(true); cachedGetIdFromItem = m; break;
                    }
                }
            }
            if (cachedGetItemMethod == null) return 0;
            Object item = cachedGetItemMethod.invoke(stack);
            if (item == null) return 0;


            if (cachedGetBlockFromItem != null && cachedGetIdFromBlock != null) {
                Object block = cachedGetBlockFromItem.invoke(null, item);
                if (block != null) {
                    int id = (int) cachedGetIdFromBlock.invoke(null, block);
                    if (id > 0) return id;
                }
            }

            if (cachedGetIdFromItem != null) {
                int id = (int) cachedGetIdFromItem.invoke(null, item);
                if (id > 0) return id;
            }

            return 0;
        } catch (Exception e) { return 0; }
    }

    private static int getInventoryMetaForBlock(int blockId, int worldMeta) {
        if (blockId == 17 || blockId == 162 || blockId == 18 || blockId == 161) {
            return worldMeta & 3;
        }
        if (blockId == 44 || blockId == 126 || blockId == 182) {
            return worldMeta & 7;
        }
        if (blockId == 53 || blockId == 67 || blockId == 108 || blockId == 109 ||
                blockId == 114 || blockId == 128 || blockId == 134 || blockId == 135 ||
                blockId == 136 || blockId == 156 || blockId == 163 || blockId == 164 || blockId == 180) {
            return 0;
        }
        if (blockId == 50 || blockId == 75 || blockId == 76 || blockId == 69 || blockId == 77 || blockId == 143) {
            return 0;
        }
        if (blockId >= 235 && blockId <= 250) {
            return 0;
        }
        if (blockId == 198) {
            return 0;
        }
        if (blockId == 63 || blockId == 68) {
            return 0;
        }
        if (blockId == 118 || blockId == 117 || blockId == 140 || blockId == 144) {
            return 0;
        }
        if (blockId == 29 || blockId == 33 || blockId == 218) {
            return 0;
        }
        if (blockId == 23 || blockId == 54 || blockId == 61 || blockId == 62 || blockId == 158 || blockId == 146 || blockId == 154) {
            return 0;
        }
        // Kapılar: envanterde meta=0 (yön bilgisi yok)
        if (blockId == 64 || blockId == 71 || (blockId >= 193 && blockId <= 197)) {
            return 0;
        }
        // Yatak: üst 4 bit = renk/tür (özel sunucu: meta=0x11 → renk=1, yön=1)
        if (blockId == 26) {
            return (worldMeta >> 4) & 0xF;
        }
        // Redstone wire: envanterde meta=0
        if (blockId == 55) {
            return 0;
        }
        // Repeater/Comparator: envanterde meta=0
        if (blockId == 93 || blockId == 94) return 0;
        if (blockId == 149 || blockId == 150) return 0;
        // Pumpkin (yönlü): envanterde meta=0
        if (blockId == 86 || blockId == 91) return 0;
        // Nilüfer (lily pad): envanterde her zaman meta=0 (rotasyon yok)
        if (blockId == 111) return 0;
        // Çift bitki (double plant 175): sadece varyant bitleri (0-2), üst yarı biti (8) olmadan
        if (blockId == 175) return worldMeta & 7;
        return worldMeta;
    }

    private static boolean stackMetaMatches(Object stack, int targetMeta) {
        if (targetMeta == 0 && stack == null) return true;
        if (stack == null) return false;
        try {

            String s = stack.toString().toLowerCase();
            int atIndex = s.lastIndexOf('@');
            if (atIndex != -1) {
                try {
                    int strMeta = Integer.parseInt(s.substring(atIndex + 1));
                    return strMeta == targetMeta;
                } catch (Exception ignored) {}
            }


            for (Method m : stack.getClass().getDeclaredMethods()) {
                if (m.getReturnType() == int.class && m.getParameterCount() == 0) {
                    m.setAccessible(true);
                    String name = m.getName().toLowerCase();


                    if (name.contains("damage") || name.contains("meta")) {
                        int v = (int) m.invoke(stack);
                        return v == targetMeta;
                    }
                }
            }
        } catch (Exception e) {}
        return false;
    }

    private static int findBlockInHotbar(int targetBlockId, int targetMeta) {
        try {
            Object inventory = getInventory();
            if (inventory == null) return -1;
            Field mainInvField = getField("InventoryPlayer.mainInventory");
            if (mainInvField == null) return -1;
            mainInvField.setAccessible(true);
            Object[] mainInv = (Object[]) mainInvField.get(inventory);
            if (mainInv == null) return -1;

            int bestSlot = -1;
            int expectedItemMeta = getInventoryMetaForBlock(targetBlockId, targetMeta);

            for (int i = 0; i < 9 && i < mainInv.length; i++) {
                Object stack = mainInv[i];
                if (stack == null) continue;
                int bid = getBlockIdFromStack(stack);

                // Fallback: item adından blok ID tahmini
                if (bid == 0) {
                    String s = stack.toString().toLowerCase();
                    if (s.contains("cauldron")) bid = 380;
                    else if (s.contains("brewing")) bid = 379;
                    else if (s.contains("sign")) bid = 323;
                    else if (s.contains("cake")) bid = 354;
                    else if (s.contains("skull") || s.contains("head")) bid = 397;
                    else if (s.contains("flower_pot") || s.contains("flowerpot")) bid = 390;
                    else if (s.contains("reeds") || s.contains("sugar")) bid = 338;
                    else if (s.contains("diode") || s.contains("repeater")) bid = 356;
                    else if (s.contains("comparator")) bid = 404;
                    else if (s.contains("bed")) bid = 355;
                    else if (s.contains("water_bucket") || s.contains("water bucket") || (s.contains("bucket") && s.contains("water"))) bid = 326;
                    else if (s.contains("lava_bucket") || s.contains("lava bucket") || (s.contains("bucket") && s.contains("lava"))) bid = 327;
                    else if (s.contains("lily_pad") || s.contains("lily") || s.contains("waterlily")) bid = 111;
                    else if (s.contains("redstone") && !s.contains("torch") && !s.contains("lamp") && !s.contains("ore") && !s.contains("block") && !s.contains("repeater") && !s.contains("comparator")) bid = 331;
                    else if (s.contains("oak_door") || (s.contains("door") && s.contains("oak"))) bid = 324;
                    else if (s.contains("iron_door") || (s.contains("door") && s.contains("iron"))) bid = 330;
                    else if (s.contains("spruce_door") || (s.contains("door") && s.contains("spruce"))) bid = 427;
                    else if (s.contains("birch_door") || (s.contains("door") && s.contains("birch"))) bid = 428;
                    else if (s.contains("jungle_door") || (s.contains("door") && s.contains("jungle"))) bid = 429;
                    else if (s.contains("acacia_door") || (s.contains("door") && s.contains("acacia"))) bid = 430;
                    else if (s.contains("dark_oak_door") || (s.contains("door") && s.contains("dark"))) bid = 431;
                }

                boolean idMatch = (bid == targetBlockId);

                if (idMatch) {
                    if (stackMetaMatches(stack, expectedItemMeta)) {
                        return i;
                    }
                    if (bid == 35 || bid == 159 || bid == 95 || bid == 160 || bid == 172 || bid == 351 ||
                            bid == 38 || bid == 31 || bid == 175 || bid == 17 || bid == 162 || bid == 6) {
                        continue;
                    }
                    if (bestSlot == -1) bestSlot = i;
                }
            }
            return bestSlot;
        } catch (Exception e) { return -1; }
    }

    private static int getRotatedFace(int face, int rotation) {
        if (face <= 1) return face;
        int steps = (rotation / 90) % 4;
        int current = face;
        for (int k = 0; k < steps; k++) {
            if (current == 5) current = 3;
            else if (current == 3) current = 4;
            else if (current == 4) current = 2;
            else if (current == 2) current = 5;
        }
        return current;
    }

