    private static void spoofInteraction(int tx, int ty, int tz, int face, int slot) {
        try {
            Object heldItem = getHeldItem();
            Object inventory = getInventory();
            Object player = getThePlayer();
            java.lang.reflect.Field currentItemField = getField("InventoryPlayer.currentItem");

            int oldSlot = -1;
            if (currentItemField != null && inventory != null) {
                currentItemField.setAccessible(true);
                oldSlot = currentItemField.getInt(inventory);
            }

            Object spoofHeldItem = heldItem;
            if (oldSlot != -1 && oldSlot != slot && currentItemField != null && inventory != null) {
                currentItemField.setInt(inventory, slot);
                syncCurrentPlayItem();
                spoofHeldItem = getHeldItem();
            }

            float[] rots = getRotationsToPosition(tx + 0.5f, ty + 0.5f, tz + 0.5f);
            float spoofYaw = -999f, spoofPitch = -999f;
            if (rots != null) {
                spoofYaw = rots[0];
                spoofPitch = rots[1];
            }
            if (spoofYaw != -999f) {
                try {
                    Class<?> c05Class = get("C05PacketPlayerLook");
                    if (c05Class != null) {
                        java.lang.reflect.Constructor<?> ctor = c05Class.getDeclaredConstructor(float.class, float.class, boolean.class);
                        ctor.setAccessible(true);
                        sendPacket(ctor.newInstance(spoofYaw, spoofPitch, true));
                    }
                } catch (Exception ignored) {}
            }

            Object blockPos = createBlockPos(tx, ty, tz);
            if (!getSettingBoolean("Schematic", "Swing")) sendSwing();
            Object c08 = createC08(blockPos, face, spoofHeldItem, 0.5f, 0.5f, 0.5f);
            if (c08 != null) sendPacket(c08);

            if (spoofYaw != -999f) {
                final float restoreYaw = getRotationYaw(player);
                final float restorePitch = getRotationPitch(player);
                TASK_QUEUE.add(() -> {
                    try {
                        Class<?> c05Class = get("C05PacketPlayerLook");
                        if (c05Class != null) {
                            java.lang.reflect.Constructor<?> ctor = c05Class.getDeclaredConstructor(float.class, float.class, boolean.class);
                            ctor.setAccessible(true);
                            sendPacket(ctor.newInstance(restoreYaw, restorePitch, true));
                        }
                    } catch (Exception ignored) {}
                });
            }

            if (oldSlot != -1 && oldSlot != slot && currentItemField != null && inventory != null) {
                currentItemField.setInt(inventory, oldSlot);
                syncCurrentPlayItem();
            }
        } catch (Exception e) {}
    }

