    private static String getDirectionalBlockName(int blockId, int meta) {
        String base = getNameForBlock(blockId, meta);

        if (blockId == 29 || blockId == 33) {
            int f = meta & 7;
            switch (f) {
                case 0: return "Down " + base;
                case 1: return "Up " + base;
                case 2: return "North " + base;
                case 3: return "South " + base;
                case 4: return "West " + base;
                case 5: return "East " + base;
            }
        }

        if (blockId == 170 || blockId == 17 || blockId == 162 || blockId == 216) {
            int axis = (meta >> 2) & 3;
            String suffix = axis == 1 ? " (X)" : axis == 2 ? " (Z)" : " (Y)";
            return base + suffix;
        }

        if (blockId == 23 || blockId == 54 || blockId == 146 || blockId == 130 || blockId == 61 || blockId == 62 || blockId == 158) {
            switch (meta & 7) {
                case 2: return "North " + base;
                case 3: return "South " + base;
                case 4: return "West " + base;
                case 5: return "East " + base;
            }
        }

        if (blockId == 154) {
            switch (meta & 7) {
                case 0: return "Down " + base;
                case 2: return "North " + base;
                case 3: return "South " + base;
                case 4: return "West " + base;
                case 5: return "East " + base;
            }
        }

        if (blockId == 53 || blockId == 67 || blockId == 108 || blockId == 109 ||
                blockId == 114 || blockId == 128 || blockId == 134 || blockId == 135 ||
                blockId == 136 || blockId == 156 || blockId == 163 || blockId == 164 || blockId == 180) {
            boolean top = (meta & 4) != 0;
            String dir;
            switch (meta & 3) {
                case 0: dir = "East "; break;
                case 1: dir = "West "; break;
                case 2: dir = "South "; break;
                default: dir = "North "; break;
            }
            return (top ? "Top " : "") + dir + base;
        }

        if (blockId == 69 || blockId == 77 || blockId == 143) {
            int f = meta & 7;
            switch (f) {
                case 0: return "Down " + base;
                case 1: return "East " + base;
                case 2: return "West " + base;
                case 3: return "South " + base;
                case 4: return "North " + base;
                case 5: case 6: return "Up " + base;
            }
        }

        if (blockId == 50 || blockId == 75 || blockId == 76) {
            int f = meta & 7;
            switch (f) {
                case 1: return "East " + base;
                case 2: return "West " + base;
                case 3: return "South " + base;
                case 4: return "North " + base;
                case 5: return "Up " + base;
            }
        }

        if (blockId == 64 || blockId == 71 || (blockId >= 193 && blockId <= 197)) {
            if ((meta & 8) == 0) {
                switch (meta & 3) {
                    case 0: return "East " + base;
                    case 1: return "South " + base;
                    case 2: return "West " + base;
                    case 3: return "North " + base;
                }
            }
        }

        if (blockId == 96 || blockId == 167) {
            boolean top = (meta & 8) != 0;
            switch (meta & 3) {
                case 0: return (top ? "Top " : "") + "South " + base;
                case 1: return (top ? "Top " : "") + "North " + base;
                case 2: return (top ? "Top " : "") + "East " + base;
                case 3: return (top ? "Top " : "") + "West " + base;
            }
        }

        if (blockId == 107 || (blockId >= 183 && blockId <= 187)) {
            switch (meta & 3) {
                case 0: return "South " + base;
                case 1: return "West " + base;
                case 2: return "North " + base;
                case 3: return "East " + base;
            }
        }

        if (blockId == 65) {
            switch (meta & 7) {
                case 2: return "North " + base;
                case 3: return "South " + base;
                case 4: return "West " + base;
                case 5: return "East " + base;
            }
        }

        if (blockId == 26) {
            switch (meta & 3) {
                case 0: return "South " + base;
                case 1: return "West " + base;
                case 2: return "North " + base;
                case 3: return "East " + base;
            }
        }

        if (blockId == 218) {
            switch (meta & 7) {
                case 0: return "Down " + base;
                case 1: return "Up " + base;
                case 2: return "North " + base;
                case 3: return "South " + base;
                case 4: return "West " + base;
                case 5: return "East " + base;
            }
        }
        return base;
    }

