    private static void clipboardCopyRegion(int originX, int originY, int originZ) {
        try {
            clipboardBlocks.clear();
            clipboardBlockNames.clear();

            int minX = Math.min(clipboardPos1X, clipboardPos2X);
            int minY = Math.min(clipboardPos1Y, clipboardPos2Y);
            int minZ = Math.min(clipboardPos1Z, clipboardPos2Z);
            int maxX = Math.max(clipboardPos1X, clipboardPos2X);
            int maxY = Math.max(clipboardPos1Y, clipboardPos2Y);
            int maxZ = Math.max(clipboardPos1Z, clipboardPos2Z);

            int sizeX = maxX - minX + 1;
            int sizeY = maxY - minY + 1;
            int sizeZ = maxZ - minZ + 1;
            int totalBlocks = sizeX * sizeY * sizeZ;

            // Limit removed for unlimited copy/paste
            addChatMessage("§b[Schematic] §fKopyalanıyor... §e" + sizeX + "x" + sizeY + "x" + sizeZ
                    + " §7(" + totalBlocks + " blok taranıyor)");

            int copied = 0;
            for (int x = minX; x <= maxX; x++) {
                for (int y = minY; y <= maxY; y++) {
                    for (int z = minZ; z <= maxZ; z++) {
                        int blockId = getBlockIdAt(x, y, z);
                        if (blockId == 0) continue;

                        int meta = getBlockMetadataAt(x, y, z);
                        // Nilüfer (lily pad): dünyada meta=0, görsel rotasyonu position hash ile hesapla ve meta'ya kaydet
                        if (blockId == 111) {
                            long lhash = (long)(x * 3129871) ^ (long)z * 116129781L ^ (long)y;
                            lhash = lhash * lhash * 42317861L + lhash * 11L;
                            meta = (int)(lhash >> 16 & 3L); // 0-3 arası yön: 0=N 1=E 2=S 3=W
                        }

                        int[] color = getColorForBlock(blockId, meta);
                        if (color == null) continue;


                        int relX = x - originX;
                        int relY = y - originY;
                        int relZ = z - originZ;

                        clipboardBlocks.add(new int[]{relX, relY, relZ, color[0], color[1], color[2], blockId, meta});
                        String blockName = getDirectionalBlockName(blockId, meta);
                        if (blockId == 44 || blockId == 126 || blockId == 182) {
                            if ((meta & 8) != 0) blockName = "Top " + getNameForBlock(blockId, meta);
                        } else if (blockId == 43 || blockId == 125 || blockId == 181) {
                            blockName = "Double " + getNameForBlock(blockId, meta);
                        } else if (blockId == 78) {
                            int layers = (meta & 7) + 1;
                            blockName = getNameForBlock(blockId, meta) + " " + layers;
                        }
                        clipboardBlockNames.add(blockName);
                        copied++;
                    }
                }
            }

            if (copied == 0) {
                addChatMessage("§c[Schematic] §fBölgede blok bulunamadı (hepsi hava).");
            } else {
                addChatMessage("§a[Schematic] §f" + copied + " blok kopyalandı! §7(origin: §e"
                        + originX + ", " + originY + ", " + originZ + "§7)");
                addChatMessage("§7Yapıştırmak için: §e.paste §7veya §ePaste §7tuşu");
            }
        } catch (Exception e) {
            addChatMessage("§c[Schematic] §fKopyalama hatası: §e" + e.getMessage());
            e.printStackTrace();
        }
    }


    private static void clipboardCopyRegion() {
        try {
            Object player = getThePlayer();
            if (player != null) {
                clipboardCopyRegion(
                        (int) Math.floor(getPosX(player)),
                        (int) Math.floor(getPosY(player)),
                        (int) Math.floor(getPosZ(player))
                );
            }
        } catch (Exception e) { e.printStackTrace(); }
    }


