    private static void setBooleanSetting(String moduleName, String settingName, boolean value) {
        List<String> names = moduleBooleanSettingNames.get(moduleName);
        List<Boolean> values = moduleSettingsBooleans.get(moduleName);
        if (names == null || values == null) return;
        for (int i = 0; i < names.size(); i++) {
            if (names.get(i).equals(settingName)) {
                values.set(i, value);
                return;
            }
        }
    }

